var e=JSON.parse(`[{"id":15000,"term":"abduct","meaning":"납치하다; 유괴하다","partOfSpeech":"v.","example":"The police worked quickly to find the suspect who tried to abduct the child.","exampleTranslation":"경찰은 아이를 납치하려 한 용의자를 빠르게 찾기 위해 수사에 나섰습니다.","level":41,"category":"빈도 학습"},{"id":15001,"term":"abide","meaning":"따르다; 견디다; 머물다","partOfSpeech":"v.","example":"All participants must abide by the rules set out in the agreement.","exampleTranslation":"모든 참가자는 합의에 정해진 규칙을 따라야 합니다.","level":41,"category":"빈도 학습"},{"id":15002,"term":"abolition","meaning":"폐지; 철폐","partOfSpeech":"n.","example":"Many activists campaigned for the abolition of the death penalty.","exampleTranslation":"많은 활동가들이 사형제 폐지를 위한 운동을 벌였습니다.","level":41,"category":"빈도 학습"},{"id":15003,"term":"abound","meaning":"풍부하다; 넘치다","partOfSpeech":"v.","example":"Wildlife and rare plants abound in this protected national park.","exampleTranslation":"이 보호 국립공원에는 야생동물과 희귀 식물이 풍부합니다.","level":41,"category":"빈도 학습"},{"id":15004,"term":"acclaim","meaning":"찬사; 칭찬하다","partOfSpeech":"n.","example":"The director received worldwide acclaim for her latest film.","exampleTranslation":"그 감독은 최신 영화로 전 세계적인 찬사를 받았습니다.","level":41,"category":"빈도 학습"},{"id":15005,"term":"accredit","meaning":"인가하다; 공인하다","partOfSpeech":"v.","example":"The board voted to accredit the new medical school after a thorough review.","exampleTranslation":"위원회는 철저한 검토 후 새 의과대학을 인가하기로 투표했습니다.","level":41,"category":"빈도 학습"},{"id":15006,"term":"accrue","meaning":"축적되다; 발생하다","partOfSpeech":"v.","example":"Interest will accrue on the loan if the balance is not paid in full.","exampleTranslation":"잔액이 완납되지 않으면 대출에 이자가 발생합니다.","level":41,"category":"빈도 학습"},{"id":15007,"term":"acquit","meaning":"무죄 판결을 내리다; 면제하다","partOfSpeech":"v.","example":"The jury decided to acquit the defendant due to lack of evidence.","exampleTranslation":"배심원단은 증거 부족으로 피고에게 무죄를 선고하기로 했습니다.","level":41,"category":"빈도 학습"},{"id":15008,"term":"adequacy","meaning":"적절성; 충분함","partOfSpeech":"n.","example":"The report questioned the adequacy of the current safety measures.","exampleTranslation":"보고서는 현재 안전 조치의 적절성에 의문을 제기했습니다.","level":41,"category":"빈도 학습"},{"id":15009,"term":"adjective","meaning":"형용사","partOfSpeech":"n.","example":"The teacher asked students to find the adjective in each sentence.","exampleTranslation":"선생님은 학생들에게 각 문장에서 형용사를 찾으라고 했습니다.","level":41,"category":"빈도 학습"},{"id":15010,"term":"adjoin","meaning":"인접하다; 붙어 있다","partOfSpeech":"v.","example":"The conference room and the lounge adjoin each other on the third floor.","exampleTranslation":"회의실과 라운지는 3층에서 서로 인접해 있습니다.","level":41,"category":"빈도 학습"},{"id":15011,"term":"admiral","meaning":"해군 제독; 최고 사령관","partOfSpeech":"n.","example":"The admiral gave orders to the fleet before the naval exercise began.","exampleTranslation":"해군 훈련이 시작되기 전 제독이 함대에 명령을 내렸습니다.","level":41,"category":"빈도 학습"},{"id":15012,"term":"adorn","meaning":"장식하다; 꾸미다","partOfSpeech":"v.","example":"Colorful flowers were used to adorn the entrance of the wedding hall.","exampleTranslation":"화려한 꽃들이 결혼식장 입구를 장식하는 데 사용되었습니다.","level":41,"category":"빈도 학습"},{"id":15013,"term":"advent","meaning":"출현; 도래","partOfSpeech":"n.","example":"The advent of smartphones changed how people communicate every day.","exampleTranslation":"스마트폰의 출현은 사람들이 매일 소통하는 방식을 바꿨습니다.","level":41,"category":"빈도 학습"},{"id":15014,"term":"adversary","meaning":"적; 상대방","partOfSpeech":"n.","example":"In the debate, each team had to listen carefully to their adversary's argument.","exampleTranslation":"토론에서 각 팀은 상대방의 주장을 주의 깊게 들어야 했습니다.","level":41,"category":"빈도 학습"},{"id":15015,"term":"aerobics","meaning":"에어로빅; 유산소 운동","partOfSpeech":"n.","example":"She does aerobics three times a week to stay fit and healthy.","exampleTranslation":"그녀는 건강을 유지하기 위해 주 3회 에어로빅을 합니다.","level":41,"category":"빈도 학습"},{"id":15016,"term":"aerospace","meaning":"항공우주; 항공우주 산업","partOfSpeech":"n.","example":"She works in the aerospace industry and designs parts for satellites.","exampleTranslation":"그녀는 항공우주 산업에 종사하며 위성 부품을 설계합니다.","level":41,"category":"빈도 학습"},{"id":15017,"term":"affinity","meaning":"친밀감; 유사성; 친화력","partOfSpeech":"n.","example":"She has always had a natural affinity for languages.","exampleTranslation":"그녀는 항상 언어에 대한 타고난 친화력을 가지고 있었습니다.","level":42,"category":"빈도 학습"},{"id":15018,"term":"afflict","meaning":"고통을 주다; 괴롭히다","partOfSpeech":"v.","example":"Chronic back pain can afflict people who sit at a desk all day.","exampleTranslation":"만성 허리 통증은 하루 종일 책상 앞에 앉아 있는 사람들을 괴롭힐 수 있습니다.","level":42,"category":"빈도 학습"},{"id":15019,"term":"affluent","meaning":"부유한; 풍요로운","partOfSpeech":"adj.","example":"The neighborhood became more affluent after several tech companies moved in.","exampleTranslation":"여러 기술 회사들이 입주한 후 그 동네는 더 부유해졌습니다.","level":42,"category":"빈도 학습"},{"id":15020,"term":"akin","meaning":"유사한; 비슷한","partOfSpeech":"adj.","example":"His teaching style is akin to coaching rather than lecturing.","exampleTranslation":"그의 교육 방식은 강의보다는 코칭에 가깝습니다.","level":42,"category":"빈도 학습"},{"id":15021,"term":"alas","meaning":"아, 슬프게도; 유감스럽게도","partOfSpeech":"excl.","example":"Alas, the last train had already left by the time we arrived.","exampleTranslation":"아, 슬프게도 우리가 도착했을 때 마지막 기차는 이미 떠났습니다.","level":42,"category":"빈도 학습"},{"id":15022,"term":"ale","meaning":"에일 맥주","partOfSpeech":"n.","example":"He ordered a cold ale at the pub after work.","exampleTranslation":"그는 퇴근 후 펍에서 시원한 에일 맥주를 주문했습니다.","level":42,"category":"빈도 학습"},{"id":15023,"term":"algae","meaning":"조류(藻類); 해조류","partOfSpeech":"n.","example":"Scientists are studying algae as a potential source of biofuel.","exampleTranslation":"과학자들은 조류를 잠재적인 바이오 연료 원료로 연구하고 있습니다.","level":42,"category":"빈도 학습"},{"id":15024,"term":"alleviate","meaning":"완화하다; 경감하다","partOfSpeech":"v.","example":"Taking a short walk can help alleviate stress after a long day.","exampleTranslation":"짧은 산책은 긴 하루 후의 스트레스를 완화하는 데 도움이 됩니다.","level":42,"category":"빈도 학습"},{"id":15025,"term":"allot","meaning":"할당하다; 배분하다","partOfSpeech":"v.","example":"The manager will allot each team a specific budget for the project.","exampleTranslation":"관리자는 각 팀에게 프로젝트에 대한 특정 예산을 할당할 것입니다.","level":42,"category":"빈도 학습"},{"id":15026,"term":"almond","meaning":"아몬드","partOfSpeech":"n.","example":"She adds a handful of almond to her oatmeal every morning.","exampleTranslation":"그녀는 매일 아침 오트밀에 아몬드 한 줌을 넣습니다.","level":42,"category":"빈도 학습"},{"id":15027,"term":"alphabet","meaning":"알파벳; 자모","partOfSpeech":"n.","example":"Children learn the alphabet before they start reading books.","exampleTranslation":"아이들은 책을 읽기 시작하기 전에 알파벳을 배웁니다.","level":42,"category":"빈도 학습"},{"id":15028,"term":"alps","meaning":"알프스 산맥","partOfSpeech":"n.","example":"They spent their vacation skiing in the alps last winter.","exampleTranslation":"그들은 지난 겨울 알프스에서 스키를 타며 휴가를 보냈습니다.","level":42,"category":"빈도 학습"},{"id":15029,"term":"amber","meaning":"호박(琥珀); 황갈색","partOfSpeech":"n.","example":"The jeweler showed us a necklace made from polished amber.","exampleTranslation":"보석상은 연마된 호박으로 만든 목걸이를 우리에게 보여주었습니다.","level":42,"category":"빈도 학습"},{"id":15030,"term":"ambivalent","meaning":"양가감정의; 마음이 복잡한","partOfSpeech":"adj.","example":"She felt ambivalent about accepting the job offer in another city.","exampleTranslation":"그녀는 다른 도시의 취업 제안을 받아들이는 것에 대해 마음이 복잡했습니다.","level":42,"category":"빈도 학습"},{"id":15031,"term":"ambush","meaning":"매복; 기습 공격하다","partOfSpeech":"n.","example":"The soldiers were caught in an ambush while crossing the valley.","exampleTranslation":"병사들은 계곡을 건너던 중 매복 공격을 당했습니다.","level":42,"category":"빈도 학습"},{"id":15032,"term":"amenity","meaning":"편의 시설; 생활 편의품","partOfSpeech":"n.","example":"The hotel offers every amenity guests could need, including a gym and pool.","exampleTranslation":"그 호텔은 헬스장과 수영장을 포함해 투숙객이 필요로 하는 모든 편의 시설을 제공합니다.","level":42,"category":"빈도 학습"},{"id":15033,"term":"analogous","meaning":"유사한; 상응하는","partOfSpeech":"adj.","example":"The situation is analogous to what happened during the last financial crisis.","exampleTranslation":"이 상황은 지난 금융 위기 때 발생했던 것과 유사합니다.","level":42,"category":"빈도 학습"},{"id":15034,"term":"anarchy","meaning":"무정부 상태; 혼란","partOfSpeech":"n.","example":"Without clear rules, the classroom quickly fell into anarchy.","exampleTranslation":"명확한 규칙 없이는 교실이 금방 무질서한 상태에 빠졌습니다.","level":42,"category":"빈도 학습"},{"id":15035,"term":"annex","meaning":"별관; 합병하다","partOfSpeech":"n.","example":"The school built an annex to add more classrooms for growing enrollment.","exampleTranslation":"학교는 늘어나는 학생 수를 위해 더 많은 교실을 추가하려고 별관을 지었습니다.","level":42,"category":"빈도 학습"},{"id":15036,"term":"ante","meaning":"판돈; 선불금","partOfSpeech":"n.","example":"Each player put up their ante before the card game began.","exampleTranslation":"카드 게임이 시작되기 전에 각 플레이어는 판돈을 걸었습니다.","level":42,"category":"빈도 학습"},{"id":15037,"term":"antiquity","meaning":"고대; 고대 유물","partOfSpeech":"n.","example":"The museum displayed artifacts that dated back to classical antiquity.","exampleTranslation":"박물관은 고전 고대 시대로 거슬러 올라가는 유물들을 전시했습니다.","level":42,"category":"빈도 학습"},{"id":15038,"term":"apartheid","meaning":"아파르트헤이트; 인종 차별 정책","partOfSpeech":"n.","example":"Nelson Mandela spent decades fighting against apartheid in South Africa.","exampleTranslation":"넬슨 만델라는 남아프리카의 아파르트헤이트에 맞서 수십 년을 싸웠습니다.","level":42,"category":"빈도 학습"},{"id":15039,"term":"ape","meaning":"유인원; 흉내 내다","partOfSpeech":"n.","example":"The researchers observed how the ape used tools to get food.","exampleTranslation":"연구원들은 유인원이 먹이를 얻기 위해 도구를 사용하는 방법을 관찰했습니다.","level":42,"category":"빈도 학습"},{"id":15040,"term":"apostle","meaning":"사도; 열렬한 지지자","partOfSpeech":"n.","example":"The story describes how each apostle traveled to spread the message.","exampleTranslation":"그 이야기는 각 사도가 어떻게 메시지를 전파하기 위해 여행했는지 묘사합니다.","level":42,"category":"빈도 학습"},{"id":15041,"term":"apron","meaning":"앞치마","partOfSpeech":"n.","example":"He put on an apron before starting to cook dinner.","exampleTranslation":"그는 저녁 식사를 요리하기 시작하기 전에 앞치마를 둘렀습니다.","level":42,"category":"빈도 학습"},{"id":15042,"term":"aquatic","meaning":"수생의; 물속의","partOfSpeech":"adj.","example":"The documentary features a variety of aquatic creatures found in the deep ocean.","exampleTranslation":"그 다큐멘터리는 심해에서 발견되는 다양한 수생 생물들을 다룹니다.","level":42,"category":"빈도 학습"},{"id":15043,"term":"aristocrat","meaning":"귀족; 상류층 사람","partOfSpeech":"n.","example":"The novel follows an aristocrat who falls in love with a commoner.","exampleTranslation":"그 소설은 평민과 사랑에 빠지는 귀족을 따라갑니다.","level":42,"category":"빈도 학습"},{"id":15044,"term":"armchair","meaning":"안락의자","partOfSpeech":"n.","example":"Grandpa always reads the newspaper in his favorite armchair by the window.","exampleTranslation":"할아버지는 항상 창가에 있는 좋아하는 안락의자에서 신문을 읽습니다.","level":42,"category":"빈도 학습"},{"id":15045,"term":"aroma","meaning":"향기; 향","partOfSpeech":"n.","example":"The aroma of fresh bread from the bakery filled the entire street.","exampleTranslation":"빵집에서 풍기는 갓 구운 빵의 향기가 거리 전체를 가득 채웠습니다.","level":42,"category":"빈도 학습"},{"id":15046,"term":"arthritis","meaning":"관절염","partOfSpeech":"n.","example":"Her arthritis makes it painful to open jars or grip small objects.","exampleTranslation":"그녀의 관절염은 병뚜껑을 열거나 작은 물건을 잡는 것을 고통스럽게 만듭니다.","level":42,"category":"빈도 학습"},{"id":15047,"term":"artisan","meaning":"장인; 숙련 기술자","partOfSpeech":"n.","example":"The artisan spent three days handcrafting a single leather wallet.","exampleTranslation":"그 장인은 가죽 지갑 하나를 손으로 만드는 데 사흘을 보냈습니다.","level":42,"category":"빈도 학습"},{"id":15048,"term":"ascent","meaning":"오름; 상승; 등반","partOfSpeech":"n.","example":"The climbers began their ascent of the mountain before sunrise.","exampleTranslation":"등반가들은 일출 전에 산 등반을 시작했습니다.","level":42,"category":"빈도 학습"},{"id":15049,"term":"ascertain","meaning":"확인하다; 알아내다","partOfSpeech":"v.","example":"The detective tried to ascertain the exact time the incident occurred.","exampleTranslation":"형사는 사건이 발생한 정확한 시간을 알아내려고 했습니다.","level":42,"category":"빈도 학습"},{"id":15050,"term":"ascribe","meaning":"~의 탓으로 돌리다; 귀속시키다","partOfSpeech":"v.","example":"Many people ascribe his success to hard work and good timing.","exampleTranslation":"많은 사람들은 그의 성공을 노력과 좋은 타이밍 덕분으로 돌립니다.","level":42,"category":"빈도 학습"},{"id":15051,"term":"ashore","meaning":"해안으로; 육지에","partOfSpeech":"adv.","example":"The sailors were relieved to finally come ashore after weeks at sea.","exampleTranslation":"선원들은 몇 주 동안 바다에 있다가 드디어 육지에 오르게 되어 안도했습니다.","level":42,"category":"빈도 학습"},{"id":15052,"term":"assail","meaning":"공격하다; 맹렬히 비난하다","partOfSpeech":"v.","example":"Critics began to assail the new policy almost immediately after it was announced.","exampleTranslation":"비평가들은 새 정책이 발표되자마자 거의 즉시 맹렬히 비난하기 시작했습니다.","level":42,"category":"빈도 학습"},{"id":15053,"term":"assorted","meaning":"다양한; 여러 종류의","partOfSpeech":"adj.","example":"She bought a box of assorted chocolates to share at the office.","exampleTranslation":"그녀는 사무실에서 나눠 먹으려고 다양한 초콜릿 상자를 샀습니다.","level":42,"category":"빈도 학습"},{"id":15054,"term":"asymmetry","meaning":"비대칭; 불균형","partOfSpeech":"n.","example":"The artist deliberately used asymmetry to create a more dynamic composition.","exampleTranslation":"그 예술가는 더 역동적인 구성을 만들기 위해 의도적으로 비대칭을 활용했습니다.","level":42,"category":"빈도 학습"},{"id":15055,"term":"attentive","meaning":"주의 깊은; 배려하는","partOfSpeech":"adj.","example":"The students were attentive throughout the entire lecture.","exampleTranslation":"학생들은 강의 내내 주의 깊게 집중했습니다.","level":42,"category":"빈도 학습"},{"id":15056,"term":"attic","meaning":"다락방","partOfSpeech":"n.","example":"She found a box of old photographs while cleaning out the attic.","exampleTranslation":"그녀는 다락방을 정리하다가 오래된 사진 상자를 발견했습니다.","level":42,"category":"빈도 학습"},{"id":15057,"term":"audition","meaning":"오디션; 오디션을 보다","partOfSpeech":"n.","example":"She was nervous before her audition for the lead role in the musical.","exampleTranslation":"그녀는 뮤지컬 주연 배역 오디션 전에 긴장했습니다.","level":42,"category":"빈도 학습"},{"id":15058,"term":"augment","meaning":"증가시키다; 보강하다","partOfSpeech":"v.","example":"The company hired extra staff to augment the team during the busy season.","exampleTranslation":"회사는 바쁜 시즌에 팀을 보강하기 위해 추가 직원을 고용했습니다.","level":42,"category":"빈도 학습"},{"id":15059,"term":"aura","meaning":"아우라; 분위기; 기운","partOfSpeech":"n.","example":"The old cathedral had a mysterious aura that made visitors feel reverent.","exampleTranslation":"오래된 대성당은 방문자들을 경건하게 만드는 신비로운 아우라를 풍겼습니다.","level":42,"category":"빈도 학습"},{"id":15060,"term":"austere","meaning":"엄격한; 검소한; 단조로운","partOfSpeech":"adj.","example":"The monk lived an austere life with few possessions and no luxuries.","exampleTranslation":"그 수도승은 소유물도 거의 없고 사치도 없는 검소한 삶을 살았습니다.","level":42,"category":"빈도 학습"},{"id":15061,"term":"authoritative","meaning":"권위 있는; 믿을 만한","partOfSpeech":"adj.","example":"The professor gave an authoritative lecture on the history of ancient Rome.","exampleTranslation":"교수는 고대 로마의 역사에 대해 권위 있는 강의를 했습니다.","level":42,"category":"빈도 학습"},{"id":15062,"term":"avert","meaning":"피하다; 막다; 돌리다","partOfSpeech":"v.","example":"Quick action by the staff helped avert a serious accident in the kitchen.","exampleTranslation":"직원들의 신속한 조치가 주방에서 심각한 사고를 막는 데 도움이 되었습니다.","level":42,"category":"빈도 학습"},{"id":15063,"term":"awesome","meaning":"굉장한; 경이로운","partOfSpeech":"adj.","example":"The view from the top of the mountain was truly awesome.","exampleTranslation":"산 정상에서 바라보는 경치는 정말 굉장했습니다.","level":42,"category":"빈도 학습"},{"id":15064,"term":"babe","meaning":"아기; 젊은 여성(구어)","partOfSpeech":"n.","example":"The babe in the stroller smiled at everyone who passed by.","exampleTranslation":"유모차 안의 아기는 지나가는 모든 사람에게 미소를 지었습니다.","level":42,"category":"빈도 학습"},{"id":15065,"term":"bachelor","meaning":"독신남; 학사 학위","partOfSpeech":"n.","example":"He remained a bachelor well into his forties before finally getting married.","exampleTranslation":"그는 마침내 결혼하기 전까지 40대 초반까지 독신으로 지냈습니다.","level":42,"category":"빈도 학습"},{"id":15066,"term":"baffle","meaning":"당혹스럽게 하다; 어리둥절하게 하다","partOfSpeech":"v.","example":"The strange error message continued to baffle the entire support team.","exampleTranslation":"그 이상한 오류 메시지는 지원팀 전체를 계속 당혹스럽게 했습니다.","level":42,"category":"빈도 학습"},{"id":15067,"term":"bandage","meaning":"붕대; 붕대를 감다","partOfSpeech":"n.","example":"The nurse wrapped a bandage around his injured wrist.","exampleTranslation":"간호사가 그의 다친 손목에 붕대를 감았습니다.","level":42,"category":"빈도 학습"},{"id":15068,"term":"banish","meaning":"추방하다; 쫓아내다","partOfSpeech":"v.","example":"The king decided to banish the traitor from the kingdom forever.","exampleTranslation":"왕은 반역자를 왕국에서 영원히 추방하기로 결정했습니다.","level":42,"category":"빈도 학습"},{"id":15069,"term":"banquet","meaning":"연회; 만찬","partOfSpeech":"n.","example":"The company held a formal banquet to celebrate its fiftieth anniversary.","exampleTranslation":"회사는 창립 50주년을 기념하기 위해 공식 연회를 열었습니다.","level":42,"category":"빈도 학습"},{"id":15070,"term":"barb","meaning":"가시; 뼈아픈 비판","partOfSpeech":"n.","example":"His comment had a sharp barb that left everyone at the table feeling uncomfortable.","exampleTranslation":"그의 말에는 날카로운 가시가 있어 테이블에 있던 모두를 불편하게 했습니다.","level":42,"category":"빈도 학습"},{"id":15071,"term":"barbecue","meaning":"바비큐; 바비큐 파티","partOfSpeech":"n.","example":"We invited the neighbors over for a barbecue in the backyard last Sunday.","exampleTranslation":"지난 일요일에 뒷마당에서 바비큐 파티를 하려고 이웃들을 초대했습니다.","level":42,"category":"빈도 학습"},{"id":15072,"term":"barge","meaning":"바지선; 불쑥 들어오다","partOfSpeech":"n.","example":"A heavy barge slowly made its way down the wide river.","exampleTranslation":"무거운 바지선이 넓은 강을 따라 천천히 나아갔습니다.","level":42,"category":"빈도 학습"},{"id":15073,"term":"barracks","meaning":"병영; 막사","partOfSpeech":"n.","example":"The soldiers returned to the barracks after the training exercise was over.","exampleTranslation":"훈련이 끝난 후 병사들은 막사로 돌아갔습니다.","level":42,"category":"빈도 학습"},{"id":15074,"term":"barren","meaning":"척박한; 불모의","partOfSpeech":"adj.","example":"Nothing could grow in the barren soil after years of drought.","exampleTranslation":"수년간의 가뭄으로 척박해진 토양에서는 아무것도 자랄 수 없었습니다.","level":42,"category":"빈도 학습"},{"id":15075,"term":"bash","meaning":"세게 치다; 파티","partOfSpeech":"v.","example":"He accidentally bash his knee against the corner of the table.","exampleTranslation":"그는 실수로 무릎을 테이블 모서리에 세게 찧었습니다.","level":42,"category":"빈도 학습"},{"id":15076,"term":"beckon","meaning":"손짓하여 부르다; 유혹하다","partOfSpeech":"v.","example":"She began to beckon her friend from across the crowded room.","exampleTranslation":"그녀는 사람들로 붐비는 방 건너편에서 친구에게 손짓하기 시작했습니다.","level":42,"category":"빈도 학습"},{"id":15077,"term":"beetle","meaning":"딱정벌레","partOfSpeech":"n.","example":"A shiny black beetle crawled slowly across the garden path.","exampleTranslation":"반짝이는 검은 딱정벌레 한 마리가 정원 길을 천천히 기어갔습니다.","level":42,"category":"빈도 학습"},{"id":15078,"term":"beforehand","meaning":"미리; 사전에","partOfSpeech":"adv.","example":"You should always call the restaurant beforehand to check if they are open.","exampleTranslation":"식당이 영업 중인지 미리 전화해서 확인해야 합니다.","level":42,"category":"빈도 학습"},{"id":15079,"term":"behold","meaning":"바라보다; 목격하다","partOfSpeech":"v.","example":"We climbed the hill to behold the magnificent view of the valley below.","exampleTranslation":"우리는 아래 계곡의 장엄한 경치를 바라보기 위해 언덕을 올랐습니다.","level":42,"category":"빈도 학습"},{"id":15080,"term":"bellow","meaning":"고함치다; 큰소리로 외치다","partOfSpeech":"v.","example":"The coach began to bellow instructions from the sideline during the final quarter.","exampleTranslation":"코치는 마지막 쿼터 동안 사이드라인에서 지시를 고함치기 시작했습니다.","level":42,"category":"빈도 학습"},{"id":15081,"term":"benevolent","meaning":"자비로운; 인정 많은","partOfSpeech":"adj.","example":"The benevolent landlord reduced the rent for tenants who lost their jobs.","exampleTranslation":"자비로운 집주인은 일자리를 잃은 세입자들의 임대료를 낮춰주었습니다.","level":42,"category":"빈도 학습"},{"id":15082,"term":"benign","meaning":"온화한; 양성의","partOfSpeech":"adj.","example":"The doctor said the tumor was benign and did not require surgery.","exampleTranslation":"의사는 종양이 양성이라 수술이 필요하지 않다고 했습니다.","level":42,"category":"빈도 학습"},{"id":15083,"term":"berry","meaning":"베리; 장과","partOfSpeech":"n.","example":"She picked a fresh berry from the bush and popped it into her mouth.","exampleTranslation":"그녀는 덤불에서 신선한 베리를 따서 입에 넣었습니다.","level":42,"category":"빈도 학습"},{"id":15084,"term":"beware","meaning":"조심하다; 경계하다","partOfSpeech":"v.","example":"The sign at the gate said to beware of the guard dog on the property.","exampleTranslation":"입구의 표지판에는 구내의 경비견을 조심하라고 쓰여 있었습니다.","level":42,"category":"빈도 학습"},{"id":15085,"term":"bibliography","meaning":"참고 문헌; 서지 목록","partOfSpeech":"n.","example":"The professor asked students to include a complete bibliography at the end of the paper.","exampleTranslation":"교수님은 학생들에게 논문 끝에 완전한 참고 문헌 목록을 포함하도록 요청했습니다.","level":42,"category":"빈도 학습"},{"id":15086,"term":"binary","meaning":"이진법의; 두 가지로 이루어진","partOfSpeech":"adj.","example":"All data in a computer is stored in binary form as ones and zeros.","exampleTranslation":"컴퓨터의 모든 데이터는 1과 0의 이진 형태로 저장됩니다.","level":42,"category":"빈도 학습"},{"id":15087,"term":"biopsy","meaning":"생체 검사; 조직 검사","partOfSpeech":"n.","example":"The doctor ordered a biopsy to determine whether the growth was cancerous.","exampleTranslation":"의사는 종양이 암성인지 확인하기 위해 생체 검사를 지시했습니다.","level":42,"category":"빈도 학습"},{"id":15088,"term":"bladder","meaning":"방광","partOfSpeech":"n.","example":"Drinking too much coffee can irritate the bladder and cause discomfort.","exampleTranslation":"커피를 너무 많이 마시면 방광을 자극해 불편함을 유발할 수 있습니다.","level":42,"category":"빈도 학습"},{"id":15089,"term":"bland","meaning":"맛없는; 단조로운","partOfSpeech":"adj.","example":"The soup was too bland, so she added some salt and pepper.","exampleTranslation":"국이 너무 맛이 없어서 그녀는 소금과 후추를 조금 더했습니다.","level":42,"category":"빈도 학습"},{"id":15090,"term":"blatant","meaning":"노골적인; 뻔뻔한","partOfSpeech":"adj.","example":"It was a blatant lie that everyone in the room could see through immediately.","exampleTranslation":"그것은 방 안의 모든 사람이 즉시 알아차릴 수 있는 노골적인 거짓말이었습니다.","level":42,"category":"빈도 학습"},{"id":15091,"term":"bleach","meaning":"표백제; 탈색하다","partOfSpeech":"n.","example":"She used bleach to remove the stubborn stain from the white shirt.","exampleTranslation":"그녀는 흰 셔츠의 완고한 얼룩을 제거하기 위해 표백제를 사용했습니다.","level":42,"category":"빈도 학습"},{"id":15092,"term":"bliss","meaning":"더없는 행복; 지복","partOfSpeech":"n.","example":"Lying on the beach with no plans for the day was pure bliss.","exampleTranslation":"아무 계획 없이 해변에 누워 있는 것은 더없는 행복이었습니다.","level":42,"category":"빈도 학습"},{"id":15093,"term":"blister","meaning":"물집; 수포","partOfSpeech":"n.","example":"She got a blister on her heel after walking in new shoes all day.","exampleTranslation":"그녀는 새 신발을 신고 하루 종일 걷다가 발뒤꿈치에 물집이 생겼습니다.","level":42,"category":"빈도 학습"},{"id":15094,"term":"bloc","meaning":"블록; 정치적 연합","partOfSpeech":"n.","example":"Several countries formed a trading bloc to strengthen their economic position.","exampleTranslation":"여러 나라가 경제적 입지를 강화하기 위해 무역 블록을 결성했습니다.","level":42,"category":"빈도 학습"},{"id":15095,"term":"blot","meaning":"얼룩; 오점","partOfSpeech":"n.","example":"There was an ink blot on the page that ruined the final presentation.","exampleTranslation":"최종 발표물을 망치는 잉크 얼룩이 페이지에 있었습니다.","level":42,"category":"빈도 학습"},{"id":15096,"term":"blueprint","meaning":"청사진; 설계도","partOfSpeech":"n.","example":"The architect presented a detailed blueprint of the new community center.","exampleTranslation":"건축가는 새 커뮤니티 센터의 자세한 청사진을 제시했습니다.","level":42,"category":"빈도 학습"},{"id":15097,"term":"bluff","meaning":"허세; 엄포를 놓다","partOfSpeech":"v.","example":"He tried to bluff his way through the interview without knowing the answer.","exampleTranslation":"그는 답을 모르면서도 허세를 부려 면접을 통과하려 했습니다.","level":42,"category":"빈도 학습"},{"id":15098,"term":"bobbed","meaning":"단발로 자른; 위아래로 흔들린","partOfSpeech":"adj.","example":"She arrived at the party with freshly bobbed hair that everyone admired.","exampleTranslation":"그녀는 모두가 감탄하는 깔끔하게 단발로 자른 머리를 하고 파티에 도착했습니다.","level":42,"category":"빈도 학습"},{"id":15099,"term":"bog","meaning":"늪; 습지","partOfSpeech":"n.","example":"The hikers got stuck near a bog and had to find a safer route.","exampleTranslation":"등산객들은 늪 근처에서 발이 묶여 더 안전한 경로를 찾아야 했습니다.","level":42,"category":"빈도 학습"},{"id":15100,"term":"bolster","meaning":"강화하다; 북돋우다","partOfSpeech":"v.","example":"The manager tried to bolster team morale after the disappointing project result.","exampleTranslation":"관리자는 실망스러운 프로젝트 결과 후 팀 사기를 북돋우려 했습니다.","level":42,"category":"빈도 학습"},{"id":15101,"term":"bombard","meaning":"폭격하다; 쏟아붓다","partOfSpeech":"v.","example":"Reporters started to bombard the spokesperson with questions about the scandal.","exampleTranslation":"기자들은 대변인에게 스캔들에 관한 질문을 쏟아붓기 시작했습니다.","level":42,"category":"빈도 학습"},{"id":15102,"term":"booth","meaning":"부스; 칸막이 공간","partOfSpeech":"n.","example":"They reserved a booth in the corner of the restaurant for a private conversation.","exampleTranslation":"그들은 개인적인 대화를 위해 식당 한 켠의 부스를 예약했습니다.","level":42,"category":"빈도 학습"},{"id":15103,"term":"borough","meaning":"자치구; 행정 구역","partOfSpeech":"n.","example":"She has lived in this borough of the city for over twenty years.","exampleTranslation":"그녀는 이 도시의 이 자치구에서 20년 넘게 살아왔습니다.","level":42,"category":"빈도 학습"},{"id":15104,"term":"boulder","meaning":"큰 바위; 암석","partOfSpeech":"n.","example":"A massive boulder had rolled onto the road, blocking all traffic.","exampleTranslation":"거대한 바위가 도로 위로 굴러와 모든 교통을 막았습니다.","level":42,"category":"빈도 학습"},{"id":15105,"term":"braid","meaning":"땋은 머리; 끈","partOfSpeech":"n.","example":"She wore her hair in a long braid that reached down to her waist.","exampleTranslation":"그녀는 허리까지 내려오는 긴 땋은 머리를 했습니다.","level":42,"category":"빈도 학습"},{"id":15106,"term":"brandy","meaning":"브랜디","partOfSpeech":"n.","example":"He warmed up by the fire and sipped a small glass of brandy.","exampleTranslation":"그는 불가에서 몸을 녹이며 브랜디 한 잔을 홀짝였습니다.","level":42,"category":"빈도 학습"},{"id":15107,"term":"brassiere","meaning":"브래지어","partOfSpeech":"n.","example":"She found a comfortable brassiere that provided good support throughout the day.","exampleTranslation":"그녀는 하루 종일 충분한 지지력을 제공하는 편안한 브래지어를 발견했습니다.","level":42,"category":"빈도 학습"},{"id":15108,"term":"breadth","meaning":"폭; 너비; 범위","partOfSpeech":"n.","example":"The professor was impressed by the breadth of knowledge the student displayed.","exampleTranslation":"교수는 학생이 보여준 지식의 폭에 감명받았습니다.","level":42,"category":"빈도 학습"},{"id":15109,"term":"briefcase","meaning":"서류 가방","partOfSpeech":"n.","example":"He left his briefcase on the train and had to report it to the lost and found.","exampleTranslation":"그는 기차에 서류 가방을 두고 내려 분실물 센터에 신고해야 했습니다.","level":42,"category":"빈도 학습"},{"id":15110,"term":"brim","meaning":"가장자리; 챙; 가득 차다","partOfSpeech":"n.","example":"She filled the cup to the brim and carefully carried it to the table.","exampleTranslation":"그녀는 컵을 가장자리까지 가득 채우고 조심스럽게 테이블로 날랐습니다.","level":42,"category":"빈도 학습"},{"id":15111,"term":"brink","meaning":"벼랑 끝; 직전","partOfSpeech":"n.","example":"The struggling company was on the brink of bankruptcy last year.","exampleTranslation":"그 어려움을 겪던 회사는 지난해 파산 직전에 놓여 있었습니다.","level":42,"category":"빈도 학습"},{"id":15112,"term":"bristle","meaning":"억센 털; 반발하다","partOfSpeech":"n.","example":"The old toothbrush had bristle that were bent out of shape.","exampleTranslation":"낡은 칫솔은 모양이 구부러진 억센 털들이 있었습니다.","level":42,"category":"빈도 학습"},{"id":15113,"term":"brood","meaning":"곱씹다; 품다; 한 배 새끼","partOfSpeech":"v.","example":"He tends to brood over his mistakes for days instead of moving on.","exampleTranslation":"그는 앞으로 나아가는 대신 며칠 동안 자신의 실수를 곱씹는 경향이 있습니다.","level":42,"category":"빈도 학습"},{"id":15114,"term":"brownie","meaning":"브라우니(초콜릿 케이크)","partOfSpeech":"n.","example":"She baked a warm brownie and served it with vanilla ice cream.","exampleTranslation":"그녀는 따뜻한 브라우니를 구워 바닐라 아이스크림과 함께 냈습니다.","level":42,"category":"빈도 학습"},{"id":15115,"term":"browse","meaning":"훑어보다; 인터넷을 검색하다","partOfSpeech":"v.","example":"She likes to browse online stores for new clothing ideas on weekends.","exampleTranslation":"그녀는 주말에 새로운 옷 아이디어를 찾아 온라인 쇼핑몰을 둘러보는 것을 좋아합니다.","level":42,"category":"빈도 학습"},{"id":15116,"term":"buddy","meaning":"친구; 동료","partOfSpeech":"n.","example":"My buddy and I went hiking together last weekend.","exampleTranslation":"내 친구와 나는 지난 주말에 함께 하이킹을 갔습니다.","level":42,"category":"빈도 학습"},{"id":15117,"term":"buffet","meaning":"뷔페; 자유롭게 먹는 식사","partOfSpeech":"n.","example":"We had a wonderful buffet at the hotel with so many choices.","exampleTranslation":"우리는 호텔에서 선택지가 너무 많은 훌륭한 뷔페를 즐겼습니다.","level":42,"category":"빈도 학습"},{"id":15118,"term":"bum","meaning":"거지; 게으름뱅이; 엉덩이(구어)","partOfSpeech":"n.","example":"A bum was sitting on the bench near the park entrance.","exampleTranslation":"공원 입구 근처 벤치에 한 부랑자가 앉아 있었습니다.","level":42,"category":"빈도 학습"},{"id":15119,"term":"bun","meaning":"번(둥근 빵); 머리 묶음","partOfSpeech":"n.","example":"She put her hair up in a bun before starting her workout.","exampleTranslation":"그녀는 운동을 시작하기 전에 머리를 올려 묶었습니다.","level":42,"category":"빈도 학습"},{"id":15120,"term":"bungalow","meaning":"방갈로; 단층 주택","partOfSpeech":"n.","example":"They rented a cozy bungalow by the beach for their vacation.","exampleTranslation":"그들은 휴가를 위해 해변가의 아늑한 방갈로를 빌렸습니다.","level":42,"category":"빈도 학습"},{"id":15121,"term":"bunker","meaning":"벙커; 지하 대피소","partOfSpeech":"n.","example":"His golf ball landed in the bunker right before the green.","exampleTranslation":"그의 골프공이 그린 바로 앞 벙커에 떨어졌습니다.","level":42,"category":"빈도 학습"},{"id":15122,"term":"bunny","meaning":"토끼(애칭)","partOfSpeech":"n.","example":"The children were excited to see a bunny hopping in the garden.","exampleTranslation":"아이들은 정원에서 토끼가 깡충깡충 뛰는 것을 보고 신이 났습니다.","level":42,"category":"빈도 학습"},{"id":15123,"term":"buoy","meaning":"부표; 기운을 북돋우다","partOfSpeech":"n.","example":"The swimmer used a buoy to mark the end of the course.","exampleTranslation":"수영 선수는 코스의 끝을 표시하기 위해 부표를 사용했습니다.","level":43,"category":"빈도 학습"},{"id":15124,"term":"burrow","meaning":"굴; 굴을 파다","partOfSpeech":"n.","example":"The rabbit disappeared into its burrow when it sensed danger.","exampleTranslation":"토끼는 위험을 감지하자 굴 속으로 사라졌습니다.","level":43,"category":"빈도 학습"},{"id":15125,"term":"bustle","meaning":"북적임; 분주하게 움직이다","partOfSpeech":"n.","example":"I love the bustle of the city market on Saturday mornings.","exampleTranslation":"나는 토요일 아침 도시 시장의 북적임을 좋아합니다.","level":43,"category":"빈도 학습"},{"id":15126,"term":"cabbage","meaning":"양배추","partOfSpeech":"n.","example":"She added shredded cabbage to the salad for a crunchy texture.","exampleTranslation":"그녀는 아삭한 식감을 위해 샐러드에 채 썬 양배추를 넣었습니다.","level":43,"category":"빈도 학습"},{"id":15127,"term":"cadet","meaning":"사관생도; 훈련생","partOfSpeech":"n.","example":"The cadet trained hard every morning before classes began.","exampleTranslation":"그 사관생도는 수업이 시작되기 전 매일 아침 열심히 훈련했습니다.","level":43,"category":"빈도 학습"},{"id":15128,"term":"calcium","meaning":"칼슘","partOfSpeech":"n.","example":"Drinking milk every day helps you get enough calcium for strong bones.","exampleTranslation":"매일 우유를 마시면 튼튼한 뼈를 위한 충분한 칼슘을 섭취하는 데 도움이 됩니다.","level":43,"category":"빈도 학습"},{"id":15129,"term":"camel","meaning":"낙타","partOfSpeech":"n.","example":"We rode a camel across the sand dunes during our desert tour.","exampleTranslation":"우리는 사막 투어 중 낙타를 타고 모래 언덕을 넘었습니다.","level":43,"category":"빈도 학습"},{"id":15130,"term":"canon","meaning":"교리; 규범; 정전(正典)","partOfSpeech":"n.","example":"This novel has become part of the literary canon taught in schools.","exampleTranslation":"이 소설은 학교에서 가르치는 문학 정전의 일부가 되었습니다.","level":43,"category":"빈도 학습"},{"id":15131,"term":"canopy","meaning":"차양; 덮개; (나무의) 수관","partOfSpeech":"n.","example":"They sat under a canopy of trees to escape the afternoon heat.","exampleTranslation":"그들은 오후의 더위를 피하기 위해 나무 수관 아래에 앉았습니다.","level":43,"category":"빈도 학습"},{"id":15132,"term":"capitalize","meaning":"대문자로 쓰다; 자본화하다; 이용하다","partOfSpeech":"v.","example":"Make sure you capitalize the first letter of every sentence.","exampleTranslation":"모든 문장의 첫 글자를 대문자로 쓰도록 하세요.","level":43,"category":"빈도 학습"},{"id":15133,"term":"capsule","meaning":"캡슐; 소형 우주선","partOfSpeech":"n.","example":"The doctor told me to swallow the capsule with a full glass of water.","exampleTranslation":"의사는 캡슐을 물 한 컵과 함께 삼키라고 했습니다.","level":43,"category":"빈도 학습"},{"id":15134,"term":"caption","meaning":"자막; 설명문","partOfSpeech":"n.","example":"She added a funny caption to the photo before posting it online.","exampleTranslation":"그녀는 사진을 온라인에 올리기 전에 재미있는 설명문을 추가했습니다.","level":43,"category":"빈도 학습"},{"id":15135,"term":"caravan","meaning":"캐러밴; 이동식 주택; 여행 대열","partOfSpeech":"n.","example":"The family traveled across the country in a caravan during the summer.","exampleTranslation":"그 가족은 여름 동안 캐러밴을 타고 전국을 여행했습니다.","level":43,"category":"빈도 학습"},{"id":15136,"term":"cardiac","meaning":"심장의; 심장에 관한","partOfSpeech":"adj.","example":"The patient was rushed to the hospital after suffering a cardiac episode.","exampleTranslation":"환자는 심장 발작을 일으킨 후 급히 병원으로 이송되었습니다.","level":43,"category":"빈도 학습"},{"id":15137,"term":"caress","meaning":"쓰다듬다; 애무하다; 부드러운 손길","partOfSpeech":"v.","example":"She knelt down to caress the stray cat gently on its head.","exampleTranslation":"그녀는 무릎을 꿇고 떠돌이 고양이의 머리를 부드럽게 쓰다듬었습니다.","level":43,"category":"빈도 학습"},{"id":15138,"term":"carnival","meaning":"카니발; 축제","partOfSpeech":"n.","example":"The whole town came out to enjoy the colorful carnival parade.","exampleTranslation":"온 마을 사람들이 화려한 카니발 퍼레이드를 즐기러 나왔습니다.","level":43,"category":"빈도 학습"},{"id":15139,"term":"carol","meaning":"캐럴; 크리스마스 노래","partOfSpeech":"n.","example":"The choir sang a familiar carol outside the shopping mall.","exampleTranslation":"합창단이 쇼핑몰 밖에서 익숙한 캐럴을 불렀습니다.","level":43,"category":"빈도 학습"},{"id":15140,"term":"carpenter","meaning":"목수; 목공","partOfSpeech":"n.","example":"The carpenter built a beautiful bookshelf for our living room.","exampleTranslation":"목수는 우리 거실을 위해 아름다운 책장을 만들었습니다.","level":43,"category":"빈도 학습"},{"id":15141,"term":"cartel","meaning":"카르텔; 기업 연합","partOfSpeech":"n.","example":"The government investigated a cartel that had been fixing prices illegally.","exampleTranslation":"정부는 불법으로 가격을 담합해 온 카르텔을 조사했습니다.","level":43,"category":"빈도 학습"},{"id":15142,"term":"cartridge","meaning":"카트리지; 탄창","partOfSpeech":"n.","example":"I need to replace the ink cartridge before printing this document.","exampleTranslation":"이 문서를 인쇄하기 전에 잉크 카트리지를 교체해야 합니다.","level":43,"category":"빈도 학습"},{"id":15143,"term":"cascade","meaning":"폭포; 연속; 쏟아지다","partOfSpeech":"n.","example":"Water fell in a beautiful cascade down the rocky hillside.","exampleTranslation":"물이 바위투성이 언덕 아래로 아름다운 폭포를 이루며 쏟아졌습니다.","level":43,"category":"빈도 학습"},{"id":15144,"term":"casino","meaning":"카지노; 도박장","partOfSpeech":"n.","example":"They spent one evening at the casino during their Las Vegas trip.","exampleTranslation":"그들은 라스베이거스 여행 중 하룻저녁을 카지노에서 보냈습니다.","level":43,"category":"빈도 학습"},{"id":15145,"term":"catalyst","meaning":"촉매; 변화를 유발하는 것","partOfSpeech":"n.","example":"The new manager became a catalyst for change within the company.","exampleTranslation":"새 관리자는 회사 내 변화의 촉매가 되었습니다.","level":43,"category":"빈도 학습"},{"id":15146,"term":"cavalry","meaning":"기병대; 기동부대","partOfSpeech":"n.","example":"The cavalry charged forward at dawn to surprise the enemy camp.","exampleTranslation":"기병대는 적진을 기습하기 위해 새벽에 돌격했습니다.","level":43,"category":"빈도 학습"},{"id":15147,"term":"cavern","meaning":"동굴; 큰 공동(空洞)","partOfSpeech":"n.","example":"The explorers discovered a massive cavern beneath the mountain.","exampleTranslation":"탐험가들은 산 아래에서 거대한 동굴을 발견했습니다.","level":43,"category":"빈도 학습"},{"id":15148,"term":"cavity","meaning":"충치; 구멍; 빈 공간","partOfSpeech":"n.","example":"The dentist found a small cavity in my back tooth during the checkup.","exampleTranslation":"치과 의사가 검진 중 어금니에서 작은 충치를 발견했습니다.","level":43,"category":"빈도 학습"},{"id":15149,"term":"chaotic","meaning":"혼돈의; 무질서한","partOfSpeech":"adj.","example":"The morning rush hour in the city can be completely chaotic.","exampleTranslation":"도시의 아침 출근 시간은 완전히 혼란스러울 수 있습니다.","level":43,"category":"빈도 학습"},{"id":15150,"term":"chaplain","meaning":"군목; 교도소 목사; 전속 사제","partOfSpeech":"n.","example":"The chaplain visited soldiers at the base to offer comfort and support.","exampleTranslation":"군목은 위안과 지원을 제공하기 위해 기지의 군인들을 방문했습니다.","level":43,"category":"빈도 학습"},{"id":15151,"term":"charcoal","meaning":"숯; 목탄","partOfSpeech":"n.","example":"We grilled the meat over charcoal for a smoky flavor.","exampleTranslation":"우리는 훈제 향을 위해 숯불에 고기를 구웠습니다.","level":43,"category":"빈도 학습"},{"id":15152,"term":"charisma","meaning":"카리스마; 매력","partOfSpeech":"n.","example":"The speaker had so much charisma that everyone in the room was captivated.","exampleTranslation":"그 연사는 카리스마가 넘쳐 방 안의 모든 사람이 매료되었습니다.","level":43,"category":"빈도 학습"},{"id":15153,"term":"cherish","meaning":"소중히 여기다; 아끼다","partOfSpeech":"v.","example":"I cherish every moment I get to spend with my family.","exampleTranslation":"나는 가족과 함께 보내는 모든 순간을 소중히 여깁니다.","level":43,"category":"빈도 학습"},{"id":15154,"term":"chess","meaning":"체스","partOfSpeech":"n.","example":"My grandfather taught me how to play chess when I was young.","exampleTranslation":"할아버지는 내가 어렸을 때 체스 두는 법을 가르쳐 주셨습니다.","level":43,"category":"빈도 학습"},{"id":15155,"term":"chestnut","meaning":"밤; 밤나무","partOfSpeech":"n.","example":"We roasted a chestnut over the fire on a cold autumn evening.","exampleTranslation":"우리는 쌀쌀한 가을 저녁에 모닥불에 밤을 구웠습니다.","level":43,"category":"빈도 학습"},{"id":15156,"term":"chili","meaning":"고추; 칠리","partOfSpeech":"n.","example":"She added a fresh chili to the soup to make it spicier.","exampleTranslation":"그녀는 국을 더 맵게 하기 위해 신선한 고추를 넣었습니다.","level":43,"category":"빈도 학습"},{"id":15157,"term":"chimpanzee","meaning":"침팬지","partOfSpeech":"n.","example":"The chimpanzee at the zoo used a stick to dig out insects from a log.","exampleTranslation":"동물원의 침팬지가 막대기를 이용해 통나무에서 곤충을 파냈습니다.","level":43,"category":"빈도 학습"},{"id":15158,"term":"chore","meaning":"집안일; 잡일","partOfSpeech":"n.","example":"Washing the dishes is the chore I dislike the most at home.","exampleTranslation":"설거지는 집에서 내가 가장 싫어하는 집안일입니다.","level":43,"category":"빈도 학습"},{"id":15159,"term":"choreograph","meaning":"안무를 짜다; 계획하다","partOfSpeech":"v.","example":"She was hired to choreograph the dance sequence for the music video.","exampleTranslation":"그녀는 뮤직비디오의 댄스 시퀀스를 안무하기 위해 고용되었습니다.","level":43,"category":"빈도 학습"},{"id":15160,"term":"chromosome","meaning":"염색체","partOfSpeech":"n.","example":"Scientists study each chromosome to understand how genes are inherited.","exampleTranslation":"과학자들은 유전자가 어떻게 유전되는지 이해하기 위해 각 염색체를 연구합니다.","level":43,"category":"빈도 학습"},{"id":15161,"term":"chronology","meaning":"연대기; 시간 순서","partOfSpeech":"n.","example":"The book presents the events in strict chronology from start to finish.","exampleTranslation":"그 책은 사건들을 처음부터 끝까지 엄격한 연대기 순서로 제시합니다.","level":43,"category":"빈도 학습"},{"id":15162,"term":"churn","meaning":"휘젓다; 동요시키다; 교반기","partOfSpeech":"v.","example":"The storm caused the waves to churn violently near the shore.","exampleTranslation":"폭풍은 해안 근처에서 파도를 격렬하게 휘젓게 했습니다.","level":43,"category":"빈도 학습"},{"id":15163,"term":"clatter","meaning":"딸그락거리는 소리; 요란하게 소리 내다","partOfSpeech":"n.","example":"There was a loud clatter from the kitchen when the pots fell.","exampleTranslation":"냄비들이 떨어졌을 때 주방에서 큰 딸그락 소리가 났습니다.","level":43,"category":"빈도 학습"},{"id":15164,"term":"cleave","meaning":"쪼개다; 갈라지다; 달라붙다","partOfSpeech":"v.","example":"The chef used an axe to cleave the large piece of firewood in half.","exampleTranslation":"요리사는 큰 장작을 반으로 쪼개기 위해 도끼를 사용했습니다.","level":43,"category":"빈도 학습"},{"id":15165,"term":"clerical","meaning":"사무직의; 성직자의","partOfSpeech":"adj.","example":"She handled all clerical tasks such as filing and scheduling appointments.","exampleTranslation":"그녀는 서류 정리와 예약 일정 관리 같은 모든 사무 업무를 처리했습니다.","level":43,"category":"빈도 학습"},{"id":15166,"term":"climax","meaning":"절정; 클라이맥스","partOfSpeech":"n.","example":"The climax of the movie left everyone in the theater speechless.","exampleTranslation":"영화의 절정 부분은 극장의 모든 사람을 말문이 막히게 했습니다.","level":43,"category":"빈도 학습"},{"id":15167,"term":"clinch","meaning":"확정 짓다; 매듭짓다","partOfSpeech":"v.","example":"The team managed to clinch the championship title in the final minute.","exampleTranslation":"그 팀은 마지막 1분에 챔피언십 타이틀을 확정 지었습니다.","level":43,"category":"빈도 학습"},{"id":15168,"term":"clog","meaning":"막히다; 막다","partOfSpeech":"v.","example":"Grease can clog the kitchen drain if you pour it down the sink.","exampleTranslation":"기름을 싱크대에 버리면 주방 배수구가 막힐 수 있습니다.","level":43,"category":"빈도 학습"},{"id":15169,"term":"closet","meaning":"옷장; 수납공간","partOfSpeech":"n.","example":"She organized her closet by sorting clothes by color and season.","exampleTranslation":"그녀는 색상과 계절별로 옷을 분류해 옷장을 정리했습니다.","level":43,"category":"빈도 학습"},{"id":15170,"term":"clove","meaning":"정향; 마늘 한 쪽","partOfSpeech":"n.","example":"Add one clove of garlic to the sauce for a richer flavor.","exampleTranslation":"더 깊은 맛을 위해 소스에 마늘 한 쪽을 넣으세요.","level":43,"category":"빈도 학습"},{"id":15171,"term":"clump","meaning":"덩어리; 무리","partOfSpeech":"n.","example":"A clump of trees at the edge of the field provided welcome shade.","exampleTranslation":"들판 끝의 나무 덩어리가 반가운 그늘을 제공했습니다.","level":43,"category":"빈도 학습"},{"id":15172,"term":"clumsy","meaning":"서툰; 어색한","partOfSpeech":"adj.","example":"He gave a clumsy apology that only made the situation more awkward.","exampleTranslation":"그는 서툰 사과를 해서 상황을 더 어색하게 만들었습니다.","level":43,"category":"빈도 학습"},{"id":15173,"term":"clutter","meaning":"어지르다; 잡동사니","partOfSpeech":"v.","example":"Too many old files can clutter your desktop and slow down your computer.","exampleTranslation":"너무 많은 오래된 파일이 바탕화면을 어지럽히고 컴퓨터를 느리게 할 수 있습니다.","level":43,"category":"빈도 학습"},{"id":15174,"term":"cobble","meaning":"조약돌을 깔다; 대충 만들다","partOfSpeech":"v.","example":"They had to cobble together a solution using spare parts from the workshop.","exampleTranslation":"그들은 작업실의 여분 부품으로 대충 해결책을 만들어야 했습니다.","level":43,"category":"빈도 학습"},{"id":15175,"term":"cockpit","meaning":"조종석","partOfSpeech":"n.","example":"The pilot invited the child to take a quick look at the cockpit.","exampleTranslation":"파일럿은 그 아이를 조종석을 잠깐 구경하도록 초대했습니다.","level":43,"category":"빈도 학습"},{"id":15176,"term":"cocoa","meaning":"코코아; 카카오","partOfSpeech":"n.","example":"She made a warm cup of cocoa to drink on the cold winter evening.","exampleTranslation":"그녀는 추운 겨울 저녁에 마시려고 따뜻한 코코아 한 잔을 만들었습니다.","level":43,"category":"빈도 학습"},{"id":15177,"term":"coconut","meaning":"코코넛","partOfSpeech":"n.","example":"He cracked open a coconut and drank the fresh juice straight from it.","exampleTranslation":"그는 코코넛을 쪼개어 신선한 즙을 바로 마셨습니다.","level":43,"category":"빈도 학습"},{"id":15178,"term":"cohort","meaning":"동기 집단; 동료 무리","partOfSpeech":"n.","example":"Our cohort from the training program meets once a year for a reunion.","exampleTranslation":"연수 프로그램 동기 집단은 1년에 한 번 동창회를 위해 만납니다.","level":43,"category":"빈도 학습"},{"id":15179,"term":"collide","meaning":"충돌하다; 부딪히다","partOfSpeech":"v.","example":"Two shopping carts collide in the narrow aisle of the grocery store.","exampleTranslation":"두 쇼핑 카트가 식료품점의 좁은 통로에서 충돌했습니다.","level":43,"category":"빈도 학습"},{"id":15180,"term":"colon","meaning":"콜론(문장부호); 결장","partOfSpeech":"n.","example":"Place a colon before the list to make the sentence clearer.","exampleTranslation":"문장을 더 명확하게 하기 위해 목록 앞에 콜론을 붙이세요.","level":43,"category":"빈도 학습"},{"id":15181,"term":"columnist","meaning":"칼럼니스트; 기고가","partOfSpeech":"n.","example":"The columnist wrote a sharp opinion piece about rising food prices.","exampleTranslation":"그 칼럼니스트는 오르는 식품 물가에 대해 날카로운 의견 기사를 썼습니다.","level":43,"category":"빈도 학습"},{"id":15182,"term":"comet","meaning":"혜성","partOfSpeech":"n.","example":"People gathered outside to watch the comet pass across the night sky.","exampleTranslation":"사람들은 혜성이 밤하늘을 가로질러 지나가는 것을 보기 위해 밖에 모였습니다.","level":43,"category":"빈도 학습"},{"id":15183,"term":"commonplace","meaning":"흔한; 평범한","partOfSpeech":"adj.","example":"Working from home has become commonplace since the pandemic.","exampleTranslation":"팬데믹 이후 재택근무가 흔한 일이 되었습니다.","level":43,"category":"빈도 학습"},{"id":15184,"term":"communion","meaning":"친밀한 교감; 성찬식","partOfSpeech":"n.","example":"The friends sat quietly by the lake, enjoying a deep communion with nature.","exampleTranslation":"친구들은 자연과의 깊은 교감을 즐기며 호수 옆에 조용히 앉아 있었습니다.","level":43,"category":"빈도 학습"},{"id":15185,"term":"compass","meaning":"나침반; 범위","partOfSpeech":"n.","example":"He used a compass to find north when he got lost in the woods.","exampleTranslation":"그는 숲에서 길을 잃었을 때 나침반을 이용해 북쪽을 찾았습니다.","level":43,"category":"빈도 학습"},{"id":15186,"term":"complacent","meaning":"자기만족에 빠진; 안이한","partOfSpeech":"adj.","example":"Don't get complacent just because the first exam went well.","exampleTranslation":"첫 번째 시험이 잘 됐다고 안이해지지 마세요.","level":43,"category":"빈도 학습"},{"id":15187,"term":"compulsory","meaning":"의무적인; 강제적인","partOfSpeech":"adj.","example":"Attendance at the safety training session is compulsory for all new hires.","exampleTranslation":"안전 교육 참석은 모든 신입 직원에게 의무적입니다.","level":43,"category":"빈도 학습"},{"id":15188,"term":"concurrent","meaning":"동시에 일어나는; 병행하는","partOfSpeech":"adj.","example":"The two concurrent meetings made it impossible for him to attend both.","exampleTranslation":"동시에 열리는 두 회의 때문에 그는 두 곳 모두 참석하는 것이 불가능했습니다.","level":43,"category":"빈도 학습"},{"id":15189,"term":"confiscate","meaning":"몰수하다; 압수하다","partOfSpeech":"v.","example":"The teacher had to confiscate the phone because it kept going off in class.","exampleTranslation":"수업 중에 계속 울렸기 때문에 선생님은 그 휴대폰을 압수해야 했습니다.","level":43,"category":"빈도 학습"},{"id":15190,"term":"conglomerate","meaning":"대기업 집단; 복합체","partOfSpeech":"n.","example":"The conglomerate owns businesses in sectors ranging from retail to technology.","exampleTranslation":"그 대기업 집단은 소매업에서 기술 분야에 이르는 사업체를 보유하고 있습니다.","level":43,"category":"빈도 학습"},{"id":15191,"term":"conjunction","meaning":"접속사; 결합","partOfSpeech":"n.","example":"The word 'and' is a conjunction that links two ideas in a sentence.","exampleTranslation":"'and'라는 단어는 문장에서 두 가지 생각을 연결하는 접속사입니다.","level":43,"category":"빈도 학습"},{"id":15192,"term":"conjure","meaning":"마법처럼 만들어내다; 불러내다","partOfSpeech":"v.","example":"A good chef can conjure a delicious meal from just a few simple ingredients.","exampleTranslation":"훌륭한 요리사는 몇 가지 간단한 재료만으로 맛있는 요리를 마법처럼 만들어낼 수 있습니다.","level":43,"category":"빈도 학습"},{"id":15193,"term":"conquest","meaning":"정복; 획득","partOfSpeech":"n.","example":"Learning a new language felt like a personal conquest for her.","exampleTranslation":"새로운 언어를 배우는 것은 그녀에게 개인적인 정복처럼 느껴졌습니다.","level":43,"category":"빈도 학습"},{"id":15194,"term":"conservatism","meaning":"보수주의; 전통 중시","partOfSpeech":"n.","example":"The debate covered both conservatism and progressive ideas about education.","exampleTranslation":"그 토론은 교육에 대한 보수주의와 진보적 생각 모두를 다뤘습니다.","level":43,"category":"빈도 학습"},{"id":15195,"term":"conspire","meaning":"공모하다; 음모를 꾸미다","partOfSpeech":"v.","example":"It seemed like everything would conspire to ruin their outdoor picnic.","exampleTranslation":"모든 것이 그들의 야외 피크닉을 망치려 공모하는 것처럼 보였습니다.","level":43,"category":"빈도 학습"},{"id":15196,"term":"constable","meaning":"경찰관; 순경","partOfSpeech":"n.","example":"A constable was stationed at the entrance to control the crowd.","exampleTranslation":"경찰관 한 명이 군중을 통제하기 위해 입구에 배치되었습니다.","level":43,"category":"빈도 학습"},{"id":15197,"term":"construe","meaning":"해석하다; 이해하다","partOfSpeech":"v.","example":"You should not construe his silence as agreement with the plan.","exampleTranslation":"그의 침묵을 계획에 대한 동의로 해석해서는 안 됩니다.","level":43,"category":"빈도 학습"},{"id":15198,"term":"contentious","meaning":"논쟁적인; 분쟁을 일으키는","partOfSpeech":"adj.","example":"The contentious proposal sparked a heated debate among committee members.","exampleTranslation":"그 논쟁적인 제안은 위원회 구성원들 사이에서 격렬한 토론을 불러일으켰습니다.","level":43,"category":"빈도 학습"},{"id":15199,"term":"continuum","meaning":"연속체; 연속","partOfSpeech":"n.","example":"Language ability exists on a continuum from beginner to advanced.","exampleTranslation":"언어 능력은 초급에서 고급까지의 연속체로 존재합니다.","level":43,"category":"빈도 학습"},{"id":15200,"term":"contour","meaning":"윤곽; 등고선","partOfSpeech":"n.","example":"The artist carefully sketched the contour of the model's face.","exampleTranslation":"화가는 모델의 얼굴 윤곽을 조심스럽게 스케치했습니다.","level":43,"category":"빈도 학습"},{"id":15201,"term":"contraction","meaning":"수축; 단축형","partOfSpeech":"n.","example":"The word 'don't' is a contraction of 'do not' used in everyday speech.","exampleTranslation":"'don't'라는 단어는 일상 대화에서 쓰이는 'do not'의 단축형입니다.","level":43,"category":"빈도 학습"},{"id":15202,"term":"convoy","meaning":"호송대; 선단","partOfSpeech":"n.","example":"A convoy of trucks carried relief supplies to the flooded region.","exampleTranslation":"트럭 호송대가 침수된 지역에 구호 물자를 운반했습니다.","level":43,"category":"빈도 학습"},{"id":15203,"term":"coronary","meaning":"관상동맥의; 심장의","partOfSpeech":"adj.","example":"A healthy diet and regular exercise can reduce the risk of coronary disease.","exampleTranslation":"건강한 식단과 규칙적인 운동은 관상동맥 질환의 위험을 줄일 수 있습니다.","level":43,"category":"빈도 학습"},{"id":15204,"term":"coroner","meaning":"검시관","partOfSpeech":"n.","example":"The coroner was called to determine the official cause of death.","exampleTranslation":"공식적인 사망 원인을 규명하기 위해 검시관이 호출되었습니다.","level":43,"category":"빈도 학습"},{"id":15205,"term":"corporal","meaning":"상병; 신체의","partOfSpeech":"n.","example":"The corporal briefed the new recruits on the day's training schedule.","exampleTranslation":"상병이 신병들에게 그날의 훈련 일정을 설명했습니다.","level":43,"category":"빈도 학습"},{"id":15206,"term":"corpus","meaning":"말뭉치; 전집","partOfSpeech":"n.","example":"The linguist analyzed a large corpus of spoken English to find common patterns.","exampleTranslation":"그 언어학자는 일반적인 패턴을 찾기 위해 대규모 구어 영어 말뭉치를 분석했습니다.","level":43,"category":"빈도 학습"},{"id":15207,"term":"corrode","meaning":"부식하다; 침식하다","partOfSpeech":"v.","example":"Salt water can corrode metal parts on a boat if they are not treated.","exampleTranslation":"소금물은 처리하지 않으면 배의 금속 부품을 부식시킬 수 있습니다.","level":43,"category":"빈도 학습"},{"id":15208,"term":"cosmic","meaning":"우주의; 광대한","partOfSpeech":"adj.","example":"The scientist talked about cosmic rays and their effect on Earth's atmosphere.","exampleTranslation":"그 과학자는 우주선과 지구 대기에 미치는 영향에 대해 이야기했습니다.","level":43,"category":"빈도 학습"},{"id":15209,"term":"coupon","meaning":"쿠폰; 할인권","partOfSpeech":"n.","example":"She used a coupon at the checkout and saved five dollars on her groceries.","exampleTranslation":"그녀는 계산대에서 쿠폰을 사용해 식료품 구매에서 5달러를 절약했습니다.","level":43,"category":"빈도 학습"},{"id":15210,"term":"covert","meaning":"비밀의; 은밀한","partOfSpeech":"adj.","example":"The agency launched a covert operation to gather information on the suspect.","exampleTranslation":"기관은 용의자에 대한 정보를 수집하기 위해 은밀한 작전을 시작했습니다.","level":43,"category":"빈도 학습"},{"id":15211,"term":"cracker","meaning":"크래커; 과자","partOfSpeech":"n.","example":"She put a slice of cheese on a cracker and enjoyed it with her tea.","exampleTranslation":"그녀는 크래커 위에 치즈 한 조각을 올려 차와 함께 즐겼습니다.","level":43,"category":"빈도 학습"},{"id":15212,"term":"crackle","meaning":"타닥타닥 소리 내다; 탁탁거리다","partOfSpeech":"v.","example":"The dry leaves crackle under your feet as you walk through the park in autumn.","exampleTranslation":"가을에 공원을 걸으면 마른 낙엽이 발 밑에서 바삭바삭 소리를 냅니다.","level":43,"category":"빈도 학습"},{"id":15213,"term":"cram","meaning":"벼락치기하다; 쑤셔 넣다","partOfSpeech":"v.","example":"He stayed up all night to cram for the history exam the next morning.","exampleTranslation":"그는 다음 날 아침 역사 시험을 위해 밤새 벼락치기를 했습니다.","level":43,"category":"빈도 학습"},{"id":15214,"term":"crate","meaning":"나무 상자; 운반용 상자","partOfSpeech":"n.","example":"The farmer loaded a crate of apples onto the back of the truck.","exampleTranslation":"농부는 트럭 뒤에 사과 한 상자를 실었습니다.","level":43,"category":"빈도 학습"},{"id":15215,"term":"crater","meaning":"분화구; 구덩이","partOfSpeech":"n.","example":"The meteor left a huge crater in the desert when it hit the ground.","exampleTranslation":"운석이 땅에 충돌했을 때 사막에 거대한 구덩이를 남겼습니다.","level":43,"category":"빈도 학습"},{"id":15216,"term":"crave","meaning":"갈망하다; 간절히 원하다","partOfSpeech":"v.","example":"After a long hike, I crave a cold glass of water more than anything.","exampleTranslation":"긴 하이킹 후에는 그 무엇보다 차가운 물 한 잔이 간절히 마시고 싶어.","level":43,"category":"빈도 학습"},{"id":15217,"term":"creak","meaning":"삐걱거리다; 삐걱거리는 소리","partOfSpeech":"v.","example":"The old floorboards creak every time someone walks across the room.","exampleTranslation":"누군가 방을 가로질러 걸을 때마다 오래된 마룻바닥이 삐걱거려.","level":43,"category":"빈도 학습"},{"id":15218,"term":"crease","meaning":"주름; 구겨지다","partOfSpeech":"n.","example":"There is a deep crease in your shirt — you should iron it before the meeting.","exampleTranslation":"셔츠에 깊은 주름이 있어 — 회의 전에 다려야 할 것 같아.","level":43,"category":"빈도 학습"},{"id":15219,"term":"credentials","meaning":"자격증; 신임장; 자격","partOfSpeech":"n.","example":"You need to check someone's credentials before hiring them for the job.","exampleTranslation":"그 직책에 채용하기 전에 지원자의 자격을 확인해야 해.","level":43,"category":"빈도 학습"},{"id":15220,"term":"crow","meaning":"까마귀; 자랑하다","partOfSpeech":"n.","example":"A crow landed on the fence and stared at us for a few seconds.","exampleTranslation":"까마귀 한 마리가 울타리에 앉아 몇 초 동안 우리를 빤히 쳐다봤어.","level":43,"category":"빈도 학습"},{"id":15221,"term":"crumb","meaning":"빵 부스러기; 아주 작은 조각","partOfSpeech":"n.","example":"There was a crumb on the table from the toast you made this morning.","exampleTranslation":"오늘 아침에 네가 만든 토스트에서 나온 빵 부스러기가 테이블에 있었어.","level":43,"category":"빈도 학습"},{"id":15222,"term":"crumple","meaning":"구기다; 쭈그러들다","partOfSpeech":"v.","example":"He began to crumple the rejection letter in frustration.","exampleTranslation":"그는 좌절감에 거절 편지를 구기기 시작했어.","level":43,"category":"빈도 학습"},{"id":15223,"term":"cuff","meaning":"소맷부리; 수갑","partOfSpeech":"n.","example":"His cuff was soiled with ink after writing for hours at his desk.","exampleTranslation":"그는 책상에서 몇 시간 동안 글을 쓴 후 소맷부리가 잉크로 더러워졌어.","level":43,"category":"빈도 학습"},{"id":15224,"term":"cuisine","meaning":"요리; 요리법","partOfSpeech":"n.","example":"I love trying cuisine from different countries whenever I travel.","exampleTranslation":"나는 여행할 때마다 다른 나라의 요리를 맛보는 걸 좋아해.","level":43,"category":"빈도 학습"},{"id":15225,"term":"cumulative","meaning":"누적되는; 점점 증가하는","partOfSpeech":"adj.","example":"The cumulative effect of skipping sleep every night is serious.","exampleTranslation":"매일 밤 수면을 건너뛰는 것의 누적 효과는 심각해.","level":43,"category":"빈도 학습"},{"id":15226,"term":"curry","meaning":"카레; 카레 요리를 하다","partOfSpeech":"n.","example":"She made a spicy curry for dinner that warmed everyone up.","exampleTranslation":"그녀는 저녁으로 모두를 따뜻하게 해줄 매운 카레를 만들었어.","level":43,"category":"빈도 학습"},{"id":15227,"term":"curtail","meaning":"줄이다; 축소하다","partOfSpeech":"v.","example":"The company decided to curtail spending to avoid going into debt.","exampleTranslation":"회사는 부채를 피하기 위해 지출을 줄이기로 결정했어.","level":43,"category":"빈도 학습"},{"id":15228,"term":"cute","meaning":"귀여운; 매력적인","partOfSpeech":"adj.","example":"Everyone agreed that the puppy was incredibly cute.","exampleTranslation":"그 강아지가 믿을 수 없을 만큼 귀엽다고 모두 동의했어.","level":43,"category":"빈도 학습"},{"id":15229,"term":"deacon","meaning":"부제; 집사","partOfSpeech":"n.","example":"The deacon helped distribute food to families in need after the service.","exampleTranslation":"집사는 예배 후 어려운 가정에 음식을 나눠주는 일을 도왔어.","level":43,"category":"빈도 학습"},{"id":15230,"term":"dean","meaning":"학장; 수석 성직자","partOfSpeech":"n.","example":"The dean welcomed new students at the start of the academic year.","exampleTranslation":"학장은 학년 초에 신입생들을 환영했어.","level":44,"category":"빈도 학습"},{"id":15231,"term":"deceive","meaning":"속이다; 기만하다","partOfSpeech":"v.","example":"It is wrong to deceive your friends, even if you think it will protect them.","exampleTranslation":"보호하려는 의도라도 친구를 속이는 건 잘못된 일이야.","level":44,"category":"빈도 학습"},{"id":15232,"term":"decency","meaning":"품위; 예의 바름","partOfSpeech":"n.","example":"He had the decency to apologize after realizing his mistake.","exampleTranslation":"그는 자신의 실수를 깨달은 후 예의 바르게 사과했어.","level":44,"category":"빈도 학습"},{"id":15233,"term":"decentralize","meaning":"분산시키다; 지방 분권화하다","partOfSpeech":"v.","example":"The government plans to decentralize power and give more authority to local regions.","exampleTranslation":"정부는 권력을 분산시키고 지방에 더 많은 권한을 부여할 계획이야.","level":44,"category":"빈도 학습"},{"id":15234,"term":"deception","meaning":"속임; 기만","partOfSpeech":"n.","example":"The investigation revealed that the company had relied on deception to attract investors.","exampleTranslation":"조사 결과 그 회사가 투자자를 유치하기 위해 기만에 의존했음이 밝혀졌어.","level":44,"category":"빈도 학습"},{"id":15236,"term":"deflect","meaning":"빗나가게 하다; 피하다","partOfSpeech":"v.","example":"He tried to deflect the blame onto his teammates instead of taking responsibility.","exampleTranslation":"그는 책임을 지는 대신 팀원들에게 비난을 돌리려 했어.","level":44,"category":"빈도 학습"},{"id":15237,"term":"deform","meaning":"변형시키다; 기형으로 만들다","partOfSpeech":"v.","example":"Extreme heat can deform plastic containers if you are not careful.","exampleTranslation":"조심하지 않으면 극심한 열이 플라스틱 용기를 변형시킬 수 있어.","level":44,"category":"빈도 학습"},{"id":15238,"term":"degenerate","meaning":"악화되다; 퇴화하다","partOfSpeech":"v.","example":"The friendly argument began to degenerate into a full shouting match.","exampleTranslation":"가벼운 말다툼이 격렬한 고함 싸움으로 악화되기 시작했어.","level":44,"category":"빈도 학습"},{"id":15239,"term":"deliberated","meaning":"심사숙고한; 신중히 논의한","partOfSpeech":"adj.","example":"After a long meeting, the team made a deliberated choice to postpone the launch.","exampleTranslation":"긴 회의 끝에 팀은 심사숙고한 끝에 출시를 연기하기로 결정했어.","level":44,"category":"빈도 학습"},{"id":15240,"term":"delinquent","meaning":"비행의; 체납된; 비행 청소년","partOfSpeech":"adj.","example":"The bank sent a warning letter to delinquent account holders.","exampleTranslation":"은행은 체납 계좌 보유자들에게 경고 편지를 보냈어.","level":44,"category":"빈도 학습"},{"id":15241,"term":"delude","meaning":"현혹하다; 속이다","partOfSpeech":"v.","example":"You should not delude yourself into thinking the problem will go away on its own.","exampleTranslation":"문제가 저절로 사라질 거라는 생각으로 스스로를 속이면 안 돼.","level":44,"category":"빈도 학습"},{"id":15242,"term":"dementia","meaning":"치매","partOfSpeech":"n.","example":"His grandmother was diagnosed with dementia and now needs full-time care.","exampleTranslation":"그의 할머니가 치매 진단을 받아 이제 전일제 돌봄이 필요해.","level":44,"category":"빈도 학습"},{"id":15243,"term":"demolish","meaning":"철거하다; 허물다","partOfSpeech":"v.","example":"The city decided to demolish the old stadium and build a new one.","exampleTranslation":"시는 낡은 경기장을 철거하고 새 경기장을 짓기로 결정했어.","level":44,"category":"빈도 학습"},{"id":15244,"term":"den","meaning":"소굴; 아늑한 방","partOfSpeech":"n.","example":"He set up a comfortable den in the basement where he could read in peace.","exampleTranslation":"그는 조용히 책을 읽을 수 있는 아늑한 방을 지하실에 꾸몄어.","level":44,"category":"빈도 학습"},{"id":15245,"term":"denomination","meaning":"교파; 단위; 액면가","partOfSpeech":"n.","example":"The church belongs to a Protestant denomination with over a million members.","exampleTranslation":"그 교회는 백만 명 이상의 신도를 가진 개신교 교파에 속해.","level":44,"category":"빈도 학습"},{"id":15246,"term":"denote","meaning":"나타내다; 의미하다","partOfSpeech":"v.","example":"An asterisk is used to denote a footnote at the bottom of the page.","exampleTranslation":"별표는 페이지 하단의 각주를 나타내기 위해 사용돼.","level":44,"category":"빈도 학습"},{"id":15247,"term":"dent","meaning":"움푹 패인 곳; 찌그러뜨리다","partOfSpeech":"n.","example":"There is a noticeable dent on the car door from a parking accident.","exampleTranslation":"주차 사고로 차 문에 눈에 띄는 찌그러짐이 생겼어.","level":44,"category":"빈도 학습"},{"id":15248,"term":"dental","meaning":"치과의; 치아의","partOfSpeech":"adj.","example":"You should schedule a dental checkup at least once a year.","exampleTranslation":"적어도 1년에 한 번은 치과 검진 예약을 해야 해.","level":44,"category":"빈도 학습"},{"id":15249,"term":"deport","meaning":"추방하다; 강제 출국시키다","partOfSpeech":"v.","example":"The authorities decided to deport the individual who had entered the country illegally.","exampleTranslation":"당국은 불법으로 입국한 사람을 추방하기로 결정했어.","level":44,"category":"빈도 학습"},{"id":15250,"term":"deposition","meaning":"퇴위; 증언; 퇴적","partOfSpeech":"n.","example":"The lawyer prepared her client for the deposition that would take place the following week.","exampleTranslation":"변호사는 다음 주에 있을 증언에 대비해 의뢰인을 준비시켰어.","level":44,"category":"빈도 학습"},{"id":15251,"term":"deregulate","meaning":"규제를 완화하다; 자유화하다","partOfSpeech":"v.","example":"Some economists argue that it is better to deregulate the energy market.","exampleTranslation":"일부 경제학자들은 에너지 시장의 규제를 완화하는 것이 더 낫다고 주장해.","level":44,"category":"빈도 학습"},{"id":15252,"term":"deride","meaning":"조롱하다; 비웃다","partOfSpeech":"v.","example":"It is unkind to deride someone for making an honest mistake.","exampleTranslation":"솔직한 실수를 한 사람을 비웃는 건 친절하지 못한 행동이야.","level":44,"category":"빈도 학습"},{"id":15253,"term":"despise","meaning":"경멸하다; 몹시 싫어하다","partOfSpeech":"v.","example":"She grew to despise dishonesty after being lied to many times.","exampleTranslation":"그녀는 여러 번 거짓말을 당한 후 불성실함을 경멸하게 됐어.","level":44,"category":"빈도 학습"},{"id":15254,"term":"detriment","meaning":"손해; 해악","partOfSpeech":"n.","example":"Working too many hours can be a serious detriment to your health.","exampleTranslation":"너무 많은 시간을 일하는 것은 건강에 심각한 해악이 될 수 있어.","level":44,"category":"빈도 학습"},{"id":15255,"term":"devalue","meaning":"가치를 떨어뜨리다; 평가절하하다","partOfSpeech":"v.","example":"Flooding the market with cheap copies will devalue the original product.","exampleTranslation":"값싼 복제품으로 시장을 넘치게 하면 원제품의 가치를 떨어뜨릴 거야.","level":44,"category":"빈도 학습"},{"id":15256,"term":"deviant","meaning":"일탈적인; 변태적인; 이탈자","partOfSpeech":"adj.","example":"The researcher studied deviant behavior in social settings.","exampleTranslation":"연구자는 사회적 환경에서 일탈적 행동을 연구했어.","level":44,"category":"빈도 학습"},{"id":15257,"term":"diagonal","meaning":"대각선의; 비스듬한","partOfSpeech":"adj.","example":"Draw a diagonal line from one corner of the square to the opposite corner.","exampleTranslation":"정사각형의 한 모서리에서 반대편 모서리까지 대각선을 그어봐.","level":44,"category":"빈도 학습"},{"id":15258,"term":"dialect","meaning":"방언; 사투리","partOfSpeech":"n.","example":"The old man spoke in a regional dialect that was hard for outsiders to understand.","exampleTranslation":"그 노인은 외지인이 이해하기 어려운 지역 방언으로 말했어.","level":44,"category":"빈도 학습"},{"id":15259,"term":"diarrhea","meaning":"설사","partOfSpeech":"n.","example":"He got diarrhea after eating at a restaurant with poor food hygiene.","exampleTranslation":"그는 위생이 불량한 식당에서 식사를 한 후 설사를 했어.","level":44,"category":"빈도 학습"},{"id":15260,"term":"digit","meaning":"숫자; 손가락","partOfSpeech":"n.","example":"Please enter your four-digit PIN to access the account.","exampleTranslation":"계정에 접근하려면 네 자리 PIN을 입력해주세요.","level":44,"category":"빈도 학습"},{"id":15261,"term":"dignify","meaning":"위엄 있게 하다; 격상시키다","partOfSpeech":"v.","example":"She refused to dignify his rude comment with a response.","exampleTranslation":"그녀는 그의 무례한 말에 대꾸하는 것으로 격을 높여주길 거부했어.","level":44,"category":"빈도 학습"},{"id":15262,"term":"diligent","meaning":"근면한; 성실한","partOfSpeech":"adj.","example":"She is a diligent student who always finishes her assignments on time.","exampleTranslation":"그녀는 항상 과제를 제때 끝내는 성실한 학생이야.","level":44,"category":"빈도 학습"},{"id":15263,"term":"diploma","meaning":"졸업장; 자격증","partOfSpeech":"n.","example":"She hung her diploma on the wall of her new office with great pride.","exampleTranslation":"그녀는 새 사무실 벽에 졸업장을 자랑스럽게 걸었어.","level":44,"category":"빈도 학습"},{"id":15264,"term":"dire","meaning":"끔찍한; 극도로 심각한","partOfSpeech":"adj.","example":"The charity warned of dire consequences if donations did not increase soon.","exampleTranslation":"자선 단체는 기부금이 곧 증가하지 않으면 끔찍한 결과가 올 것이라고 경고했어.","level":44,"category":"빈도 학습"},{"id":15265,"term":"disciple","meaning":"제자; 신봉자","partOfSpeech":"n.","example":"Every disciple of the philosopher gathered to hear his final lecture.","exampleTranslation":"철학자의 모든 제자가 그의 마지막 강의를 듣기 위해 모였어.","level":44,"category":"빈도 학습"},{"id":15266,"term":"disco","meaning":"디스코(음악·춤 장르); 나이트클럽","partOfSpeech":"n.","example":"My parents met at a disco back in the seventies.","exampleTranslation":"우리 부모님은 70년대에 디스코 클럽에서 만났대요.","level":44,"category":"빈도 학습"},{"id":15267,"term":"disconnect","meaning":"연결을 끊다; 단절하다","partOfSpeech":"v.","example":"Please disconnect the cable before you restart the device.","exampleTranslation":"장치를 재시작하기 전에 케이블을 분리해 주세요.","level":44,"category":"빈도 학습"},{"id":15268,"term":"discontent","meaning":"불만; 불만족","partOfSpeech":"n.","example":"There was widespread discontent among the staff over the new policy.","exampleTranslation":"새 정책에 대한 직원들 사이에 광범위한 불만이 있었습니다.","level":44,"category":"빈도 학습"},{"id":15269,"term":"discredit","meaning":"신뢰를 떨어뜨리다; 불명예","partOfSpeech":"v.","example":"The rival tried to discredit her research by pointing out minor flaws.","exampleTranslation":"경쟁자는 사소한 결함을 지적하며 그녀의 연구를 깎아내리려 했습니다.","level":44,"category":"빈도 학습"},{"id":15270,"term":"discrete","meaning":"별개의; 분리된","partOfSpeech":"adj.","example":"The project is divided into several discrete stages that must be completed in order.","exampleTranslation":"프로젝트는 순서대로 완료해야 하는 여러 별개의 단계로 나뉩니다.","level":44,"category":"빈도 학습"},{"id":15271,"term":"disdain","meaning":"경멸; 무시","partOfSpeech":"n.","example":"She looked at the rude comment with obvious disdain.","exampleTranslation":"그녀는 그 무례한 말을 명백한 경멸의 눈빛으로 바라봤습니다.","level":44,"category":"빈도 학습"},{"id":15272,"term":"dishonest","meaning":"정직하지 않은; 부정직한","partOfSpeech":"adj.","example":"It is dishonest to claim credit for work you did not do.","exampleTranslation":"자신이 하지 않은 일에 공을 차지하는 것은 부정직한 행동입니다.","level":44,"category":"빈도 학습"},{"id":15273,"term":"disillusion","meaning":"환멸을 느끼게 하다; 환상을 깨다","partOfSpeech":"v.","example":"The harsh reality of the job began to disillusion him after just a few months.","exampleTranslation":"몇 달 만에 직장의 냉혹한 현실이 그를 환멸하게 만들기 시작했습니다.","level":44,"category":"빈도 학습"},{"id":15274,"term":"dismal","meaning":"우울한; 형편없는","partOfSpeech":"adj.","example":"The weather was so dismal that we decided to stay indoors all day.","exampleTranslation":"날씨가 너무 우울해서 우리는 하루 종일 실내에 있기로 했습니다.","level":44,"category":"빈도 학습"},{"id":15275,"term":"disparity","meaning":"불균형; 격차","partOfSpeech":"n.","example":"There is a significant disparity in wages between men and women in that industry.","exampleTranslation":"그 산업에서는 남성과 여성 간에 상당한 임금 격차가 있습니다.","level":44,"category":"빈도 학습"},{"id":15276,"term":"disproportion","meaning":"불균형; 어울리지 않음","partOfSpeech":"n.","example":"The disproportion between effort and reward frustrated the whole team.","exampleTranslation":"노력과 보상의 불균형이 팀 전체를 좌절시켰습니다.","level":44,"category":"빈도 학습"},{"id":15277,"term":"disqualify","meaning":"자격을 박탈하다; 실격시키다","partOfSpeech":"v.","example":"The judges decided to disqualify the athlete for using banned substances.","exampleTranslation":"심판단은 금지 약물 사용을 이유로 그 선수를 실격시키기로 결정했습니다.","level":44,"category":"빈도 학습"},{"id":15278,"term":"disseminate","meaning":"전파하다; 보급하다","partOfSpeech":"v.","example":"Social media makes it easy to disseminate information to millions of people instantly.","exampleTranslation":"소셜 미디어는 수백만 명에게 정보를 즉시 전파하기 쉽게 만들어 줍니다.","level":44,"category":"빈도 학습"},{"id":15279,"term":"dissident","meaning":"반체제 인사; 반대하는","partOfSpeech":"n.","example":"The dissident was arrested for openly criticizing the government.","exampleTranslation":"그 반체제 인사는 정부를 공개적으로 비판했다는 이유로 체포되었습니다.","level":44,"category":"빈도 학습"},{"id":15280,"term":"distaste","meaning":"혐오감; 불쾌함","partOfSpeech":"n.","example":"He could not hide his distaste for the overly spicy food.","exampleTranslation":"그는 지나치게 매운 음식에 대한 혐오감을 감추지 못했습니다.","level":44,"category":"빈도 학습"},{"id":15281,"term":"distill","meaning":"증류하다; 핵심을 추출하다","partOfSpeech":"v.","example":"They distill water using a special filter to make it safe to drink.","exampleTranslation":"그들은 마시기 안전하게 만들기 위해 특수 필터로 물을 증류합니다.","level":44,"category":"빈도 학습"},{"id":15282,"term":"distrust","meaning":"불신; 불신하다","partOfSpeech":"n.","example":"Years of broken promises created deep distrust between the two sides.","exampleTranslation":"수년간 약속을 어긴 탓에 양측 사이에 깊은 불신이 생겼습니다.","level":44,"category":"빈도 학습"},{"id":15283,"term":"donkey","meaning":"당나귀","partOfSpeech":"n.","example":"The farmer used a donkey to carry heavy loads up the hillside.","exampleTranslation":"농부는 언덕길에서 무거운 짐을 운반하기 위해 당나귀를 이용했습니다.","level":44,"category":"빈도 학습"},{"id":15284,"term":"dormitory","meaning":"기숙사; 공동 침실","partOfSpeech":"n.","example":"She lived in a campus dormitory during her first year of college.","exampleTranslation":"그녀는 대학 첫 해에 캠퍼스 기숙사에서 생활했습니다.","level":44,"category":"빈도 학습"},{"id":15285,"term":"dough","meaning":"반죽; 돈(속어)","partOfSpeech":"n.","example":"She kneaded the dough for ten minutes before shaping it into loaves.","exampleTranslation":"그녀는 반죽을 10분간 치댄 뒤 빵 모양으로 만들었습니다.","level":44,"category":"빈도 학습"},{"id":15286,"term":"dove","meaning":"비둘기; 평화의 상징","partOfSpeech":"n.","example":"A white dove flew over the crowd during the peace ceremony.","exampleTranslation":"평화 기념식 중에 흰 비둘기 한 마리가 군중 위를 날아갔습니다.","level":44,"category":"빈도 학습"},{"id":15287,"term":"drawback","meaning":"단점; 불리한 점","partOfSpeech":"n.","example":"The main drawback of this plan is that it will cost too much money.","exampleTranslation":"이 계획의 가장 큰 단점은 돈이 너무 많이 든다는 것입니다.","level":44,"category":"빈도 학습"},{"id":15288,"term":"duct","meaning":"도관; 통로","partOfSpeech":"n.","example":"The technician checked every air duct in the building for blockages.","exampleTranslation":"기술자는 막힌 곳이 있는지 건물의 모든 환기 도관을 점검했습니다.","level":44,"category":"빈도 학습"},{"id":15289,"term":"dummy","meaning":"모형; 가짜; 마네킹","partOfSpeech":"n.","example":"The store window displayed a dummy wearing the latest fashion.","exampleTranslation":"가게 쇼윈도에는 최신 패션을 입은 마네킹이 전시되어 있었습니다.","level":44,"category":"빈도 학습"},{"id":15290,"term":"dune","meaning":"모래 언덕","partOfSpeech":"n.","example":"We climbed to the top of a tall dune to watch the desert sunset.","exampleTranslation":"우리는 사막의 석양을 보기 위해 높은 모래 언덕 꼭대기에 올랐습니다.","level":44,"category":"빈도 학습"},{"id":15291,"term":"dwindle","meaning":"점점 줄어들다; 감소하다","partOfSpeech":"v.","example":"Their savings began to dwindle after months of unemployment.","exampleTranslation":"몇 달간의 실직 후 그들의 저축이 점점 줄어들기 시작했습니다.","level":44,"category":"빈도 학습"},{"id":15292,"term":"dynasty","meaning":"왕조; 왕가","partOfSpeech":"n.","example":"The dynasty ruled the country for over three hundred years.","exampleTranslation":"그 왕조는 300년 이상 나라를 통치했습니다.","level":44,"category":"빈도 학습"},{"id":15293,"term":"ecosystem","meaning":"생태계","partOfSpeech":"n.","example":"Pollution is seriously damaging the ocean ecosystem.","exampleTranslation":"오염이 해양 생태계를 심각하게 훼손하고 있습니다.","level":44,"category":"빈도 학습"},{"id":15294,"term":"eerie","meaning":"으스스한; 기묘한","partOfSpeech":"adj.","example":"There was an eerie silence in the house after the storm passed.","exampleTranslation":"폭풍이 지나간 후 집 안에는 으스스한 고요함이 감돌았습니다.","level":44,"category":"빈도 학습"},{"id":15295,"term":"eldest","meaning":"가장 나이 많은; 맏이의","partOfSpeech":"adj.","example":"The eldest child in the family often takes on extra responsibilities.","exampleTranslation":"가족 중 맏이는 종종 더 많은 책임을 맡습니다.","level":44,"category":"빈도 학습"},{"id":15296,"term":"elegance","meaning":"우아함; 기품","partOfSpeech":"n.","example":"The ballroom was decorated with great elegance for the charity gala.","exampleTranslation":"무도회장은 자선 갈라를 위해 매우 우아하게 장식되었습니다.","level":44,"category":"빈도 학습"},{"id":15297,"term":"eloquent","meaning":"웅변적인; 표현이 유창한","partOfSpeech":"adj.","example":"The mayor gave an eloquent speech that moved many in the audience to tears.","exampleTranslation":"시장은 청중의 많은 사람을 눈물짓게 한 감동적인 연설을 했습니다.","level":44,"category":"빈도 학습"},{"id":15298,"term":"emanate","meaning":"발산하다; 흘러나오다","partOfSpeech":"v.","example":"A warm glow seemed to emanate from the fireplace on that cold evening.","exampleTranslation":"그 추운 저녁 벽난로에서 따뜻한 빛이 흘러나오는 것 같았습니다.","level":44,"category":"빈도 학습"},{"id":15299,"term":"embargo","meaning":"무역 금지; 통상 금지령","partOfSpeech":"n.","example":"The government placed an embargo on imported goods from that country.","exampleTranslation":"정부는 그 나라로부터의 수입품에 무역 금지 조치를 취했습니다.","level":44,"category":"빈도 학습"},{"id":15300,"term":"eminent","meaning":"著名한; 탁월한","partOfSpeech":"adj.","example":"An eminent professor from Oxford was invited to give the keynote speech.","exampleTranslation":"옥스퍼드의 著名한 교수가 기조연설을 하도록 초청되었습니다.","level":44,"category":"빈도 학습"},{"id":15301,"term":"empathy","meaning":"공감; 감정이입","partOfSpeech":"n.","example":"Good teachers show empathy toward students who are struggling.","exampleTranslation":"훌륭한 교사는 어려움을 겪는 학생들에게 공감을 보여줍니다.","level":44,"category":"빈도 학습"},{"id":15302,"term":"emphatic","meaning":"강조하는; 단호한","partOfSpeech":"adj.","example":"She gave an emphatic no when asked if she wanted to work overtime.","exampleTranslation":"그녀는 초과 근무를 원하느냐는 질문에 단호하게 거절했습니다.","level":44,"category":"빈도 학습"},{"id":15303,"term":"emulate","meaning":"모방하다; 따라 하다","partOfSpeech":"v.","example":"Young athletes often try to emulate their favorite sports stars.","exampleTranslation":"젊은 운동선수들은 종종 자신이 가장 좋아하는 스포츠 스타를 모방하려 합니다.","level":44,"category":"빈도 학습"},{"id":15304,"term":"enchant","meaning":"매혹하다; 마법을 걸다","partOfSpeech":"v.","example":"The children's performance managed to enchant everyone in the audience.","exampleTranslation":"어린이들의 공연은 관객 모두를 매혹시켰습니다.","level":44,"category":"빈도 학습"},{"id":15305,"term":"encode","meaning":"부호화하다; 암호화하다","partOfSpeech":"v.","example":"The system will automatically encode your password to keep it secure.","exampleTranslation":"시스템이 자동으로 비밀번호를 암호화하여 안전하게 보호합니다.","level":44,"category":"빈도 학습"},{"id":15306,"term":"entice","meaning":"유혹하다; 꾀다","partOfSpeech":"v.","example":"The store used big discounts to entice new customers through the door.","exampleTranslation":"가게는 새 고객을 유인하기 위해 큰 할인 행사를 활용했습니다.","level":44,"category":"빈도 학습"},{"id":15307,"term":"entrench","meaning":"굳히다; 깊이 박히게 하다","partOfSpeech":"v.","example":"Years of habit can entrench certain behaviors that are hard to change.","exampleTranslation":"수년간의 습관은 바꾸기 어려운 특정 행동을 굳혀버릴 수 있습니다.","level":44,"category":"빈도 학습"},{"id":15308,"term":"epidemiology","meaning":"역학(疫學); 전염병학","partOfSpeech":"n.","example":"Students who study epidemiology learn how diseases spread through populations.","exampleTranslation":"역학을 공부하는 학생들은 질병이 인구 집단에서 어떻게 퍼지는지 배웁니다.","level":44,"category":"빈도 학습"},{"id":15309,"term":"epistemology","meaning":"인식론","partOfSpeech":"n.","example":"The philosophy course covered epistemology and the nature of human knowledge.","exampleTranslation":"그 철학 수업은 인식론과 인간 지식의 본질을 다뤘습니다.","level":44,"category":"빈도 학습"},{"id":15310,"term":"equate","meaning":"동일시하다; 같다고 보다","partOfSpeech":"v.","example":"Many people equate success with having a lot of money.","exampleTranslation":"많은 사람들이 성공을 많은 돈을 갖는 것과 동일시합니다.","level":44,"category":"빈도 학습"},{"id":15311,"term":"equitable","meaning":"공평한; 공정한","partOfSpeech":"adj.","example":"The manager tried to find an equitable solution that satisfied both teams.","exampleTranslation":"관리자는 두 팀 모두를 만족시키는 공평한 해결책을 찾으려 했습니다.","level":44,"category":"빈도 학습"},{"id":15312,"term":"equivocal","meaning":"애매한; 모호한","partOfSpeech":"adj.","example":"His equivocal answer left everyone unsure of what he actually meant.","exampleTranslation":"그의 애매한 대답은 모두가 그가 실제로 무슨 뜻인지 확신할 수 없게 했습니다.","level":44,"category":"빈도 학습"},{"id":15313,"term":"eradicate","meaning":"근절하다; 완전히 없애다","partOfSpeech":"v.","example":"The organization works hard to eradicate poverty in rural areas.","exampleTranslation":"그 단체는 농촌 지역에서 빈곤을 근절하기 위해 열심히 노력합니다.","level":44,"category":"빈도 학습"},{"id":15314,"term":"err","meaning":"실수하다; 잘못을 저지르다","partOfSpeech":"v.","example":"It is human to err, so try not to be too hard on yourself.","exampleTranslation":"실수하는 것은 인간적인 일이니 너무 자책하지 마세요.","level":44,"category":"빈도 학습"},{"id":15315,"term":"esteem","meaning":"존경; 존중하다","partOfSpeech":"n.","example":"She was held in high esteem by all of her colleagues at the hospital.","exampleTranslation":"그녀는 병원의 모든 동료들에게 매우 높은 존경을 받았습니다.","level":44,"category":"빈도 학습"},{"id":15316,"term":"etch","meaning":"새기다; 부식시키다","partOfSpeech":"v.","example":"The artist used acid to etch a detailed pattern onto the metal plate.","exampleTranslation":"그 예술가는 금속판에 세밀한 무늬를 새기기 위해 산을 사용했습니다.","level":44,"category":"빈도 학습"},{"id":15317,"term":"eternity","meaning":"영원; 무한한 시간","partOfSpeech":"n.","example":"Waiting in that line felt like an eternity on a hot summer day.","exampleTranslation":"뜨거운 여름날 그 줄에서 기다리는 것은 영원처럼 느껴졌습니다.","level":44,"category":"빈도 학습"},{"id":15318,"term":"ethanol","meaning":"에탄올; 에틸알코올","partOfSpeech":"n.","example":"The lab technician used ethanol to sterilize the equipment before testing.","exampleTranslation":"실험실 기술자는 검사 전 장비를 소독하기 위해 에탄올을 사용했습니다.","level":44,"category":"빈도 학습"},{"id":15319,"term":"ethnography","meaning":"민족지학; 문화 기술지","partOfSpeech":"n.","example":"Her dissertation was based on ethnography conducted in a remote fishing community.","exampleTranslation":"그녀의 논문은 외딴 어촌 공동체에서 수행한 민족지학 연구를 바탕으로 했습니다.","level":44,"category":"빈도 학습"},{"id":15320,"term":"euro","meaning":"유로(유럽 통화 단위)","partOfSpeech":"n.","example":"The coffee shop in Paris charged five euro for a small latte.","exampleTranslation":"파리의 그 커피숍은 작은 라떼 한 잔에 5유로를 받았습니다.","level":44,"category":"빈도 학습"},{"id":15321,"term":"evade","meaning":"피하다; 회피하다","partOfSpeech":"v.","example":"He tried to evade the question by changing the subject.","exampleTranslation":"그는 주제를 바꿔 질문을 회피하려 했습니다.","level":44,"category":"빈도 학습"},{"id":15322,"term":"evict","meaning":"퇴거시키다; 내쫓다","partOfSpeech":"v.","example":"The landlord had no choice but to evict the tenant for not paying rent.","exampleTranslation":"집주인은 임차인이 임대료를 내지 않아 퇴거시킬 수밖에 없었습니다.","level":44,"category":"빈도 학습"},{"id":15323,"term":"exasperate","meaning":"몹시 화나게 하다; 짜증나게 하다","partOfSpeech":"v.","example":"Constant interruptions during the meeting began to exasperate the presenter.","exampleTranslation":"회의 중 계속되는 방해가 발표자를 몹시 짜증나게 하기 시작했습니다.","level":44,"category":"빈도 학습"},{"id":15324,"term":"excel","meaning":"뛰어나다; 탁월하다","partOfSpeech":"v.","example":"She worked hard every day to excel in her chosen field.","exampleTranslation":"그녀는 선택한 분야에서 뛰어나기 위해 매일 열심히 노력했습니다.","level":44,"category":"빈도 학습"},{"id":15325,"term":"excise","meaning":"소비세; 제거하다","partOfSpeech":"n.","example":"The government raised the excise on tobacco products to discourage smoking.","exampleTranslation":"정부는 흡연을 억제하기 위해 담배 제품에 대한 소비세를 인상했습니다.","level":44,"category":"빈도 학습"},{"id":15326,"term":"excursion","meaning":"소풍; 짧은 여행","partOfSpeech":"n.","example":"The school organized a day excursion to a nearby nature reserve.","exampleTranslation":"학교는 인근 자연 보호 구역으로 당일 소풍을 계획했습니다.","level":44,"category":"빈도 학습"},{"id":15327,"term":"exemplar","meaning":"모범; 전형적인 예","partOfSpeech":"n.","example":"Her career is often cited as an exemplar of perseverance and hard work.","exampleTranslation":"그녀의 경력은 인내와 노력의 모범으로 자주 언급됩니다.","level":44,"category":"빈도 학습"},{"id":15328,"term":"exemplify","meaning":"예시하다; 전형이 되다","partOfSpeech":"v.","example":"His behavior continues to exemplify the values the organization stands for.","exampleTranslation":"그의 행동은 조직이 추구하는 가치를 계속해서 잘 보여줍니다.","level":44,"category":"빈도 학습"},{"id":15329,"term":"exhilarate","meaning":"기분을 들뜨게 하다; 활기차게 하다","partOfSpeech":"v.","example":"The view from the mountaintop never fails to exhilarate anyone who reaches it.","exampleTranslation":"산 정상에서의 전망은 그곳에 오른 사람을 언제나 기분 좋게 만듭니다.","level":44,"category":"빈도 학습"},{"id":15330,"term":"explicable","meaning":"설명 가능한; 이해할 수 있는","partOfSpeech":"adj.","example":"The sudden drop in sales was barely explicable given how well the product had performed.","exampleTranslation":"제품 실적이 워낙 좋았던 터라 갑작스러운 매출 하락은 쉽게 설명하기 어려웠습니다.","level":44,"category":"빈도 학습"},{"id":15331,"term":"extravagant","meaning":"사치스러운; 과도한","partOfSpeech":"adj.","example":"She felt that spending so much on a single meal was extravagant.","exampleTranslation":"그녀는 한 끼 식사에 그렇게 많이 쓰는 것은 사치스럽다고 느꼈습니다.","level":44,"category":"빈도 학습"},{"id":15332,"term":"fabricate","meaning":"조작하다; 만들어 내다","partOfSpeech":"v.","example":"The witness admitted she had been pressured to fabricate her testimony.","exampleTranslation":"목격자는 자신의 증언을 조작하도록 압력을 받았다고 인정했습니다.","level":44,"category":"빈도 학습"},{"id":15333,"term":"facet","meaning":"면; 측면","partOfSpeech":"n.","example":"Leadership is just one facet of what makes a good manager.","exampleTranslation":"리더십은 좋은 관리자를 만드는 여러 측면 중 하나일 뿐입니다.","level":44,"category":"빈도 학습"},{"id":15334,"term":"falcon","meaning":"매(새)","partOfSpeech":"n.","example":"The trainer released the falcon and watched it soar high into the sky.","exampleTranslation":"조련사는 매를 풀어주고 하늘 높이 솟구치는 것을 바라봤습니다.","level":44,"category":"빈도 학습"},{"id":15335,"term":"falter","meaning":"흔들리다; 머뭇거리다","partOfSpeech":"v.","example":"Her confidence began to falter when the audience stopped paying attention.","exampleTranslation":"청중이 집중하지 않자 그녀의 자신감이 흔들리기 시작했습니다.","level":44,"category":"빈도 학습"},{"id":15336,"term":"famine","meaning":"기근; 극심한 식량 부족","partOfSpeech":"n.","example":"Aid organizations rushed supplies to the region suffering from famine.","exampleTranslation":"구호 단체들이 기근에 시달리는 지역에 물자를 서둘러 보냈습니다.","level":44,"category":"빈도 학습"},{"id":15337,"term":"fanatic","meaning":"광신자; 열광적인 사람","partOfSpeech":"n.","example":"He is such a fanatic about fitness that he goes to the gym twice a day.","exampleTranslation":"그는 운동에 너무 열광적이어서 하루에 두 번 헬스장에 갑니다.","level":45,"category":"빈도 학습"},{"id":15338,"term":"fascist","meaning":"파시스트; 극단적 독재주의자","partOfSpeech":"n.","example":"The documentary traced how a fascist regime rose to power in the 1930s.","exampleTranslation":"그 다큐멘터리는 1930년대에 파시스트 정권이 어떻게 권력을 잡았는지를 추적했습니다.","level":45,"category":"빈도 학습"},{"id":15339,"term":"feat","meaning":"위업; 묘기","partOfSpeech":"n.","example":"Climbing that mountain alone was a remarkable feat of endurance.","exampleTranslation":"혼자 그 산을 오른 것은 놀라운 인내의 위업이었습니다.","level":45,"category":"빈도 학습"},{"id":15340,"term":"feeble","meaning":"허약한; 힘없는","partOfSpeech":"adj.","example":"The old man's feeble voice was hard to hear across the crowded room.","exampleTranslation":"노인의 힘없는 목소리는 사람들로 가득 찬 방 저편에서 듣기 어려웠습니다.","level":45,"category":"빈도 학습"},{"id":15341,"term":"felled","meaning":"벌채된; 쓰러뜨려진","partOfSpeech":"adj.","example":"The path was blocked by a large felled tree after the storm.","exampleTranslation":"폭풍이 지나간 후 큰 벌채된 나무가 길을 막고 있었습니다.","level":45,"category":"빈도 학습"},{"id":15342,"term":"feminism","meaning":"페미니즘; 여성 평등주의","partOfSpeech":"n.","example":"The professor taught a class on the history of feminism in the twentieth century.","exampleTranslation":"그 교수는 20세기 페미니즘의 역사에 관한 수업을 가르쳤습니다.","level":45,"category":"빈도 학습"},{"id":15343,"term":"fern","meaning":"고사리(식물)","partOfSpeech":"n.","example":"A large fern grew in the shady corner of the garden near the fence.","exampleTranslation":"울타리 근처 정원의 그늘진 구석에 큰 고사리가 자라고 있었습니다.","level":45,"category":"빈도 학습"},{"id":15344,"term":"fidelity","meaning":"충실; 충성; 재현 정밀도","partOfSpeech":"n.","example":"The biographer was praised for her fidelity to the facts of the subject's life.","exampleTranslation":"그 전기 작가는 인물의 삶에 대한 사실에 충실한 점에서 찬사를 받았습니다.","level":45,"category":"빈도 학습"},{"id":15345,"term":"fiery","meaning":"불같은; 격렬한","partOfSpeech":"adj.","example":"She gave a fiery speech that inspired everyone in the audience.","exampleTranslation":"그녀는 청중 모두를 감동시키는 불같은 연설을 했습니다.","level":45,"category":"빈도 학습"},{"id":15347,"term":"finite","meaning":"유한한; 한계가 있는","partOfSpeech":"adj.","example":"We only have a finite amount of time to finish the project before the deadline.","exampleTranslation":"우리는 마감일 전에 프로젝트를 마칠 유한한 시간만 있습니다.","level":45,"category":"빈도 학습"},{"id":15348,"term":"firearm","meaning":"화기; 총기","partOfSpeech":"n.","example":"The law requires a background check before purchasing a firearm.","exampleTranslation":"법에 따라 화기를 구매하기 전에 신원 조회가 필요합니다.","level":45,"category":"빈도 학습"},{"id":15349,"term":"firefight","meaning":"총격전; 교전","partOfSpeech":"n.","example":"The soldiers were caught in a fierce firefight near the border crossing.","exampleTranslation":"병사들은 국경 검문소 근처에서 치열한 총격전에 휘말렸습니다.","level":45,"category":"빈도 학습"},{"id":15350,"term":"firework","meaning":"불꽃놀이; 폭죽","partOfSpeech":"n.","example":"A single firework lit up the night sky at exactly midnight.","exampleTranslation":"자정 정각에 불꽃 하나가 밤하늘을 환하게 밝혔습니다.","level":45,"category":"빈도 학습"},{"id":15352,"term":"flex","meaning":"구부리다; 유연하게 하다","partOfSpeech":"v.","example":"He likes to flex his fingers before sitting down to play the piano.","exampleTranslation":"그는 피아노를 치기 전에 손가락을 구부려 풀기를 좋아합니다.","level":45,"category":"빈도 학습"},{"id":15353,"term":"flirt","meaning":"희롱하다; 가볍게 사귀다","partOfSpeech":"v.","example":"He would always flirt with the barista when ordering his morning coffee.","exampleTranslation":"그는 아침 커피를 주문할 때마다 바리스타에게 가볍게 농담을 건네곤 했습니다.","level":45,"category":"빈도 학습"},{"id":15354,"term":"flora","meaning":"식물상; 특정 지역의 식물","partOfSpeech":"n.","example":"The national park protects the native flora and fauna of the region.","exampleTranslation":"그 국립공원은 이 지역의 토착 식물상과 동물상을 보호합니다.","level":45,"category":"빈도 학습"},{"id":15355,"term":"floral","meaning":"꽃의; 꽃무늬의","partOfSpeech":"adj.","example":"She wore a bright floral dress to the outdoor garden party.","exampleTranslation":"그녀는 야외 정원 파티에 밝은 꽃무늬 드레스를 입고 갔습니다.","level":45,"category":"빈도 학습"},{"id":15356,"term":"fluent","meaning":"유창한; 능숙한","partOfSpeech":"adj.","example":"After two years in Spain, she became fluent in Spanish.","exampleTranslation":"스페인에서 2년을 보낸 후, 그녀는 스페인어에 유창해졌습니다.","level":45,"category":"빈도 학습"},{"id":15357,"term":"fluff","meaning":"솜털; 보풀; 사소한 것","partOfSpeech":"n.","example":"She picked a piece of fluff off her dark jacket before the interview.","exampleTranslation":"그녀는 면접 전 검은 재킷에서 보풀 한 조각을 떼어냈습니다.","level":45,"category":"빈도 학습"},{"id":15358,"term":"fluorescent","meaning":"형광의; 형광 빛을 내는","partOfSpeech":"adj.","example":"The ceiling was fitted with a long fluorescent light that brightened the whole room.","exampleTranslation":"천장에는 방 전체를 환하게 밝히는 긴 형광등이 설치되어 있었습니다.","level":45,"category":"빈도 학습"},{"id":15359,"term":"flute","meaning":"플루트(악기); 세로홈","partOfSpeech":"n.","example":"She practiced the flute for an hour every evening before dinner.","exampleTranslation":"그녀는 저녁 식사 전 매일 저녁 한 시간씩 플루트를 연습했습니다.","level":45,"category":"빈도 학습"},{"id":15360,"term":"flux","meaning":"변화; 유동 상태","partOfSpeech":"n.","example":"The company's strategy is in flux as new leadership takes over.","exampleTranslation":"새 경영진이 들어오면서 회사의 전략이 유동적인 상태에 있습니다.","level":45,"category":"빈도 학습"},{"id":15361,"term":"focal","meaning":"초점의; 중심의","partOfSpeech":"adj.","example":"The large fireplace was the focal point of the entire living room.","exampleTranslation":"큰 벽난로는 거실 전체의 중심이 되는 초점이었습니다.","level":45,"category":"빈도 학습"},{"id":15362,"term":"foe","meaning":"적; 원수","partOfSpeech":"n.","example":"In the story, the hero must outsmart a foe who knows his every weakness.","exampleTranslation":"이야기에서 주인공은 자신의 모든 약점을 아는 적을 꾀로 이겨야 합니다.","level":45,"category":"빈도 학습"},{"id":15363,"term":"folder","meaning":"폴더; 서류철","partOfSpeech":"n.","example":"She kept all the signed contracts in a clearly labeled folder on her desk.","exampleTranslation":"그녀는 서명된 계약서를 모두 책상 위의 명확히 표시된 폴더에 보관했습니다.","level":45,"category":"빈도 학습"},{"id":15364,"term":"folly","meaning":"어리석음; 바보 같은 행동","partOfSpeech":"n.","example":"Investing all your savings in one stock is pure folly.","exampleTranslation":"모든 저축을 하나의 주식에 투자하는 것은 완전한 어리석음입니다.","level":45,"category":"빈도 학습"},{"id":15365,"term":"forensic","meaning":"법의학의; 법정의","partOfSpeech":"adj.","example":"The forensic team collected evidence from the scene before it could be disturbed.","exampleTranslation":"법의학 팀은 현장이 훼손되기 전에 증거를 수집했습니다.","level":45,"category":"빈도 학습"},{"id":15366,"term":"forgo","meaning":"포기하다; 삼가다","partOfSpeech":"v.","example":"She decided to forgo dessert to stick to her diet.","exampleTranslation":"그녀는 다이어트를 유지하기 위해 디저트를 포기하기로 했습니다.","level":45,"category":"빈도 학습"},{"id":15367,"term":"fortify","meaning":"강화하다; 요새화하다","partOfSpeech":"v.","example":"They worked to fortify the old walls before the storm arrived.","exampleTranslation":"그들은 폭풍이 오기 전에 낡은 벽을 강화하는 작업을 했습니다.","level":45,"category":"빈도 학습"},{"id":15368,"term":"fortress","meaning":"요새; 성채","partOfSpeech":"n.","example":"Tourists visited the ancient fortress built on top of the hill.","exampleTranslation":"관광객들이 언덕 꼭대기에 세워진 고대 요새를 방문했습니다.","level":45,"category":"빈도 학습"},{"id":15369,"term":"frail","meaning":"허약한; 연약한","partOfSpeech":"adj.","example":"The frail old man needed help carrying his groceries home.","exampleTranslation":"그 허약한 노인은 식료품을 집까지 나르는 데 도움이 필요했습니다.","level":45,"category":"빈도 학습"},{"id":15370,"term":"fray","meaning":"닳다; 해지다; 언쟁","partOfSpeech":"v.","example":"The edges of his old jacket began to fray after years of use.","exampleTranslation":"그의 낡은 재킷 끝부분이 수년간 사용한 끝에 닳기 시작했습니다.","level":45,"category":"빈도 학습"},{"id":15371,"term":"freak","meaning":"괴짜; 이상한 사람; 광팬","partOfSpeech":"n.","example":"He is a total freak about keeping his workspace perfectly clean.","exampleTranslation":"그는 작업 공간을 완벽하게 깔끔하게 유지하는 것에 집착하는 사람입니다.","level":45,"category":"빈도 학습"},{"id":15372,"term":"freelance","meaning":"프리랜서; 자유계약의","partOfSpeech":"adj.","example":"She works as a freelance writer for several online magazines.","exampleTranslation":"그녀는 여러 온라인 잡지에 프리랜서 작가로 일합니다.","level":45,"category":"빈도 학습"},{"id":15373,"term":"frenzy","meaning":"열광; 광란","partOfSpeech":"n.","example":"The crowd was in a frenzy when their team scored the winning goal.","exampleTranslation":"팀이 결승 골을 넣었을 때 군중은 열광했습니다.","level":45,"category":"빈도 학습"},{"id":15374,"term":"fret","meaning":"안달하다; 걱정하다","partOfSpeech":"v.","example":"There is no need to fret over small mistakes at work.","exampleTranslation":"직장에서의 사소한 실수에 대해 안달할 필요가 없습니다.","level":45,"category":"빈도 학습"},{"id":15375,"term":"friction","meaning":"마찰; 불화","partOfSpeech":"n.","example":"There was some friction between the two departments over budget cuts.","exampleTranslation":"예산 삭감 문제로 두 부서 사이에 약간의 불화가 있었습니다.","level":45,"category":"빈도 학습"},{"id":15376,"term":"fumble","meaning":"더듬다; 실수하다","partOfSpeech":"v.","example":"He began to fumble with his keys when he heard a noise outside.","exampleTranslation":"그는 밖에서 소리를 듣자 열쇠를 더듬기 시작했습니다.","level":45,"category":"빈도 학습"},{"id":15377,"term":"futile","meaning":"헛된; 소용없는","partOfSpeech":"adj.","example":"It seemed futile to argue with him when he had already made up his mind.","exampleTranslation":"이미 마음을 정한 그와 다투는 것은 헛된 일처럼 보였습니다.","level":45,"category":"빈도 학습"},{"id":15378,"term":"gag","meaning":"재갈; 개그; 입을 막다","partOfSpeech":"n.","example":"The comedian's opening gag made the whole audience burst out laughing.","exampleTranslation":"그 코미디언의 오프닝 개그에 관객 전체가 폭소를 터뜨렸습니다.","level":45,"category":"빈도 학습"},{"id":15379,"term":"gala","meaning":"갈라; 화려한 행사","partOfSpeech":"n.","example":"The charity gala raised over a million dollars for local hospitals.","exampleTranslation":"그 자선 갈라 행사는 지역 병원을 위해 백만 달러 이상을 모금했습니다.","level":45,"category":"빈도 학습"},{"id":15380,"term":"gall","meaning":"뻔뻔함; 담즙; 화나게 하다","partOfSpeech":"n.","example":"She had the gall to ask for a raise right after arriving late.","exampleTranslation":"그녀는 지각한 직후에 뻔뻔하게도 임금 인상을 요구했습니다.","level":45,"category":"빈도 학습"},{"id":15381,"term":"gallop","meaning":"전속력으로 달리다; 질주","partOfSpeech":"v.","example":"The horse began to gallop across the open field at full speed.","exampleTranslation":"그 말은 넓은 들판을 전속력으로 질주하기 시작했습니다.","level":45,"category":"빈도 학습"},{"id":15382,"term":"gape","meaning":"입을 벌리고 바라보다; 멍하니 쳐다보다","partOfSpeech":"v.","example":"The children began to gape at the giant sculpture in the middle of the square.","exampleTranslation":"아이들은 광장 한가운데에 있는 거대한 조각품을 입을 벌리고 바라보기 시작했습니다.","level":45,"category":"빈도 학습"},{"id":15383,"term":"garbage","meaning":"쓰레기; 폐기물","partOfSpeech":"n.","example":"Please put the garbage in the bin before you leave the kitchen.","exampleTranslation":"부엌을 떠나기 전에 쓰레기를 통에 넣어 주세요.","level":45,"category":"빈도 학습"},{"id":15384,"term":"garnish","meaning":"장식하다; 고명","partOfSpeech":"v.","example":"The chef used fresh herbs to garnish the dish before serving.","exampleTranslation":"주방장은 서빙하기 전에 신선한 허브로 요리를 장식했습니다.","level":45,"category":"빈도 학습"},{"id":15385,"term":"garrison","meaning":"수비대; 주둔군","partOfSpeech":"n.","example":"The garrison was stationed at the border to protect the town.","exampleTranslation":"수비대는 마을을 보호하기 위해 국경에 주둔하고 있었습니다.","level":45,"category":"빈도 학습"},{"id":15386,"term":"gem","meaning":"보석; 귀중한 것","partOfSpeech":"n.","example":"This little restaurant is a hidden gem that locals rarely share.","exampleTranslation":"이 작은 레스토랑은 현지인들이 좀처럼 알려주지 않는 숨겨진 보석 같은 곳입니다.","level":45,"category":"빈도 학습"},{"id":15387,"term":"genesis","meaning":"기원; 창세기","partOfSpeech":"n.","example":"The professor explained the genesis of the modern political movement.","exampleTranslation":"교수는 현대 정치 운동의 기원을 설명했습니다.","level":45,"category":"빈도 학습"},{"id":15388,"term":"genome","meaning":"게놈; 유전체","partOfSpeech":"n.","example":"Scientists mapped the entire genome of the plant to study its traits.","exampleTranslation":"과학자들은 식물의 특성을 연구하기 위해 전체 게놈을 분석했습니다.","level":45,"category":"빈도 학습"},{"id":15389,"term":"gentry","meaning":"신사 계급; 상류층","partOfSpeech":"n.","example":"The gentry of the region gathered at the manor for the annual festival.","exampleTranslation":"그 지역의 신사 계급이 연례 축제를 위해 저택에 모였습니다.","level":45,"category":"빈도 학습"},{"id":15390,"term":"gigantic","meaning":"거대한; 엄청난","partOfSpeech":"adj.","example":"A gigantic wave hit the beach and surprised everyone nearby.","exampleTranslation":"거대한 파도가 해변을 강타해 근처의 모든 사람을 놀라게 했습니다.","level":45,"category":"빈도 학습"},{"id":15391,"term":"gin","meaning":"진(술); 목화 씨 제거기","partOfSpeech":"n.","example":"She ordered a gin and tonic at the bar after a long day at work.","exampleTranslation":"그녀는 긴 하루 업무를 마치고 바에서 진 토닉을 주문했습니다.","level":45,"category":"빈도 학습"},{"id":15392,"term":"glacier","meaning":"빙하","partOfSpeech":"n.","example":"The glacier has been slowly melting due to rising temperatures.","exampleTranslation":"그 빙하는 기온 상승으로 인해 천천히 녹고 있습니다.","level":45,"category":"빈도 학습"},{"id":15393,"term":"gland","meaning":"선(腺); 분비샘","partOfSpeech":"n.","example":"The doctor checked whether the gland in his neck was swollen.","exampleTranslation":"의사는 목의 분비샘이 부어 있는지 확인했습니다.","level":45,"category":"빈도 학습"},{"id":15394,"term":"glint","meaning":"반짝이다; 번득임","partOfSpeech":"v.","example":"Sunlight made the coins on the ground glint in the afternoon light.","exampleTranslation":"햇빛이 오후 빛 속에서 땅 위의 동전을 반짝이게 했습니다.","level":45,"category":"빈도 학습"},{"id":15395,"term":"glisten","meaning":"반짝반짝 빛나다; 번들거리다","partOfSpeech":"v.","example":"Her eyes began to glisten with tears when she heard the good news.","exampleTranslation":"그녀는 좋은 소식을 듣고 눈이 눈물로 반짝이기 시작했습니다.","level":45,"category":"빈도 학습"},{"id":15396,"term":"gloss","meaning":"광택; 윤; 얼버무리다","partOfSpeech":"n.","example":"The new paint gave the wooden floor a beautiful gloss finish.","exampleTranslation":"새 페인트가 목재 바닥에 아름다운 광택 마감을 선사했습니다.","level":45,"category":"빈도 학습"},{"id":15397,"term":"glossy","meaning":"광택 있는; 번들번들한","partOfSpeech":"adj.","example":"The magazine had glossy pages filled with colorful fashion photos.","exampleTranslation":"그 잡지는 화려한 패션 사진으로 가득 찬 광택 있는 페이지로 이루어져 있었습니다.","level":45,"category":"빈도 학습"},{"id":15398,"term":"godfather","meaning":"대부; 후견인","partOfSpeech":"n.","example":"He asked his closest friend to be the godfather of his newborn child.","exampleTranslation":"그는 가장 친한 친구에게 갓 태어난 아이의 대부가 되어 달라고 부탁했습니다.","level":45,"category":"빈도 학습"},{"id":15399,"term":"gothic","meaning":"고딕 양식의; 어둡고 음산한","partOfSpeech":"adj.","example":"The gothic cathedral in the city center draws thousands of visitors each year.","exampleTranslation":"도심에 있는 고딕 양식의 대성당은 매년 수천 명의 방문객을 끌어들입니다.","level":45,"category":"빈도 학습"},{"id":15400,"term":"gracious","meaning":"우아한; 친절한; 자비로운","partOfSpeech":"adj.","example":"The gracious host made sure every guest felt welcome at the dinner.","exampleTranslation":"그 친절한 주인은 저녁 식사에서 모든 손님이 환영받는다고 느끼도록 배려했습니다.","level":45,"category":"빈도 학습"},{"id":15401,"term":"graft","meaning":"접목하다; 이식하다; 부패","partOfSpeech":"v.","example":"The surgeon had to graft new skin over the burned area of the patient.","exampleTranslation":"외과 의사는 환자의 화상 부위에 새 피부를 이식해야 했습니다.","level":45,"category":"빈도 학습"},{"id":15402,"term":"granite","meaning":"화강암","partOfSpeech":"n.","example":"The kitchen countertop is made of polished granite imported from Italy.","exampleTranslation":"주방 조리대는 이탈리아에서 수입한 연마된 화강암으로 만들어졌습니다.","level":45,"category":"빈도 학습"},{"id":15403,"term":"granny","meaning":"할머니","partOfSpeech":"n.","example":"My granny always bakes cookies for us whenever we visit her.","exampleTranslation":"우리 할머니는 우리가 방문할 때마다 항상 쿠키를 구워 주십니다.","level":45,"category":"빈도 학습"},{"id":15404,"term":"gratify","meaning":"만족시키다; 기쁘게 하다","partOfSpeech":"v.","example":"It would greatly gratify me to see you succeed in your career.","exampleTranslation":"당신이 직업적으로 성공하는 것을 보면 정말 기쁠 것 같습니다.","level":45,"category":"빈도 학습"},{"id":15405,"term":"grievance","meaning":"불만; 고충","partOfSpeech":"n.","example":"Employees were encouraged to file a grievance if they felt treated unfairly.","exampleTranslation":"직원들은 부당하게 대우받았다고 느끼면 불만을 제기하도록 권장받았습니다.","level":45,"category":"빈도 학습"},{"id":15406,"term":"grieve","meaning":"슬퍼하다; 비통해하다","partOfSpeech":"v.","example":"The family took time to grieve after the sudden loss of their father.","exampleTranslation":"가족은 아버지의 갑작스러운 죽음 후 슬퍼하는 시간을 가졌습니다.","level":45,"category":"빈도 학습"},{"id":15407,"term":"grimace","meaning":"찡그리다; 인상 쓰다","partOfSpeech":"v.","example":"He could not help but grimace when the dentist touched the sore tooth.","exampleTranslation":"치과의사가 아픈 이를 건드렸을 때 그는 인상을 찡그릴 수밖에 없었습니다.","level":45,"category":"빈도 학습"},{"id":15408,"term":"groove","meaning":"홈; 리듬; 즐기다","partOfSpeech":"n.","example":"The record player needle fits perfectly into the groove of the vinyl.","exampleTranslation":"레코드 플레이어 바늘은 바이닐의 홈에 딱 맞게 들어갑니다.","level":45,"category":"빈도 학습"},{"id":15409,"term":"grudge","meaning":"원한; 악감정","partOfSpeech":"n.","example":"He still holds a grudge against his former boss after all these years.","exampleTranslation":"그는 수년이 지난 지금도 전 상사에 대한 원한을 품고 있습니다.","level":45,"category":"빈도 학습"},{"id":15410,"term":"grumble","meaning":"투덜거리다; 불평하다","partOfSpeech":"v.","example":"He started to grumble about the long wait at the coffee shop.","exampleTranslation":"그는 커피숍에서의 긴 대기에 대해 투덜거리기 시작했습니다.","level":45,"category":"빈도 학습"},{"id":15411,"term":"gulp","meaning":"꿀꺽 삼키다; 한 모금","partOfSpeech":"v.","example":"She took a quick gulp of water before starting her presentation.","exampleTranslation":"그녀는 발표를 시작하기 전에 물을 빠르게 한 모금 마셨습니다.","level":45,"category":"빈도 학습"},{"id":15412,"term":"gutter","meaning":"하수구; 홈통; 빈민가","partOfSpeech":"n.","example":"Leaves had piled up in the gutter and were blocking the water flow.","exampleTranslation":"낙엽이 하수구에 쌓여 물 흐름을 막고 있었습니다.","level":45,"category":"빈도 학습"},{"id":15413,"term":"gypsy","meaning":"집시; 방랑자","partOfSpeech":"n.","example":"The gypsy musician played a lively tune on the street corner.","exampleTranslation":"집시 음악가가 길모퉁이에서 활기찬 곡을 연주했습니다.","level":45,"category":"빈도 학습"},{"id":15414,"term":"halve","meaning":"반으로 줄이다; 이등분하다","partOfSpeech":"v.","example":"The new system helped the company halve its production costs.","exampleTranslation":"새 시스템은 회사가 생산 비용을 절반으로 줄이는 데 도움이 되었습니다.","level":45,"category":"빈도 학습"},{"id":15415,"term":"hamper","meaning":"방해하다; 저해하다; 바구니","partOfSpeech":"v.","example":"Bad weather continued to hamper rescue efforts in the flooded area.","exampleTranslation":"악천후가 침수 지역의 구조 활동을 계속 방해했습니다.","level":45,"category":"빈도 학습"},{"id":15416,"term":"handbook","meaning":"안내서; 편람; 지침서","partOfSpeech":"n.","example":"Please read the employee handbook before your first day at work.","exampleTranslation":"출근 첫날 전에 직원 안내서를 읽어 주세요.","level":45,"category":"빈도 학습"},{"id":15417,"term":"hare","meaning":"산토끼; 빠르게 달리다","partOfSpeech":"n.","example":"A hare darted across the field and disappeared into the bushes.","exampleTranslation":"산토끼 한 마리가 들판을 가로질러 달려가 덤불 속으로 사라졌습니다.","level":45,"category":"빈도 학습"},{"id":15418,"term":"hearty","meaning":"진심 어린; 푸짐한; 건강한","partOfSpeech":"adj.","example":"She gave him a hearty welcome when he returned from his long trip.","exampleTranslation":"그녀는 긴 여행을 마치고 돌아온 그를 진심 어린 환영으로 맞이했습니다.","level":45,"category":"빈도 학습"},{"id":15419,"term":"heath","meaning":"황야; 황무지","partOfSpeech":"n.","example":"They walked across the open heath as the fog slowly rolled in.","exampleTranslation":"안개가 천천히 밀려오는 가운데 그들은 탁 트인 황야를 가로질러 걸었습니다.","level":45,"category":"빈도 학습"},{"id":15420,"term":"hectare","meaning":"헥타르(면적 단위)","partOfSpeech":"n.","example":"The farm covers about fifty hectare of land in the countryside.","exampleTranslation":"그 농장은 시골에 약 50헥타르의 땅을 차지하고 있습니다.","level":45,"category":"빈도 학습"},{"id":15421,"term":"heed","meaning":"주의를 기울이다; 유의하다","partOfSpeech":"v.","example":"You should heed the doctor's advice and get plenty of rest.","exampleTranslation":"의사의 조언에 귀를 기울여 충분히 쉬어야 합니다.","level":45,"category":"빈도 학습"},{"id":15422,"term":"hegemony","meaning":"패권; 주도권","partOfSpeech":"n.","example":"The country's hegemony in the region was challenged by its neighbors.","exampleTranslation":"그 국가의 지역 내 패권은 주변국들의 도전을 받았습니다.","level":45,"category":"빈도 학습"},{"id":15423,"term":"hem","meaning":"옷단; 가장자리를 꿰매다","partOfSpeech":"n.","example":"The tailor sewed a neat hem along the bottom of the dress.","exampleTranslation":"재단사는 드레스 아랫부분을 따라 깔끔하게 옷단을 꿰맸습니다.","level":45,"category":"빈도 학습"},{"id":15424,"term":"hepatitis","meaning":"간염","partOfSpeech":"n.","example":"The doctor recommended a vaccine to protect against hepatitis B.","exampleTranslation":"의사는 B형 간염을 예방하기 위한 백신을 권고했습니다.","level":45,"category":"빈도 학습"},{"id":15425,"term":"heroine","meaning":"여주인공; 여성 영웅","partOfSpeech":"n.","example":"The heroine of the novel overcomes many hardships to achieve her dream.","exampleTranslation":"소설의 여주인공은 꿈을 이루기 위해 많은 어려움을 극복합니다.","level":45,"category":"빈도 학습"},{"id":15426,"term":"hesitant","meaning":"망설이는; 주저하는","partOfSpeech":"adj.","example":"She was hesitant to speak up during the meeting because she was new.","exampleTranslation":"그녀는 신입이라 회의 중에 발언하기를 주저했습니다.","level":45,"category":"빈도 학습"},{"id":15427,"term":"hijack","meaning":"납치하다; 강탈하다","partOfSpeech":"v.","example":"Armed men tried to hijack the cargo truck on the highway.","exampleTranslation":"무장한 남성들이 고속도로에서 화물 트럭을 납치하려 했습니다.","level":45,"category":"빈도 학습"},{"id":15428,"term":"hitch","meaning":"장애; 문제; 걸다","partOfSpeech":"n.","example":"The event went smoothly without a single hitch from start to finish.","exampleTranslation":"행사는 처음부터 끝까지 아무런 문제 없이 순조롭게 진행되었습니다.","level":45,"category":"빈도 학습"},{"id":15429,"term":"hoist","meaning":"들어 올리다; 끌어올리다","partOfSpeech":"v.","example":"Workers used a crane to hoist the heavy beam into position.","exampleTranslation":"작업자들은 크레인을 이용해 무거운 들보를 제자리에 들어 올렸습니다.","level":45,"category":"빈도 학습"},{"id":15430,"term":"holistic","meaning":"전체론적인; 전인적인","partOfSpeech":"adj.","example":"The clinic offers a holistic approach to treating both the body and mind.","exampleTranslation":"그 클리닉은 몸과 마음을 함께 치료하는 전체론적 접근법을 제공합니다.","level":45,"category":"빈도 학습"},{"id":15431,"term":"homicide","meaning":"살인; 살인 사건","partOfSpeech":"n.","example":"Detectives investigated the homicide that occurred near the downtown area.","exampleTranslation":"형사들은 도심 근처에서 발생한 살인 사건을 수사했습니다.","level":45,"category":"빈도 학습"},{"id":15432,"term":"homogeneous","meaning":"동질적인; 균일한","partOfSpeech":"adj.","example":"The mixture must be homogeneous before you pour it into the mold.","exampleTranslation":"혼합물을 틀에 붓기 전에 균일하게 섞여야 합니다.","level":45,"category":"빈도 학습"},{"id":15433,"term":"honeymoon","meaning":"신혼여행; 밀월 기간","partOfSpeech":"n.","example":"The couple spent their honeymoon on a tropical island in the Pacific.","exampleTranslation":"그 부부는 신혼여행을 태평양의 열대 섬에서 보냈습니다.","level":45,"category":"빈도 학습"},{"id":15434,"term":"horrific","meaning":"끔찍한; 소름 끼치는","partOfSpeech":"adj.","example":"Witnesses described the horrific scene after the building collapsed.","exampleTranslation":"목격자들은 건물이 붕괴된 후의 끔찍한 광경을 묘사했습니다.","level":45,"category":"빈도 학습"},{"id":15435,"term":"hose","meaning":"호스; 물을 호스로 뿌리다","partOfSpeech":"n.","example":"He used a garden hose to water the plants in the backyard.","exampleTranslation":"그는 뒷마당 식물에 물을 주기 위해 정원용 호스를 사용했습니다.","level":45,"category":"빈도 학습"},{"id":15436,"term":"hospitality","meaning":"환대; 친절한 접대","partOfSpeech":"n.","example":"The local family showed great hospitality by offering us a home-cooked meal.","exampleTranslation":"그 지역 가족은 집에서 요리한 음식을 대접하며 큰 환대를 보여 주었습니다.","level":45,"category":"빈도 학습"},{"id":15437,"term":"hound","meaning":"사냥개; 집요하게 쫓아다니다","partOfSpeech":"n.","example":"The hunter set out with his hound to track deer through the forest.","exampleTranslation":"사냥꾼은 사냥개를 데리고 숲 속에서 사슴을 추적하러 나섰습니다.","level":45,"category":"빈도 학습"},{"id":15438,"term":"hub","meaning":"중심지; 중추; 허브","partOfSpeech":"n.","example":"Singapore is a major hub for international trade and finance in Asia.","exampleTranslation":"싱가포르는 아시아에서 국제 무역과 금융의 주요 중심지입니다.","level":45,"category":"빈도 학습"},{"id":15439,"term":"huddle","meaning":"모여들다; 웅크리다; 옹기종기 모임","partOfSpeech":"v.","example":"The players huddle together before the game to discuss their strategy.","exampleTranslation":"선수들은 경기 전에 전략을 논의하기 위해 한데 모입니다.","level":45,"category":"빈도 학습"},{"id":15440,"term":"hue","meaning":"색조; 색깔","partOfSpeech":"n.","example":"The sunset painted the sky in a warm hue of orange and pink.","exampleTranslation":"석양이 하늘을 주황색과 분홍색의 따뜻한 색조로 물들였습니다.","level":45,"category":"빈도 학습"},{"id":15441,"term":"hull","meaning":"선체; 껍데기; 껍질을 벗기다","partOfSpeech":"n.","example":"Divers inspected the hull of the ship for any signs of damage.","exampleTranslation":"잠수부들이 손상 흔적이 있는지 배의 선체를 점검했습니다.","level":45,"category":"빈도 학습"},{"id":15442,"term":"humane","meaning":"인도적인; 자비로운","partOfSpeech":"adj.","example":"The organization campaigns for humane treatment of animals on farms.","exampleTranslation":"그 단체는 농장 동물의 인도적 처우를 위해 캠페인을 벌이고 있습니다.","level":45,"category":"빈도 학습"},{"id":15443,"term":"humanities","meaning":"인문학; 인문 과학","partOfSpeech":"n.","example":"He chose to study humanities because he was passionate about history and philosophy.","exampleTranslation":"그는 역사와 철학에 열정이 있어 인문학을 공부하기로 했습니다.","level":45,"category":"빈도 학습"},{"id":15444,"term":"hunch","meaning":"직감; 예감; 몸을 구부리다","partOfSpeech":"n.","example":"I had a hunch that the interview would go well, and it did.","exampleTranslation":"면접이 잘 될 것 같은 직감이 있었는데 실제로 그랬습니다.","level":45,"category":"빈도 학습"},{"id":15445,"term":"hush","meaning":"조용히 하다; 쉬잇; 침묵","partOfSpeech":"v.","example":"The librarian asked everyone to hush so others could concentrate.","exampleTranslation":"사서는 다른 사람들이 집중할 수 있도록 모두에게 조용히 해달라고 했습니다.","level":45,"category":"빈도 학습"},{"id":15446,"term":"hygiene","meaning":"위생; 청결","partOfSpeech":"n.","example":"Good personal hygiene is essential for preventing the spread of illness.","exampleTranslation":"개인 위생을 잘 지키는 것은 질병 확산을 예방하는 데 필수적입니다.","level":46,"category":"빈도 학습"},{"id":15447,"term":"hymn","meaning":"찬송가; 찬가","partOfSpeech":"n.","example":"The choir sang a traditional hymn at the beginning of the ceremony.","exampleTranslation":"합창단은 행사 시작 부분에 전통 찬송가를 불렀습니다.","level":46,"category":"빈도 학습"},{"id":15448,"term":"hype","meaning":"과대 광고; 부풀리다","partOfSpeech":"n.","example":"The movie did not live up to all the hype it received before release.","exampleTranslation":"그 영화는 개봉 전 받았던 모든 과대 광고에 부응하지 못했습니다.","level":46,"category":"빈도 학습"},{"id":15449,"term":"hypothetical","meaning":"가상의; 가설적인","partOfSpeech":"adj.","example":"The teacher posed a hypothetical situation to help students think critically.","exampleTranslation":"선생님은 학생들이 비판적으로 사고할 수 있도록 가상의 상황을 제시했습니다.","level":46,"category":"빈도 학습"},{"id":15450,"term":"hysterical","meaning":"히스테리적인; 극도로 웃긴","partOfSpeech":"adj.","example":"She found the comedian so hysterical that she could not stop laughing.","exampleTranslation":"그녀는 그 코미디언이 너무 극도로 웃겨서 웃음을 멈출 수 없었습니다.","level":46,"category":"빈도 학습"},{"id":15451,"term":"ibid","meaning":"같은 책에(앞서 인용한 것과 동일한 출처)","partOfSpeech":"adv.","example":"The footnote simply reads ibid to refer to the same source cited above.","exampleTranslation":"각주는 위에서 인용한 것과 동일한 출처를 나타내기 위해 해당 라틴어 약어가 쓰여 있었습니다.","level":46,"category":"빈도 학습"},{"id":15452,"term":"idol","meaning":"우상; 아이돌","partOfSpeech":"n.","example":"As a child, she dreamed of becoming a pop idol admired by millions.","exampleTranslation":"어린 시절 그녀는 수백만 명의 팬이 흠모하는 팝 아이돌이 되는 꿈을 꾸었습니다.","level":46,"category":"빈도 학습"},{"id":15453,"term":"ignorant","meaning":"무지한; 모르는","partOfSpeech":"adj.","example":"He was completely ignorant of the local customs when he first arrived.","exampleTranslation":"그는 처음 도착했을 때 현지 관습을 전혀 몰랐습니다.","level":46,"category":"빈도 학습"},{"id":15454,"term":"immoral","meaning":"비도덕적인; 부도덕한","partOfSpeech":"adj.","example":"Many people considered the executive's decision to be immoral and unfair.","exampleTranslation":"많은 사람들이 그 임원의 결정을 비도덕적이고 불공정하다고 여겼습니다.","level":46,"category":"빈도 학습"},{"id":15455,"term":"impeach","meaning":"탄핵하다; 문책하다","partOfSpeech":"v.","example":"The opposition party moved to impeach the president over the scandal.","exampleTranslation":"야당은 스캔들을 이유로 대통령을 탄핵하려는 움직임을 보였습니다.","level":46,"category":"빈도 학습"},{"id":15456,"term":"impede","meaning":"방해하다; 지연시키다","partOfSpeech":"v.","example":"Heavy traffic can impede the delivery of goods to customers on time.","exampleTranslation":"심한 교통체증은 고객에게 제때 상품을 배달하는 것을 방해할 수 있습니다.","level":46,"category":"빈도 학습"},{"id":15457,"term":"impending","meaning":"임박한; 곧 닥칠","partOfSpeech":"adj.","example":"Everyone could sense the impending storm as the dark clouds gathered.","exampleTranslation":"먹구름이 몰려오자 모두가 임박한 폭풍을 느낄 수 있었습니다.","level":46,"category":"빈도 학습"},{"id":15458,"term":"impetus","meaning":"추진력; 자극; 동기","partOfSpeech":"n.","example":"The new funding gave fresh impetus to the research team's work.","exampleTranslation":"새로운 자금 지원이 연구팀의 업무에 새로운 추진력을 불어넣었습니다.","level":46,"category":"빈도 학습"},{"id":15459,"term":"impoverish","meaning":"가난하게 만들다; 빈곤화하다","partOfSpeech":"v.","example":"Prolonged conflict can impoverish entire communities for generations.","exampleTranslation":"장기간의 분쟁은 지역 사회 전체를 여러 세대에 걸쳐 가난하게 만들 수 있습니다.","level":46,"category":"빈도 학습"},{"id":15460,"term":"imprint","meaning":"자국; 흔적; 새기다","partOfSpeech":"n.","example":"The artist pressed the stamp firmly to leave a clear imprint on the paper.","exampleTranslation":"예술가는 종이에 선명한 자국을 남기기 위해 도장을 꾹 눌렀습니다.","level":46,"category":"빈도 학습"},{"id":15461,"term":"inadvertent","meaning":"부주의한; 의도하지 않은","partOfSpeech":"adj.","example":"The inadvertent error in the report caused a brief delay in the project.","exampleTranslation":"보고서의 부주의한 오류로 인해 프로젝트가 잠시 지연되었습니다.","level":46,"category":"빈도 학습"},{"id":15462,"term":"inaugurate","meaning":"취임식을 열다; 개막하다","partOfSpeech":"v.","example":"They plan to inaugurate the new mayor in a ceremony at city hall.","exampleTranslation":"그들은 시청에서 열리는 행사에서 새 시장의 취임식을 열 계획입니다.","level":46,"category":"빈도 학습"},{"id":15463,"term":"incarnate","meaning":"육체를 가진; 화신; 화신하다","partOfSpeech":"adj.","example":"People described the villain as evil incarnate because of his cruel actions.","exampleTranslation":"사람들은 그 악당의 잔인한 행동 때문에 그를 악의 화신이라고 묘사했습니다.","level":46,"category":"빈도 학습"},{"id":15464,"term":"incinerate","meaning":"소각하다; 불태우다","partOfSpeech":"v.","example":"The facility was built to incinerate hazardous medical waste safely.","exampleTranslation":"그 시설은 위험한 의료 폐기물을 안전하게 소각하기 위해 건설되었습니다.","level":46,"category":"빈도 학습"},{"id":15465,"term":"incise","meaning":"절개하다; 새기다","partOfSpeech":"v.","example":"The surgeon needed to incise the skin carefully to reach the affected area.","exampleTranslation":"외과 의사는 환부에 도달하기 위해 피부를 조심스럽게 절개해야 했습니다.","level":46,"category":"빈도 학습"},{"id":15466,"term":"inclusive","meaning":"포용적인; 모두를 아우르는","partOfSpeech":"adj.","example":"The school aims to create an inclusive environment for all students.","exampleTranslation":"그 학교는 모든 학생을 위한 포용적인 환경을 만들고자 합니다.","level":46,"category":"빈도 학습"},{"id":15467,"term":"incomprehensible","meaning":"이해할 수 없는; 불가해한","partOfSpeech":"adj.","example":"The technical manual was incomprehensible to someone without a background in engineering.","exampleTranslation":"그 기술 매뉴얼은 공학 배경이 없는 사람에게는 이해할 수 없는 내용이었습니다.","level":46,"category":"빈도 학습"},{"id":15468,"term":"increment","meaning":"증가분; 단계적 증가","partOfSpeech":"n.","example":"Salaries will rise by a small increment each year based on performance.","exampleTranslation":"급여는 성과에 따라 매년 소폭의 증가분이 반영될 것입니다.","level":46,"category":"빈도 학습"},{"id":15469,"term":"incubate","meaning":"부화시키다; 배양하다","partOfSpeech":"v.","example":"The scientists used a warm chamber to incubate the bacterial samples.","exampleTranslation":"과학자들은 세균 샘플을 배양하기 위해 따뜻한 챔버를 사용했습니다.","level":46,"category":"빈도 학습"},{"id":15470,"term":"indignant","meaning":"분개한; 화가 난","partOfSpeech":"adj.","example":"She was indignant when she found out she had been left off the invitation list.","exampleTranslation":"그녀는 초대 명단에서 빠진 것을 알고 분개했습니다.","level":46,"category":"빈도 학습"},{"id":15471,"term":"indispensable","meaning":"없어서는 안 될; 필수적인","partOfSpeech":"adj.","example":"A good dictionary is indispensable for anyone learning a new language.","exampleTranslation":"좋은 사전은 새로운 언어를 배우는 누구에게나 없어서는 안 될 도구입니다.","level":46,"category":"빈도 학습"},{"id":15472,"term":"induct","meaning":"취임시키다; 입회시키다","partOfSpeech":"v.","example":"They will induct three new members into the hall of fame next month.","exampleTranslation":"그들은 다음 달 명예의 전당에 세 명의 새 회원을 입회시킬 예정입니다.","level":46,"category":"빈도 학습"},{"id":15473,"term":"infantry","meaning":"보병대; 보병","partOfSpeech":"n.","example":"The infantry advanced slowly through the dense forest during the exercise.","exampleTranslation":"보병대는 훈련 중 빽빽한 숲을 천천히 전진했습니다.","level":46,"category":"빈도 학습"},{"id":15474,"term":"infiltrate","meaning":"침투하다; 스며들다","partOfSpeech":"v.","example":"The undercover agent managed to infiltrate the criminal organization.","exampleTranslation":"잠입 요원은 범죄 조직에 침투하는 데 성공했습니다.","level":46,"category":"빈도 학습"},{"id":15475,"term":"influx","meaning":"유입; 밀려듦","partOfSpeech":"n.","example":"The city struggled to handle the sudden influx of tourists during the festival.","exampleTranslation":"그 도시는 축제 기간 동안 갑작스러운 관광객 유입을 감당하는 데 어려움을 겪었습니다.","level":46,"category":"빈도 학습"},{"id":15476,"term":"informative","meaning":"유익한; 정보가 풍부한","partOfSpeech":"adj.","example":"The tour guide gave a very informative talk about the history of the castle.","exampleTranslation":"관광 가이드는 성의 역사에 대해 매우 유익한 설명을 해주었습니다.","level":46,"category":"빈도 학습"},{"id":15477,"term":"infringe","meaning":"침해하다; 위반하다","partOfSpeech":"v.","example":"Using someone else's music without permission could infringe on their copyright.","exampleTranslation":"허락 없이 다른 사람의 음악을 사용하면 저작권을 침해할 수 있습니다.","level":46,"category":"빈도 학습"},{"id":15478,"term":"injunction","meaning":"금지 명령; 법원 명령","partOfSpeech":"n.","example":"The court issued an injunction to stop the company from releasing the product.","exampleTranslation":"법원은 그 회사가 제품을 출시하지 못하도록 금지 명령을 내렸습니다.","level":46,"category":"빈도 학습"},{"id":15479,"term":"inscribe","meaning":"새기다; 기입하다","partOfSpeech":"v.","example":"He asked the jeweler to inscribe their wedding date inside the ring.","exampleTranslation":"그는 보석상에게 반지 안쪽에 결혼 날짜를 새겨달라고 부탁했습니다.","level":46,"category":"빈도 학습"},{"id":15480,"term":"inscription","meaning":"비문; 새긴 글","partOfSpeech":"n.","example":"The inscription on the old coin was difficult to read after years of wear.","exampleTranslation":"오래된 동전의 비문은 세월이 흘러 닳아서 읽기 어려웠습니다.","level":46,"category":"빈도 학습"},{"id":15481,"term":"insulin","meaning":"인슐린","partOfSpeech":"n.","example":"People with type 1 diabetes need to inject insulin every day.","exampleTranslation":"제1형 당뇨병 환자는 매일 인슐린을 주사해야 합니다.","level":46,"category":"빈도 학습"},{"id":15482,"term":"insurgent","meaning":"반란군; 반란을 일으키는","partOfSpeech":"n.","example":"The government sent troops to contain the insurgent activity in the region.","exampleTranslation":"정부는 그 지역의 반란군 활동을 진압하기 위해 군대를 파견했습니다.","level":46,"category":"빈도 학습"},{"id":15483,"term":"intellect","meaning":"지성; 지적 능력","partOfSpeech":"n.","example":"She impressed everyone at the debate with her sharp intellect.","exampleTranslation":"그녀는 날카로운 지성으로 토론에서 모든 이들을 감동시켰습니다.","level":46,"category":"빈도 학습"},{"id":15484,"term":"interchange","meaning":"교환하다; 교차로","partOfSpeech":"v.","example":"The two teams decided to interchange roles halfway through the project.","exampleTranslation":"두 팀은 프로젝트 중간에 역할을 교환하기로 결정했습니다.","level":46,"category":"빈도 학습"},{"id":15485,"term":"intermittent","meaning":"간헐적인; 단속적인","partOfSpeech":"adj.","example":"There was intermittent rain throughout the afternoon, so we kept our umbrellas handy.","exampleTranslation":"오후 내내 간헐적인 비가 내려서 우산을 항상 가까이 두었습니다.","level":46,"category":"빈도 학습"},{"id":15486,"term":"intern","meaning":"인턴; 인턴으로 일하다","partOfSpeech":"n.","example":"The intern impressed everyone with her dedication and quick learning.","exampleTranslation":"그 인턴은 헌신적인 자세와 빠른 학습 능력으로 모두를 감동시켰습니다.","level":46,"category":"빈도 학습"},{"id":15487,"term":"intolerable","meaning":"참을 수 없는; 견딜 수 없는","partOfSpeech":"adj.","example":"The heat inside the car became intolerable after being parked in the sun.","exampleTranslation":"햇빛 아래 주차된 차 안의 열기는 참을 수 없을 지경이었습니다.","level":46,"category":"빈도 학습"},{"id":15488,"term":"intricate","meaning":"복잡한; 정교한","partOfSpeech":"adj.","example":"The artist spent weeks painting the intricate patterns on the ceiling.","exampleTranslation":"그 예술가는 천장에 복잡한 문양을 그리는 데 수 주를 보냈습니다.","level":46,"category":"빈도 학습"},{"id":15489,"term":"intrusion","meaning":"침입; 방해","partOfSpeech":"n.","example":"She apologized for the intrusion and quickly left the room.","exampleTranslation":"그녀는 방해가 된 것에 사과하며 빠르게 방을 나갔습니다.","level":46,"category":"빈도 학습"},{"id":15490,"term":"intuition","meaning":"직감; 직관","partOfSpeech":"n.","example":"Her intuition told her something was wrong before anyone else noticed.","exampleTranslation":"그녀의 직감은 다른 사람들이 알아채기 전에 무언가 잘못되었음을 알려주었습니다.","level":46,"category":"빈도 학습"},{"id":15491,"term":"intuitive","meaning":"직관적인; 이해하기 쉬운","partOfSpeech":"adj.","example":"The new app design is intuitive and easy for anyone to use right away.","exampleTranslation":"새로운 앱 디자인은 직관적이라 누구든 바로 사용하기 쉽습니다.","level":46,"category":"빈도 학습"},{"id":15492,"term":"invert","meaning":"뒤집다; 역전시키다","partOfSpeech":"v.","example":"If you invert the triangle, the pattern looks completely different.","exampleTranslation":"삼각형을 뒤집으면 패턴이 완전히 다르게 보입니다.","level":46,"category":"빈도 학습"},{"id":15493,"term":"involuntary","meaning":"무의식적인; 비자발적인","partOfSpeech":"adj.","example":"Blinking is an involuntary action that protects the surface of your eyes.","exampleTranslation":"눈을 깜빡이는 것은 눈 표면을 보호하는 무의식적인 동작입니다.","level":46,"category":"빈도 학습"},{"id":15494,"term":"irresistible","meaning":"저항할 수 없는; 매력적인","partOfSpeech":"adj.","example":"The smell of fresh bread from the bakery was irresistible.","exampleTranslation":"빵집에서 나는 갓 구운 빵 냄새는 저항할 수 없을 만큼 매혹적이었습니다.","level":46,"category":"빈도 학습"},{"id":15495,"term":"irrigate","meaning":"관개하다; 물을 대다","partOfSpeech":"v.","example":"Farmers use large pipes to irrigate their fields during dry seasons.","exampleTranslation":"농부들은 건기에 밭에 물을 대기 위해 큰 파이프를 사용합니다.","level":46,"category":"빈도 학습"},{"id":15496,"term":"irritable","meaning":"짜증을 잘 내는; 화를 잘 내는","partOfSpeech":"adj.","example":"He gets irritable when he hasn't had enough sleep the night before.","exampleTranslation":"그는 전날 밤 잠을 충분히 자지 못하면 짜증을 잘 냅니다.","level":46,"category":"빈도 학습"},{"id":15497,"term":"isle","meaning":"작은 섬","partOfSpeech":"n.","example":"They spent their honeymoon on a quiet isle off the coast of Greece.","exampleTranslation":"그들은 그리스 해안에서 떨어진 조용한 작은 섬에서 신혼여행을 보냈습니다.","level":46,"category":"빈도 학습"},{"id":15498,"term":"itch","meaning":"가려움; 가렵다","partOfSpeech":"n.","example":"She had an itch on her back that she could not reach to scratch.","exampleTranslation":"그녀는 등에 가려움이 있었는데 손이 닿지 않아 긁을 수가 없었습니다.","level":46,"category":"빈도 학습"},{"id":15499,"term":"jaguar","meaning":"재규어(동물)","partOfSpeech":"n.","example":"The jaguar moved silently through the jungle in search of prey.","exampleTranslation":"재규어는 먹이를 찾아 정글 속을 조용히 이동했습니다.","level":46,"category":"빈도 학습"},{"id":15500,"term":"jealousy","meaning":"질투; 시기심","partOfSpeech":"n.","example":"His jealousy got in the way of their friendship over time.","exampleTranslation":"그의 질투심이 시간이 지나면서 그들의 우정을 방해했습니다.","level":46,"category":"빈도 학습"},{"id":15501,"term":"jeep","meaning":"지프차","partOfSpeech":"n.","example":"They rented a jeep to explore the rough mountain trails.","exampleTranslation":"그들은 험한 산길을 탐험하기 위해 지프차를 빌렸습니다.","level":46,"category":"빈도 학습"},{"id":15502,"term":"jelly","meaning":"젤리; 잼","partOfSpeech":"n.","example":"She spread some jelly on her toast before eating breakfast.","exampleTranslation":"그녀는 아침 식사 전에 토스트에 젤리를 발랐습니다.","level":46,"category":"빈도 학습"},{"id":15503,"term":"jersey","meaning":"저지(운동복 상의); 유니폼","partOfSpeech":"n.","example":"He wore his favorite team's jersey to the soccer match.","exampleTranslation":"그는 축구 경기에 자신이 가장 좋아하는 팀의 저지를 입고 갔습니다.","level":46,"category":"빈도 학습"},{"id":15504,"term":"jolly","meaning":"즐거운; 명랑한","partOfSpeech":"adj.","example":"The jolly old man greeted every customer with a big smile.","exampleTranslation":"그 명랑한 노인은 모든 고객을 환한 미소로 맞이했습니다.","level":46,"category":"빈도 학습"},{"id":15505,"term":"jolt","meaning":"충격; 흔들림; 갑자기 흔들다","partOfSpeech":"n.","example":"The sudden jolt of the train woke everyone up from their naps.","exampleTranslation":"기차의 갑작스러운 흔들림이 낮잠을 자던 모든 사람을 깨웠습니다.","level":46,"category":"빈도 학습"},{"id":15506,"term":"jug","meaning":"주전자; 큰 컵","partOfSpeech":"n.","example":"She poured cold water from the jug into everyone's glasses.","exampleTranslation":"그녀는 주전자에서 차가운 물을 모두의 잔에 따랐습니다.","level":46,"category":"빈도 학습"},{"id":15507,"term":"juggle","meaning":"저글링하다; 동시에 처리하다","partOfSpeech":"v.","example":"It can be hard to juggle work responsibilities and family time every day.","exampleTranslation":"매일 업무와 가족 시간을 동시에 처리하는 것은 힘들 수 있습니다.","level":46,"category":"빈도 학습"},{"id":15508,"term":"juror","meaning":"배심원","partOfSpeech":"n.","example":"Each juror was asked to review the evidence carefully before making a decision.","exampleTranslation":"각 배심원은 결정을 내리기 전에 증거를 주의 깊게 검토하도록 요청받았습니다.","level":46,"category":"빈도 학습"},{"id":15509,"term":"justly","meaning":"공정하게; 정당하게","partOfSpeech":"adv.","example":"The judge was known for treating all people justly regardless of their background.","exampleTranslation":"그 판사는 배경에 관계없이 모든 사람을 공정하게 대하는 것으로 알려져 있었습니다.","level":46,"category":"빈도 학습"},{"id":15510,"term":"kettle","meaning":"주전자; 냄비","partOfSpeech":"n.","example":"She put the kettle on to boil water for a cup of tea.","exampleTranslation":"그녀는 차 한 잔을 위해 물을 끓이려고 주전자를 올려놓았습니다.","level":46,"category":"빈도 학습"},{"id":15511,"term":"kidding","meaning":"농담하는; 장난치는","partOfSpeech":"adj.","example":"Are you kidding me? I can't believe you forgot our plans today.","exampleTranslation":"농담하는 거야? 오늘 우리 약속을 잊어버렸다니 믿기지 않아.","level":46,"category":"빈도 학습"},{"id":15512,"term":"kite","meaning":"연; 연을 날리다","partOfSpeech":"n.","example":"The children spent the afternoon flying a kite in the park.","exampleTranslation":"아이들은 공원에서 연을 날리며 오후를 보냈습니다.","level":46,"category":"빈도 학습"},{"id":15513,"term":"knob","meaning":"손잡이; 돌기","partOfSpeech":"n.","example":"She turned the knob slowly and opened the door as quietly as she could.","exampleTranslation":"그녀는 손잡이를 천천히 돌려 최대한 조용히 문을 열었습니다.","level":46,"category":"빈도 학습"},{"id":15514,"term":"knuckle","meaning":"손가락 관절; 너클","partOfSpeech":"n.","example":"He tapped his knuckle on the table nervously while waiting for the result.","exampleTranslation":"그는 결과를 기다리는 동안 긴장하며 손가락 관절로 테이블을 두드렸습니다.","level":46,"category":"빈도 학습"},{"id":15515,"term":"lance","meaning":"창; 랜싯(의료용); 창으로 찌르다","partOfSpeech":"n.","example":"The knight lowered his lance and charged toward the opponent.","exampleTranslation":"기사는 창을 내리고 상대방을 향해 돌진했습니다.","level":46,"category":"빈도 학습"},{"id":15516,"term":"lantern","meaning":"랜턴; 등롱; 초롱","partOfSpeech":"n.","example":"She hung a lantern on the porch to light the path at night.","exampleTranslation":"그녀는 밤에 길을 밝히기 위해 현관에 랜턴을 걸었습니다.","level":46,"category":"빈도 학습"},{"id":15517,"term":"latch","meaning":"걸쇠; 잠금장치; 걸어 잠그다","partOfSpeech":"n.","example":"Make sure to lift the latch before you push the gate open.","exampleTranslation":"문을 열기 전에 반드시 걸쇠를 올려야 합니다.","level":46,"category":"빈도 학습"},{"id":15518,"term":"latent","meaning":"잠재적인; 숨어 있는","partOfSpeech":"adj.","example":"The doctor explained that the virus can remain latent for years.","exampleTranslation":"의사는 바이러스가 수년간 잠복 상태로 남아 있을 수 있다고 설명했습니다.","level":46,"category":"빈도 학습"},{"id":15519,"term":"latitude","meaning":"위도; 자유 재량","partOfSpeech":"n.","example":"The city sits at a latitude that gives it mild winters and warm summers.","exampleTranslation":"그 도시는 온화한 겨울과 따뜻한 여름을 가진 위도에 자리하고 있습니다.","level":46,"category":"빈도 학습"},{"id":15520,"term":"lava","meaning":"용암","partOfSpeech":"n.","example":"The lava flowed slowly down the side of the volcano toward the village.","exampleTranslation":"용암이 화산 측면을 따라 마을 쪽으로 천천히 흘러내렸습니다.","level":46,"category":"빈도 학습"},{"id":15521,"term":"lavender","meaning":"라벤더; 연보라색","partOfSpeech":"n.","example":"She planted lavender along the garden path for its calming scent.","exampleTranslation":"그녀는 진정시키는 향기를 위해 정원 오솔길을 따라 라벤더를 심었습니다.","level":46,"category":"빈도 학습"},{"id":15522,"term":"ledge","meaning":"선반처럼 튀어나온 바위; 창턱","partOfSpeech":"n.","example":"The climber rested on a narrow ledge halfway up the cliff face.","exampleTranslation":"등반가는 절벽 중간쯤의 좁은 바위 턱에서 쉬었습니다.","level":46,"category":"빈도 학습"},{"id":15523,"term":"lettuce","meaning":"상추; 양상추","partOfSpeech":"n.","example":"She added fresh lettuce to the sandwich to make it crunchier.","exampleTranslation":"그녀는 샌드위치를 더 바삭하게 만들기 위해 신선한 상추를 추가했습니다.","level":46,"category":"빈도 학습"},{"id":15524,"term":"levy","meaning":"세금 부과; 징수하다","partOfSpeech":"n.","example":"The government decided to impose a levy on imported luxury goods.","exampleTranslation":"정부는 수입 명품에 세금을 부과하기로 결정했습니다.","level":46,"category":"빈도 학습"},{"id":15525,"term":"lily","meaning":"백합","partOfSpeech":"n.","example":"She received a bouquet of white lily flowers on her birthday.","exampleTranslation":"그녀는 생일에 흰 백합 꽃다발을 받았습니다.","level":46,"category":"빈도 학습"},{"id":15526,"term":"limousine","meaning":"리무진","partOfSpeech":"n.","example":"The celebrity arrived at the premiere in a long black limousine.","exampleTranslation":"그 유명인은 긴 검정 리무진을 타고 시사회에 도착했습니다.","level":46,"category":"빈도 학습"},{"id":15527,"term":"lineage","meaning":"혈통; 가계","partOfSpeech":"n.","example":"He was proud of his royal lineage that stretched back centuries.","exampleTranslation":"그는 수 세기 전으로 거슬러 올라가는 왕족 혈통을 자랑스러워했습니다.","level":46,"category":"빈도 학습"},{"id":15528,"term":"liner","meaning":"정기 여객선; 안감","partOfSpeech":"n.","example":"The luxury liner sailed across the Atlantic in just five days.","exampleTranslation":"그 호화 여객선은 대서양을 단 5일 만에 횡단했습니다.","level":46,"category":"빈도 학습"},{"id":15529,"term":"liquidate","meaning":"청산하다; 처분하다","partOfSpeech":"v.","example":"The company had to liquidate its assets to pay off the remaining debts.","exampleTranslation":"회사는 남은 부채를 갚기 위해 자산을 청산해야 했습니다.","level":46,"category":"빈도 학습"},{"id":15530,"term":"liter","meaning":"리터(용량 단위)","partOfSpeech":"n.","example":"Please buy a liter of milk from the store on your way home.","exampleTranslation":"집에 오는 길에 가게에서 우유 한 리터를 사오세요.","level":46,"category":"빈도 학습"},{"id":15531,"term":"liturgy","meaning":"전례; 예배 의식","partOfSpeech":"n.","example":"The priest led the congregation through the traditional liturgy of the service.","exampleTranslation":"신부님은 신도들을 이끌며 전통 예배 의식을 진행했습니다.","level":46,"category":"빈도 학습"},{"id":15532,"term":"lizard","meaning":"도마뱀","partOfSpeech":"n.","example":"A small lizard darted across the warm rock and disappeared into the grass.","exampleTranslation":"작은 도마뱀 한 마리가 따뜻한 바위를 가로질러 달려가 풀숲으로 사라졌습니다.","level":46,"category":"빈도 학습"},{"id":15533,"term":"lo","meaning":"보라!; 이봐(주의를 끌 때 쓰는 감탄사)","partOfSpeech":"interj.","example":"Lo and behold, she walked in just as we were talking about her.","exampleTranslation":"이런, 우리가 그녀 얘기를 하던 참에 그녀가 들어왔습니다.","level":46,"category":"빈도 학습"},{"id":15534,"term":"loaf","meaning":"덩어리(빵 등); 빈둥거리다","partOfSpeech":"n.","example":"She bought a fresh loaf of bread from the bakery this morning.","exampleTranslation":"그녀는 오늘 아침 빵집에서 신선한 빵 한 덩이를 샀습니다.","level":46,"category":"빈도 학습"},{"id":15535,"term":"loathe","meaning":"몹시 싫어하다; 혐오하다","partOfSpeech":"v.","example":"He said he would loathe having to commute two hours every day.","exampleTranslation":"그는 매일 두 시간씩 통근해야 한다면 정말 싫을 것이라고 말했습니다.","level":46,"category":"빈도 학습"},{"id":15536,"term":"lobster","meaning":"바닷가재; 랍스터","partOfSpeech":"n.","example":"We ordered a grilled lobster as the main dish at the seafood restaurant.","exampleTranslation":"우리는 해산물 식당에서 메인 요리로 구운 바닷가재를 주문했습니다.","level":46,"category":"빈도 학습"},{"id":15537,"term":"locality","meaning":"지역; 장소; 인근","partOfSpeech":"n.","example":"The new park has improved the quality of life in the surrounding locality.","exampleTranslation":"새 공원이 주변 지역의 삶의 질을 향상시켰습니다.","level":46,"category":"빈도 학습"},{"id":15538,"term":"locker","meaning":"사물함; 잠금 보관함","partOfSpeech":"n.","example":"He forgot the combination to his locker and had to ask the school office.","exampleTranslation":"그는 사물함 비밀번호를 잊어버려 학교 사무실에 도움을 요청해야 했습니다.","level":46,"category":"빈도 학습"},{"id":15539,"term":"locomotive","meaning":"기관차; 증기기관차","partOfSpeech":"n.","example":"The old steam locomotive is now on display at the national railway museum.","exampleTranslation":"오래된 증기 기관차가 이제 국립 철도 박물관에 전시되어 있습니다.","level":46,"category":"빈도 학습"},{"id":15540,"term":"locus","meaning":"중심지; (수학) 자취; 위치","partOfSpeech":"n.","example":"The capital city became the locus of political power in the region.","exampleTranslation":"수도는 그 지역의 정치 권력 중심지가 되었습니다.","level":46,"category":"빈도 학습"},{"id":15541,"term":"loft","meaning":"다락방; 다락식 공간","partOfSpeech":"n.","example":"They converted the old barn loft into a cozy studio apartment.","exampleTranslation":"그들은 낡은 헛간 다락방을 아늑한 원룸 아파트로 개조했습니다.","level":46,"category":"빈도 학습"},{"id":15542,"term":"lottery","meaning":"복권; 추첨","partOfSpeech":"n.","example":"He bought a lottery ticket every week but never won a prize.","exampleTranslation":"그는 매주 복권을 샀지만 한 번도 당첨된 적이 없었습니다.","level":46,"category":"빈도 학습"},{"id":15543,"term":"lotus","meaning":"연꽃","partOfSpeech":"n.","example":"A beautiful lotus floated on the surface of the still pond.","exampleTranslation":"아름다운 연꽃이 잔잔한 연못 위에 떠 있었습니다.","level":46,"category":"빈도 학습"},{"id":15544,"term":"lucrative","meaning":"수익성이 높은; 돈이 되는","partOfSpeech":"adj.","example":"Starting an online business turned out to be a very lucrative venture.","exampleTranslation":"온라인 사업을 시작하는 것이 매우 수익성 있는 일로 밝혀졌습니다.","level":46,"category":"빈도 학습"},{"id":15545,"term":"lumber","meaning":"목재; 재목; 느릿느릿 움직이다","partOfSpeech":"n.","example":"The builders ordered several truckloads of lumber for the new house.","exampleTranslation":"건축업자들은 새 집을 위해 몇 트럭 분량의 목재를 주문했습니다.","level":46,"category":"빈도 학습"},{"id":15546,"term":"luminous","meaning":"빛을 발하는; 밝게 빛나는","partOfSpeech":"adj.","example":"The luminous stars filled the sky on that clear winter night.","exampleTranslation":"맑은 겨울밤 하늘은 빛나는 별들로 가득 찼습니다.","level":46,"category":"빈도 학습"},{"id":15547,"term":"lurch","meaning":"갑자기 기울다; 비틀거리다","partOfSpeech":"v.","example":"The bus hit a pothole and began to lurch to one side.","exampleTranslation":"버스가 웅덩이를 지나면서 한쪽으로 갑자기 기울기 시작했습니다.","level":46,"category":"빈도 학습"},{"id":15548,"term":"lush","meaning":"무성한; 풍성한; 풍요로운","partOfSpeech":"adj.","example":"The hiking trail wound through lush green forest for several miles.","exampleTranslation":"등산로는 무성한 녹색 숲을 수 마일에 걸쳐 구불구불 이어졌습니다.","level":46,"category":"빈도 학습"},{"id":15549,"term":"magnify","meaning":"확대하다; 과장하다","partOfSpeech":"v.","example":"The lens is designed to magnify objects up to ten times their actual size.","exampleTranslation":"그 렌즈는 물체를 실제 크기의 최대 10배까지 확대하도록 설계되었습니다.","level":46,"category":"빈도 학습"},{"id":15550,"term":"mahogany","meaning":"마호가니(열대산 목재); 적갈색","partOfSpeech":"n.","example":"The antique desk was crafted from solid mahogany and still looked beautiful.","exampleTranslation":"그 골동품 책상은 단단한 마호가니로 제작되어 여전히 아름다워 보였습니다.","level":46,"category":"빈도 학습"},{"id":15551,"term":"maiden","meaning":"처녀; 첫 번째의","partOfSpeech":"n.","example":"The ship set off on its maiden voyage across the Pacific Ocean.","exampleTranslation":"그 배는 태평양을 건너는 첫 항해를 시작했습니다.","level":46,"category":"빈도 학습"},{"id":15552,"term":"makeup","meaning":"화장품; 화장; 구성","partOfSpeech":"n.","example":"She applied a small amount of makeup before heading out for the interview.","exampleTranslation":"그녀는 면접을 보러 나가기 전에 약간의 화장을 했습니다.","level":47,"category":"빈도 학습"},{"id":15553,"term":"malign","meaning":"중상하다; 악의적인","partOfSpeech":"v.","example":"It is unfair to malign someone based on rumors you have heard.","exampleTranslation":"들은 소문을 근거로 누군가를 중상하는 것은 불공평합니다.","level":47,"category":"빈도 학습"},{"id":15554,"term":"mantle","meaning":"망토; 덮개; (책임의) 짐","partOfSpeech":"n.","example":"She accepted the mantle of leadership when the director stepped down.","exampleTranslation":"이사가 물러나자 그녀가 리더십의 책임을 받아들였습니다.","level":47,"category":"빈도 학습"},{"id":15555,"term":"maple","meaning":"단풍나무; 단풍나무 목재","partOfSpeech":"n.","example":"The street was lined with maple trees that turned brilliant red in autumn.","exampleTranslation":"거리는 가을에 선명한 붉은색으로 변하는 단풍나무들로 줄지어 있었습니다.","level":47,"category":"빈도 학습"},{"id":15556,"term":"mar","meaning":"손상시키다; 흠집 내다","partOfSpeech":"v.","example":"A single spelling error can mar an otherwise perfect cover letter.","exampleTranslation":"철자 오류 하나가 완벽한 자기소개서를 망칠 수 있습니다.","level":47,"category":"빈도 학습"},{"id":15557,"term":"mare","meaning":"암말","partOfSpeech":"n.","example":"The mare gently nuzzled her newborn foal in the stable.","exampleTranslation":"암말이 마구간에서 갓 태어난 새끼를 부드럽게 코로 비볐습니다.","level":47,"category":"빈도 학습"},{"id":15558,"term":"maritime","meaning":"해양의; 항해의","partOfSpeech":"adj.","example":"The city has a rich maritime history connected to centuries of seafaring trade.","exampleTranslation":"그 도시는 수 세기에 걸친 해상 무역과 연결된 풍부한 해양 역사를 가지고 있습니다.","level":47,"category":"빈도 학습"},{"id":15559,"term":"martial","meaning":"군사의; 전쟁의; 무술의","partOfSpeech":"adj.","example":"He trained in martial arts for ten years before opening his own studio.","exampleTranslation":"그는 자신의 스튜디오를 열기 전 10년 동안 무술을 훈련했습니다.","level":47,"category":"빈도 학습"},{"id":15560,"term":"mash","meaning":"으깨다; 으깬 음식","partOfSpeech":"v.","example":"She used a fork to mash the potatoes until they were soft and smooth.","exampleTranslation":"그녀는 포크를 사용해 감자를 부드럽고 매끄럽게 될 때까지 으깼습니다.","level":47,"category":"빈도 학습"},{"id":15561,"term":"masterpiece","meaning":"걸작; 명작","partOfSpeech":"n.","example":"Critics agreed that the film was a masterpiece of modern storytelling.","exampleTranslation":"비평가들은 그 영화가 현대 스토리텔링의 걸작이라는 데 동의했습니다.","level":47,"category":"빈도 학습"},{"id":15562,"term":"materialize","meaning":"실현되다; 구체화되다; 나타나다","partOfSpeech":"v.","example":"The business deal they had hoped for failed to materialize in the end.","exampleTranslation":"그들이 바랐던 사업 거래는 결국 실현되지 못했습니다.","level":47,"category":"빈도 학습"},{"id":15563,"term":"maze","meaning":"미로; 복잡한 상황","partOfSpeech":"n.","example":"The children got lost in the corn maze and had to call for help.","exampleTranslation":"아이들은 옥수수 미로에서 길을 잃어 도움을 요청해야 했습니다.","level":47,"category":"빈도 학습"},{"id":15564,"term":"mega","meaning":"초대형의; 엄청난","partOfSpeech":"adj.","example":"The new stadium is a mega project that will take five years to complete.","exampleTranslation":"새 경기장은 완공까지 5년이 걸릴 초대형 프로젝트입니다.","level":47,"category":"빈도 학습"},{"id":15565,"term":"melancholy","meaning":"우울함; 우울한","partOfSpeech":"n.","example":"A deep sense of melancholy came over her as she read the old letters.","exampleTranslation":"오래된 편지를 읽으면서 깊은 우울감이 그녀를 감쌌습니다.","level":47,"category":"빈도 학습"},{"id":15566,"term":"memorandum","meaning":"메모; 각서; 업무 연락문","partOfSpeech":"n.","example":"The manager sent a memorandum to all staff about the new policy.","exampleTranslation":"관리자는 새 정책에 대해 전 직원에게 메모를 보냈습니다.","level":47,"category":"빈도 학습"},{"id":15567,"term":"mend","meaning":"수선하다; 고치다; 나아지다","partOfSpeech":"v.","example":"She asked the tailor to mend the torn seam on her jacket.","exampleTranslation":"그녀는 재단사에게 재킷의 찢어진 솔기를 수선해 달라고 부탁했습니다.","level":47,"category":"빈도 학습"},{"id":15568,"term":"mentor","meaning":"멘토; 스승; 조언자","partOfSpeech":"n.","example":"She found a mentor who helped her navigate the early years of her career.","exampleTranslation":"그녀는 경력 초기를 헤쳐 나가도록 도와줄 멘토를 찾았습니다.","level":47,"category":"빈도 학습"},{"id":15569,"term":"merchandise","meaning":"상품; 판매 상품","partOfSpeech":"n.","example":"The store is clearing out old merchandise to make room for new stock.","exampleTranslation":"가게는 새 재고를 들일 공간을 만들기 위해 오래된 상품을 정리하고 있습니다.","level":47,"category":"빈도 학습"},{"id":15570,"term":"mercury","meaning":"수은; 수성","partOfSpeech":"n.","example":"Old thermometers used mercury to measure temperature.","exampleTranslation":"구형 온도계는 온도를 측정하는 데 수은을 사용했습니다.","level":47,"category":"빈도 학습"},{"id":15571,"term":"mesh","meaning":"그물망; 맞물리다; 조화를 이루다","partOfSpeech":"n.","example":"The window was covered with a fine mesh to keep insects out.","exampleTranslation":"창문에는 벌레가 들어오지 못하도록 촘촘한 그물망이 쳐져 있었습니다.","level":47,"category":"빈도 학습"},{"id":15572,"term":"metabolism","meaning":"신진대사; 물질대사","partOfSpeech":"n.","example":"Regular exercise can help boost your metabolism over time.","exampleTranslation":"규칙적인 운동은 시간이 지남에 따라 신진대사를 높이는 데 도움이 됩니다.","level":47,"category":"빈도 학습"},{"id":15573,"term":"metaphysic","meaning":"형이상학; 초물리적 원리","partOfSpeech":"n.","example":"His lecture on metaphysic explored the nature of reality and existence.","exampleTranslation":"그의 형이상학 강의는 현실과 존재의 본질을 탐구했습니다.","level":47,"category":"빈도 학습"},{"id":15574,"term":"meteor","meaning":"유성; 별똥별","partOfSpeech":"n.","example":"We stayed up late to watch a meteor shower from the hillside.","exampleTranslation":"우리는 언덕에서 유성우를 보기 위해 늦게까지 깨어 있었습니다.","level":47,"category":"빈도 학습"},{"id":15575,"term":"meticulous","meaning":"꼼꼼한; 세심한; 빈틈없는","partOfSpeech":"adj.","example":"She was meticulous about checking every detail before submitting the report.","exampleTranslation":"그녀는 보고서를 제출하기 전에 모든 세부 사항을 꼼꼼하게 확인했습니다.","level":47,"category":"빈도 학습"},{"id":15576,"term":"micro","meaning":"극소의; 매우 작은","partOfSpeech":"adj.","example":"The research focused on micro organisms found in deep ocean water.","exampleTranslation":"그 연구는 깊은 바닷속에서 발견된 극소 생물에 초점을 맞췄습니다.","level":47,"category":"빈도 학습"},{"id":15577,"term":"millionaire","meaning":"백만장자; 억만장자","partOfSpeech":"n.","example":"He became a millionaire after selling his tech startup.","exampleTranslation":"그는 자신의 기술 스타트업을 매각한 후 백만장자가 되었습니다.","level":47,"category":"빈도 학습"},{"id":15578,"term":"mince","meaning":"다지다; 잘게 썰다","partOfSpeech":"v.","example":"Please mince the garlic finely before adding it to the pan.","exampleTranslation":"팬에 넣기 전에 마늘을 곱게 다져 주세요.","level":47,"category":"빈도 학습"},{"id":15579,"term":"mingle","meaning":"어울리다; 섞이다","partOfSpeech":"v.","example":"Guests were encouraged to mingle and introduce themselves at the reception.","exampleTranslation":"손님들은 리셉션에서 서로 어울리며 자기소개를 하도록 권장받았습니다.","level":47,"category":"빈도 학습"},{"id":15580,"term":"mini","meaning":"소형의; 아주 작은","partOfSpeech":"adj.","example":"She ordered a mini version of the dessert to save room for dinner.","exampleTranslation":"그녀는 저녁 식사를 위해 배를 남겨 두려고 소형 디저트를 주문했습니다.","level":47,"category":"빈도 학습"},{"id":15581,"term":"miraculous","meaning":"기적적인; 놀라운","partOfSpeech":"adj.","example":"The patient made a miraculous recovery after the surgery.","exampleTranslation":"그 환자는 수술 후 기적적으로 회복했습니다.","level":47,"category":"빈도 학습"},{"id":15582,"term":"mischief","meaning":"장난; 못된 짓; 해악","partOfSpeech":"n.","example":"The children were full of mischief during the long school holiday.","exampleTranslation":"아이들은 긴 학교 방학 동안 온갖 장난으로 가득했습니다.","level":47,"category":"빈도 학습"},{"id":15583,"term":"mole","meaning":"두더지; 점(피부); 몰(화학 단위)","partOfSpeech":"n.","example":"A mole had dug several tunnels under the garden overnight.","exampleTranslation":"두더지 한 마리가 밤새 정원 아래에 여러 개의 굴을 팠습니다.","level":47,"category":"빈도 학습"},{"id":15584,"term":"mop","meaning":"대걸레; 대걸레로 닦다","partOfSpeech":"n.","example":"He used a mop to clean up the water spilled on the kitchen floor.","exampleTranslation":"그는 부엌 바닥에 쏟아진 물을 대걸레로 닦아냈습니다.","level":47,"category":"빈도 학습"},{"id":15585,"term":"morbid","meaning":"병적인; 불건전한; 음울한","partOfSpeech":"adj.","example":"He had a morbid fascination with crime documentaries late at night.","exampleTranslation":"그는 늦은 밤 범죄 다큐멘터리에 병적인 매력을 느꼈습니다.","level":47,"category":"빈도 학습"},{"id":15586,"term":"mosque","meaning":"이슬람 사원; 모스크","partOfSpeech":"n.","example":"Visitors removed their shoes before entering the mosque.","exampleTranslation":"방문객들은 모스크에 들어가기 전에 신발을 벗었습니다.","level":47,"category":"빈도 학습"},{"id":15587,"term":"moss","meaning":"이끼; 이끼가 끼다","partOfSpeech":"n.","example":"Thick moss covered the old stone walls along the forest path.","exampleTranslation":"숲길을 따라 오래된 돌담에 두꺼운 이끼가 덮여 있었습니다.","level":47,"category":"빈도 학습"},{"id":15588,"term":"moth","meaning":"나방","partOfSpeech":"n.","example":"A moth flew around the lamp all evening and kept distracting us.","exampleTranslation":"나방 한 마리가 저녁 내내 전등 주위를 날아다니며 우리의 신경을 건드렸습니다.","level":47,"category":"빈도 학습"},{"id":15589,"term":"muffle","meaning":"소리를 죽이다; 감싸다","partOfSpeech":"v.","example":"She used a pillow to muffle the sound of her alarm in the morning.","exampleTranslation":"그녀는 아침에 베개로 알람 소리를 죽였습니다.","level":47,"category":"빈도 학습"},{"id":15590,"term":"mule","meaning":"노새; 고집쟁이","partOfSpeech":"n.","example":"The farmer used a mule to carry heavy loads up the steep hill.","exampleTranslation":"농부는 가파른 언덕 위로 무거운 짐을 나르기 위해 노새를 사용했습니다.","level":47,"category":"빈도 학습"},{"id":15591,"term":"multicultural","meaning":"다문화의; 다양한 문화가 공존하는","partOfSpeech":"adj.","example":"Toronto is known as one of the most multicultural cities in the world.","exampleTranslation":"토론토는 세계에서 가장 다문화적인 도시 중 하나로 알려져 있습니다.","level":47,"category":"빈도 학습"},{"id":15592,"term":"multitude","meaning":"다수; 군중; 무리","partOfSpeech":"n.","example":"A multitude of fans gathered outside the stadium before the game.","exampleTranslation":"경기 전에 수많은 팬들이 경기장 밖에 모였습니다.","level":47,"category":"빈도 학습"},{"id":15593,"term":"mumble","meaning":"중얼거리다; 웅얼거리다","partOfSpeech":"v.","example":"He began to mumble something under his breath and no one could hear him.","exampleTranslation":"그는 작게 중얼거리기 시작했고 아무도 그의 말을 들을 수 없었습니다.","level":47,"category":"빈도 학습"},{"id":15594,"term":"mundane","meaning":"평범한; 일상적인; 세속적인","partOfSpeech":"adj.","example":"Even mundane tasks like doing laundry can feel satisfying when done well.","exampleTranslation":"빨래 같은 평범한 일도 잘 하면 뿌듯함을 느낄 수 있습니다.","level":47,"category":"빈도 학습"},{"id":15595,"term":"muscular","meaning":"근육질의; 건장한","partOfSpeech":"adj.","example":"Years of swimming gave him a lean and muscular body.","exampleTranslation":"수년간의 수영으로 그는 날씬하고 근육질의 몸을 갖게 되었습니다.","level":47,"category":"빈도 학습"},{"id":15596,"term":"mustard","meaning":"겨자; 머스터드","partOfSpeech":"n.","example":"He put a little mustard on his sandwich to add some flavor.","exampleTranslation":"그는 맛을 더하기 위해 샌드위치에 약간의 머스터드를 발랐습니다.","level":47,"category":"빈도 학습"},{"id":15597,"term":"muster","meaning":"모으다; 불러모으다; (용기를) 내다","partOfSpeech":"v.","example":"She tried to muster enough courage to speak in front of the crowd.","exampleTranslation":"그녀는 군중 앞에서 말할 용기를 내려고 애썼습니다.","level":47,"category":"빈도 학습"},{"id":15598,"term":"myriad","meaning":"무수히 많은; 다양한","partOfSpeech":"adj.","example":"The app offers a myriad of features that most users never even discover.","exampleTranslation":"그 앱은 대부분의 사용자가 발견하지 못하는 무수히 많은 기능을 제공합니다.","level":47,"category":"빈도 학습"},{"id":15599,"term":"mythology","meaning":"신화; 신화학","partOfSpeech":"n.","example":"She loves reading about Greek mythology and the stories of the gods.","exampleTranslation":"그녀는 그리스 신화와 신들의 이야기 읽기를 좋아합니다.","level":47,"category":"빈도 학습"},{"id":15600,"term":"nag","meaning":"잔소리하다; 계속 괴롭히다","partOfSpeech":"v.","example":"She would nag him every morning about leaving his dishes in the sink.","exampleTranslation":"그녀는 매일 아침 그가 싱크대에 그릇을 놔두는 것에 대해 잔소리를 했습니다.","level":47,"category":"빈도 학습"},{"id":15601,"term":"nap","meaning":"낮잠; 잠깐 자다","partOfSpeech":"n.","example":"I took a short nap after lunch and felt much more refreshed.","exampleTranslation":"점심 식사 후 짧은 낮잠을 자고 나서 훨씬 더 개운했습니다.","level":47,"category":"빈도 학습"},{"id":15602,"term":"nausea","meaning":"메스꺼움; 구역질","partOfSpeech":"n.","example":"She felt a wave of nausea on the boat due to the rough water.","exampleTranslation":"그녀는 거친 파도 때문에 배 위에서 메스꺼움을 느꼈습니다.","level":47,"category":"빈도 학습"},{"id":15603,"term":"necessitate","meaning":"필요로 하다; 불가피하게 만들다","partOfSpeech":"v.","example":"The new regulations will necessitate changes to our current workflow.","exampleTranslation":"새로운 규정은 우리의 현재 업무 흐름에 변화를 필요로 할 것입니다.","level":47,"category":"빈도 학습"},{"id":15604,"term":"necklace","meaning":"목걸이","partOfSpeech":"n.","example":"She wore a gold necklace that her grandmother had passed down to her.","exampleTranslation":"그녀는 할머니에게 물려받은 금 목걸이를 착용했습니다.","level":47,"category":"빈도 학습"},{"id":15605,"term":"neuron","meaning":"신경세포; 뉴런","partOfSpeech":"n.","example":"Each neuron in the brain can connect to thousands of other neurons.","exampleTranslation":"뇌의 각 뉴런은 수천 개의 다른 뉴런과 연결될 수 있습니다.","level":47,"category":"빈도 학습"},{"id":15606,"term":"niece","meaning":"조카딸","partOfSpeech":"n.","example":"My niece just started her first year of kindergarten this month.","exampleTranslation":"내 조카딸이 이번 달에 유치원 첫 해를 시작했습니다.","level":47,"category":"빈도 학습"},{"id":15607,"term":"nightclub","meaning":"나이트클럽","partOfSpeech":"n.","example":"They went to a nightclub downtown to celebrate the end of exams.","exampleTranslation":"그들은 시험 종료를 축하하기 위해 시내 나이트클럽에 갔습니다.","level":47,"category":"빈도 학습"},{"id":15608,"term":"nitrate","meaning":"질산염; 질산","partOfSpeech":"n.","example":"High levels of nitrate in the water supply can be harmful to health.","exampleTranslation":"수돗물 속의 높은 수준의 질산염은 건강에 해로울 수 있습니다.","level":47,"category":"빈도 학습"},{"id":15609,"term":"nostalgia","meaning":"향수; 그리움","partOfSpeech":"n.","example":"Looking at old photos filled her with nostalgia for her childhood.","exampleTranslation":"오래된 사진을 보니 어린 시절에 대한 향수가 밀려왔습니다.","level":47,"category":"빈도 학습"},{"id":15610,"term":"nostril","meaning":"콧구멍","partOfSpeech":"n.","example":"He could smell the aroma of fresh bread from one nostril to the other.","exampleTranslation":"그는 콧구멍 가득히 갓 구운 빵의 향기를 맡을 수 있었습니다.","level":47,"category":"빈도 학습"},{"id":15611,"term":"notate","meaning":"기보하다; 기호로 표기하다","partOfSpeech":"v.","example":"The composer asked his student to notate the melody in the correct key.","exampleTranslation":"작곡가는 학생에게 올바른 조성으로 선율을 기보해 달라고 부탁했습니다.","level":47,"category":"빈도 학습"},{"id":15612,"term":"notch","meaning":"홈; 눈금; 한 단계","partOfSpeech":"n.","example":"He carved a notch into the wooden stick to mark each day.","exampleTranslation":"그는 매일을 표시하기 위해 나무 막대에 홈을 새겼습니다.","level":47,"category":"빈도 학습"},{"id":15613,"term":"notwithstanding","meaning":"~에도 불구하고; 그럼에도 불구하고","partOfSpeech":"prep.","example":"Notwithstanding the bad weather, the outdoor event went ahead as planned.","exampleTranslation":"악천후에도 불구하고 야외 행사는 계획대로 진행되었습니다.","level":47,"category":"빈도 학습"},{"id":15614,"term":"nourish","meaning":"영양을 공급하다; 키우다; 북돋우다","partOfSpeech":"v.","example":"A balanced diet helps nourish the body and keep the mind sharp.","exampleTranslation":"균형 잡힌 식단은 몸에 영양을 공급하고 정신을 날카롭게 유지하는 데 도움이 됩니다.","level":47,"category":"빈도 학습"},{"id":15615,"term":"novelty","meaning":"참신함; 새로움; 신기한 것","partOfSpeech":"n.","example":"The novelty of the gadget wore off after just a few weeks of use.","exampleTranslation":"그 기기의 참신함은 불과 몇 주간의 사용 후에 사라졌습니다.","level":47,"category":"빈도 학습"},{"id":15616,"term":"novice","meaning":"초보자; 신참","partOfSpeech":"n.","example":"As a novice cook, she followed every step in the recipe carefully.","exampleTranslation":"초보 요리사로서 그녀는 레시피의 모든 단계를 꼼꼼히 따랐습니다.","level":47,"category":"빈도 학습"},{"id":15617,"term":"nudge","meaning":"슬쩍 밀다; 살짝 건드리다","partOfSpeech":"v.","example":"She gave him a gentle nudge to remind him it was his turn to speak.","exampleTranslation":"그녀는 그가 말할 차례임을 상기시키기 위해 살짝 팔꿈치로 건드렸습니다.","level":47,"category":"빈도 학습"},{"id":15618,"term":"nylon","meaning":"나일론","partOfSpeech":"n.","example":"The bag is made of durable nylon that can withstand heavy use.","exampleTranslation":"그 가방은 많이 사용해도 견딜 수 있는 튼튼한 나일론으로 만들어졌습니다.","level":47,"category":"빈도 학습"},{"id":15619,"term":"obese","meaning":"비만인; 심하게 살찐","partOfSpeech":"adj.","example":"The doctor warned him that his unhealthy diet could make him obese.","exampleTranslation":"의사는 건강에 좋지 않은 식단이 그를 비만으로 만들 수 있다고 경고했습니다.","level":47,"category":"빈도 학습"},{"id":15620,"term":"ominous","meaning":"불길한; 나쁜 징조의","partOfSpeech":"adj.","example":"The dark clouds on the horizon looked ominous before the storm hit.","exampleTranslation":"폭풍이 몰아치기 전 지평선의 먹구름이 불길해 보였습니다.","level":47,"category":"빈도 학습"},{"id":15621,"term":"omission","meaning":"누락; 빠뜨림","partOfSpeech":"n.","example":"The omission of her name from the list was an embarrassing mistake.","exampleTranslation":"명단에서 그녀의 이름이 빠진 것은 당혹스러운 실수였습니다.","level":47,"category":"빈도 학습"},{"id":15622,"term":"onwards","meaning":"앞으로; 이후로","partOfSpeech":"adv.","example":"From that point onwards, the two friends kept in touch every week.","exampleTranslation":"그 시점 이후로 두 친구는 매주 연락을 유지했습니다.","level":47,"category":"빈도 학습"},{"id":15623,"term":"opportune","meaning":"적절한 때의; 시의적절한","partOfSpeech":"adj.","example":"This seems like an opportune moment to bring up the salary issue.","exampleTranslation":"지금이 급여 문제를 꺼내기에 적절한 순간인 것 같습니다.","level":47,"category":"빈도 학습"},{"id":15624,"term":"optimize","meaning":"최적화하다; 최대한 활용하다","partOfSpeech":"v.","example":"We need to optimize our daily schedule to get more work done.","exampleTranslation":"더 많은 일을 처리하기 위해 일상 일정을 최적화해야 합니다.","level":47,"category":"빈도 학습"},{"id":15625,"term":"oracle","meaning":"신탁; 예언자","partOfSpeech":"n.","example":"In ancient times, people traveled far to consult the oracle for guidance.","exampleTranslation":"고대에는 사람들이 지침을 구하기 위해 신탁자를 찾아 먼 길을 떠났습니다.","level":47,"category":"빈도 학습"},{"id":15626,"term":"orchard","meaning":"과수원","partOfSpeech":"n.","example":"The family spent the afternoon picking apples at the local orchard.","exampleTranslation":"그 가족은 지역 과수원에서 사과를 따며 오후를 보냈습니다.","level":47,"category":"빈도 학습"},{"id":15627,"term":"ordeal","meaning":"고난; 시련","partOfSpeech":"n.","example":"Getting lost in the mountains for two days was a terrifying ordeal.","exampleTranslation":"이틀 동안 산에서 길을 잃은 것은 무서운 시련이었습니다.","level":47,"category":"빈도 학습"},{"id":15628,"term":"ore","meaning":"광석","partOfSpeech":"n.","example":"The miners extracted iron ore from the mountain to supply the factory.","exampleTranslation":"광부들은 공장에 공급하기 위해 산에서 철 광석을 채굴했습니다.","level":47,"category":"빈도 학습"},{"id":15629,"term":"oscar","meaning":"오스카 (영화 시상식 트로피); 아카데미상","partOfSpeech":"n.","example":"She burst into tears the moment she received the oscar on stage.","exampleTranslation":"그녀는 무대에서 영화상을 받는 순간 눈물을 터뜨렸습니다.","level":47,"category":"빈도 학습"},{"id":15630,"term":"oscillate","meaning":"진동하다; 왔다 갔다 하다","partOfSpeech":"v.","example":"The fan blade will oscillate back and forth to cool the entire room.","exampleTranslation":"선풍기 날개는 방 전체를 식히기 위해 앞뒤로 진동할 것입니다.","level":47,"category":"빈도 학습"},{"id":15631,"term":"ostensible","meaning":"표면상의; 겉으로 보이는","partOfSpeech":"adj.","example":"The ostensible reason for the meeting was to discuss budget cuts.","exampleTranslation":"회의의 표면상 이유는 예산 삭감을 논의하기 위해서였습니다.","level":47,"category":"빈도 학습"},{"id":15632,"term":"oust","meaning":"몰아내다; 축출하다","partOfSpeech":"v.","example":"The board voted to oust the CEO after the financial scandal broke out.","exampleTranslation":"이사회는 재정 스캔들이 터진 후 CEO를 축출하기로 투표했습니다.","level":47,"category":"빈도 학습"},{"id":15633,"term":"outing","meaning":"야외 나들이; 소풍","partOfSpeech":"n.","example":"The whole class enjoyed the outing to the science museum last Friday.","exampleTranslation":"지난 금요일 전체 학급이 과학 박물관 나들이를 즐겼습니다.","level":47,"category":"빈도 학습"},{"id":15634,"term":"outlaw","meaning":"무법자; 불법화하다","partOfSpeech":"n.","example":"The sheriff finally caught the outlaw who had been robbing stagecoaches.","exampleTranslation":"보안관은 마침내 역마차를 털던 무법자를 잡았습니다.","level":47,"category":"빈도 학습"},{"id":15635,"term":"outskirts","meaning":"변두리; 외곽","partOfSpeech":"n.","example":"They moved to the outskirts of the city to enjoy a quieter lifestyle.","exampleTranslation":"그들은 더 조용한 생활을 즐기기 위해 도시 외곽으로 이사했습니다.","level":47,"category":"빈도 학습"},{"id":15636,"term":"outweigh","meaning":"~보다 더 중요하다; 능가하다","partOfSpeech":"v.","example":"The benefits of regular exercise outweigh the effort it takes to start.","exampleTranslation":"규칙적인 운동의 이점은 시작하는 데 드는 노력보다 훨씬 큽니다.","level":47,"category":"빈도 학습"},{"id":15637,"term":"overcrowd","meaning":"과밀하게 하다; 너무 많이 채우다","partOfSpeech":"v.","example":"The festival organizers tried not to overcrowd the venue for safety reasons.","exampleTranslation":"축제 주최측은 안전상의 이유로 행사장을 과밀하게 하지 않으려 했습니다.","level":47,"category":"빈도 학습"},{"id":15638,"term":"overhaul","meaning":"전면 점검; 대대적으로 수리하다","partOfSpeech":"n.","example":"The mechanic recommended a complete overhaul of the old engine.","exampleTranslation":"정비사는 낡은 엔진을 완전히 점검할 것을 권장했습니다.","level":47,"category":"빈도 학습"},{"id":15639,"term":"overhear","meaning":"우연히 듣다; 엿듣다","partOfSpeech":"v.","example":"I didn't mean to overhear your conversation, but the walls are very thin.","exampleTranslation":"대화를 엿들으려던 게 아니었는데 벽이 너무 얇네요.","level":47,"category":"빈도 학습"},{"id":15640,"term":"overtake","meaning":"앞질러 가다; 추월하다","partOfSpeech":"v.","example":"The runner started slow but managed to overtake the leader near the finish line.","exampleTranslation":"그 선수는 천천히 출발했지만 결승선 근처에서 선두를 추월하는 데 성공했습니다.","level":47,"category":"빈도 학습"},{"id":15641,"term":"overweight","meaning":"과체중인; 중량 초과의","partOfSpeech":"adj.","example":"The airline charged an extra fee because his luggage was overweight.","exampleTranslation":"항공사는 그의 짐이 초과 중량이었기 때문에 추가 요금을 청구했습니다.","level":47,"category":"빈도 학습"},{"id":15642,"term":"oxide","meaning":"산화물","partOfSpeech":"n.","example":"Iron oxide is what forms on metal surfaces when they are exposed to moisture.","exampleTranslation":"철 산화물은 금속 표면이 습기에 노출될 때 생성되는 것입니다.","level":47,"category":"빈도 학습"},{"id":15643,"term":"oyster","meaning":"굴","partOfSpeech":"n.","example":"He ordered a dozen fresh oyster at the seafood restaurant by the harbor.","exampleTranslation":"그는 항구 근처 해산물 식당에서 신선한 굴 한 다스를 주문했습니다.","level":47,"category":"빈도 학습"},{"id":15644,"term":"pagan","meaning":"이교도; 다신교의","partOfSpeech":"n.","example":"The historian explained that many pagan festivals were tied to seasonal changes.","exampleTranslation":"역사가는 많은 이교도 축제가 계절의 변화와 연결되어 있다고 설명했습니다.","level":47,"category":"빈도 학습"},{"id":15645,"term":"palette","meaning":"팔레트; 색 범위","partOfSpeech":"n.","example":"The artist mixed several shades of blue on her palette before painting.","exampleTranslation":"화가는 그림을 그리기 전에 팔레트에서 여러 파란색을 섞었습니다.","level":47,"category":"빈도 학습"},{"id":15646,"term":"pamphlet","meaning":"소책자; 팸플릿","partOfSpeech":"n.","example":"She handed out a pamphlet about the new recycling program in the neighborhood.","exampleTranslation":"그녀는 동네의 새로운 재활용 프로그램에 대한 소책자를 나눠줬습니다.","level":47,"category":"빈도 학습"},{"id":15648,"term":"papal","meaning":"교황의","partOfSpeech":"adj.","example":"The cathedral received a papal blessing during the pope's visit to the city.","exampleTranslation":"대성당은 교황이 도시를 방문하는 동안 교황의 축복을 받았습니다.","level":47,"category":"빈도 학습"},{"id":15649,"term":"parachute","meaning":"낙하산; 낙하산으로 뛰어내리다","partOfSpeech":"n.","example":"The skydiver checked her parachute carefully before jumping out of the plane.","exampleTranslation":"스카이다이버는 비행기에서 뛰어내리기 전에 낙하산을 꼼꼼히 확인했습니다.","level":47,"category":"빈도 학습"},{"id":15650,"term":"paramount","meaning":"가장 중요한; 최고의","partOfSpeech":"adj.","example":"Safety is paramount when working with heavy machinery at the construction site.","exampleTranslation":"공사 현장에서 중장비를 다룰 때 안전이 가장 중요합니다.","level":47,"category":"빈도 학습"},{"id":15651,"term":"parlor","meaning":"응접실; 살롱","partOfSpeech":"n.","example":"The guests were asked to wait in the parlor while dinner was being prepared.","exampleTranslation":"저녁 식사가 준비되는 동안 손님들은 응접실에서 기다려 달라는 요청을 받았습니다.","level":47,"category":"빈도 학습"},{"id":15652,"term":"parody","meaning":"패러디; 흉내 내어 풍자하다","partOfSpeech":"n.","example":"The comedy show did a hilarious parody of the most popular news program.","exampleTranslation":"그 코미디 쇼는 가장 인기 있는 뉴스 프로그램의 우스꽝스러운 패러디를 선보였습니다.","level":47,"category":"빈도 학습"},{"id":15653,"term":"parrot","meaning":"앵무새; 앵무새처럼 따라 하다","partOfSpeech":"n.","example":"The parrot in the pet shop could say hello and whistle a short tune.","exampleTranslation":"애완동물 가게의 앵무새는 안녕이라고 말하고 짧은 멜로디를 휘파람으로 불 수 있었습니다.","level":47,"category":"빈도 학습"},{"id":15654,"term":"parsley","meaning":"파슬리","partOfSpeech":"n.","example":"She sprinkled fresh parsley on top of the soup just before serving.","exampleTranslation":"그녀는 서빙하기 직전에 수프 위에 신선한 파슬리를 뿌렸습니다.","level":47,"category":"빈도 학습"},{"id":15655,"term":"partiality","meaning":"편파성; 편애","partOfSpeech":"n.","example":"The judge was removed due to clear partiality toward one side in the case.","exampleTranslation":"판사는 사건에서 한쪽에 대한 명백한 편파성으로 인해 교체되었습니다.","level":47,"category":"빈도 학습"},{"id":15656,"term":"partition","meaning":"칸막이; 분할하다","partOfSpeech":"n.","example":"They put up a glass partition to divide the open office into two work areas.","exampleTranslation":"그들은 오픈 사무실을 두 개의 작업 공간으로 나누기 위해 유리 칸막이를 설치했습니다.","level":47,"category":"빈도 학습"},{"id":15657,"term":"pastor","meaning":"목사; 성직자","partOfSpeech":"n.","example":"The pastor gave a warm and encouraging sermon to the congregation on Sunday.","exampleTranslation":"목사는 일요일에 회중에게 따뜻하고 격려가 되는 설교를 했습니다.","level":47,"category":"빈도 학습"},{"id":15658,"term":"pathology","meaning":"병리학; 병리","partOfSpeech":"n.","example":"The lab report came back from the pathology department with detailed findings.","exampleTranslation":"실험실 보고서가 상세한 검사 결과와 함께 병리학과에서 돌아왔습니다.","level":47,"category":"빈도 학습"},{"id":15659,"term":"patio","meaning":"파티오; 야외 테라스","partOfSpeech":"n.","example":"They had breakfast on the patio every morning during their vacation.","exampleTranslation":"그들은 휴가 중 매일 아침 파티오에서 아침을 먹었습니다.","level":48,"category":"빈도 학습"},{"id":15660,"term":"patronage","meaning":"후원; 단골 거래","partOfSpeech":"n.","example":"The small bookstore survived thanks to the loyal patronage of local readers.","exampleTranslation":"작은 서점은 지역 독자들의 충실한 단골 거래 덕분에 살아남았습니다.","level":48,"category":"빈도 학습"},{"id":15661,"term":"pavilion","meaning":"파빌리온; 전시관","partOfSpeech":"n.","example":"The wedding reception was held in a decorated pavilion in the garden.","exampleTranslation":"결혼 피로연은 정원의 장식된 파빌리온에서 열렸습니다.","level":48,"category":"빈도 학습"},{"id":15662,"term":"paw","meaning":"발; (동물의) 발","partOfSpeech":"n.","example":"The puppy lifted its tiny paw and touched the glass door.","exampleTranslation":"강아지는 작은 발을 들어 유리문을 건드렸습니다.","level":48,"category":"빈도 학습"},{"id":15663,"term":"payroll","meaning":"급여 대장; 급여 지급","partOfSpeech":"n.","example":"The HR department processes the payroll at the end of every month.","exampleTranslation":"인사부는 매월 말에 급여 대장을 처리합니다.","level":48,"category":"빈도 학습"},{"id":15664,"term":"peanut","meaning":"땅콩","partOfSpeech":"n.","example":"She spread a thick layer of peanut butter on her toast every morning.","exampleTranslation":"그녀는 매일 아침 토스트에 땅콩 버터를 두껍게 발랐습니다.","level":48,"category":"빈도 학습"},{"id":15665,"term":"pear","meaning":"배 (과일)","partOfSpeech":"n.","example":"He packed a pear in his lunch bag along with a sandwich and some juice.","exampleTranslation":"그는 샌드위치와 주스와 함께 도시락에 배를 하나 챙겼습니다.","level":48,"category":"빈도 학습"},{"id":15666,"term":"pebble","meaning":"조약돌; 자갈","partOfSpeech":"n.","example":"She skipped a pebble across the surface of the calm lake.","exampleTranslation":"그녀는 잔잔한 호수 표면에 조약돌을 튀겼습니다.","level":48,"category":"빈도 학습"},{"id":15667,"term":"pedagogy","meaning":"교육학; 교수법","partOfSpeech":"n.","example":"The professor's research focuses on modern pedagogy in digital classrooms.","exampleTranslation":"그 교수의 연구는 디지털 교실에서의 현대 교수법에 초점을 맞추고 있습니다.","level":48,"category":"빈도 학습"},{"id":15668,"term":"peg","meaning":"못; 고정핀; 고정하다","partOfSpeech":"n.","example":"She hung the wet towel on the peg behind the bathroom door.","exampleTranslation":"그녀는 욕실 문 뒤에 있는 못에 젖은 수건을 걸었습니다.","level":48,"category":"빈도 학습"},{"id":15669,"term":"perennial","meaning":"다년생의; 영원한; 반복되는","partOfSpeech":"adj.","example":"Traffic jams are a perennial problem in this city during rush hour.","exampleTranslation":"교통 정체는 출퇴근 시간에 이 도시에서 반복되는 문제입니다.","level":48,"category":"빈도 학습"},{"id":15670,"term":"perimeter","meaning":"둘레; 경계선","partOfSpeech":"n.","example":"Security guards walked the perimeter of the building all night.","exampleTranslation":"경비원들은 밤새 건물 경계선을 순찰했습니다.","level":48,"category":"빈도 학습"},{"id":15671,"term":"perish","meaning":"죽다; 소멸하다","partOfSpeech":"v.","example":"Many crops will perish if the drought continues for another month.","exampleTranslation":"가뭄이 한 달 더 지속되면 많은 농작물이 죽을 것입니다.","level":48,"category":"빈도 학습"},{"id":15672,"term":"perk","meaning":"특권; 혜택; 활기를 띠다","partOfSpeech":"n.","example":"One great perk of working here is the free gym membership.","exampleTranslation":"여기서 일하는 큰 혜택 중 하나는 무료 헬스장 회원권입니다.","level":48,"category":"빈도 학습"},{"id":15673,"term":"perpetrate","meaning":"(범죄를) 저지르다; 행하다","partOfSpeech":"v.","example":"The investigators worked hard to identify who had helped perpetrate the fraud.","exampleTranslation":"수사관들은 사기를 저지르는 데 누가 도왔는지 파악하기 위해 열심히 일했습니다.","level":48,"category":"빈도 학습"},{"id":15674,"term":"perpetual","meaning":"영구적인; 끊임없는","partOfSpeech":"adj.","example":"The neighbors complained about the perpetual noise from the construction site.","exampleTranslation":"이웃 주민들은 공사 현장의 끊임없는 소음에 대해 불만을 제기했습니다.","level":48,"category":"빈도 학습"},{"id":15675,"term":"perpetuate","meaning":"영속시키다; 지속시키다","partOfSpeech":"v.","example":"Negative stereotypes in media can perpetuate harmful social biases.","exampleTranslation":"미디어의 부정적인 고정관념은 해로운 사회적 편견을 지속시킬 수 있습니다.","level":48,"category":"빈도 학습"},{"id":15676,"term":"pervasive","meaning":"만연한; 퍼져 있는","partOfSpeech":"adj.","example":"The use of smartphones has become pervasive in everyday life.","exampleTranslation":"스마트폰 사용이 일상생활에 만연해졌습니다.","level":48,"category":"빈도 학습"},{"id":15677,"term":"perverse","meaning":"비뚤어진; 고집스러운; 변태적인","partOfSpeech":"adj.","example":"It seems perverse to punish people for trying to do the right thing.","exampleTranslation":"옳은 일을 하려는 사람을 처벌하는 것은 비뚤어진 것처럼 보입니다.","level":48,"category":"빈도 학습"},{"id":15678,"term":"petal","meaning":"꽃잎","partOfSpeech":"n.","example":"She pulled off each petal one by one as she sat in the garden.","exampleTranslation":"그녀는 정원에 앉아 꽃잎을 하나씩 뜯어냈습니다.","level":48,"category":"빈도 학습"},{"id":15679,"term":"physiological","meaning":"생리학적인; 생리적인","partOfSpeech":"adj.","example":"Exercise produces many physiological benefits for the human body.","exampleTranslation":"운동은 인체에 많은 생리적 이점을 가져다줍니다.","level":48,"category":"빈도 학습"},{"id":15680,"term":"picket","meaning":"말뚝; 피켓 시위를 하다","partOfSpeech":"n.","example":"Workers set up a picket line outside the factory to protest their conditions.","exampleTranslation":"노동자들은 자신들의 처우에 항의하기 위해 공장 밖에 피켓 라인을 설치했습니다.","level":48,"category":"빈도 학습"},{"id":15681,"term":"pickle","meaning":"피클; 곤경","partOfSpeech":"n.","example":"Can you add extra pickle on my burger, please?","exampleTranslation":"버거에 피클을 더 넣어 주시겠어요?","level":48,"category":"빈도 학습"},{"id":15682,"term":"pigment","meaning":"색소; 안료","partOfSpeech":"n.","example":"The artist mixed pigment with oil to create a rich, deep color.","exampleTranslation":"화가는 진하고 깊은 색을 만들기 위해 안료를 기름과 섞었습니다.","level":48,"category":"빈도 학습"},{"id":15683,"term":"pike","meaning":"창; 큰 창꼬치(생선); 고속도로","partOfSpeech":"n.","example":"The soldier carried a long pike as his primary weapon in battle.","exampleTranslation":"그 병사는 전투에서 주요 무기로 긴 창을 들었습니다.","level":48,"category":"빈도 학습"},{"id":15684,"term":"pinpoint","meaning":"정확히 찾아내다; 핀포인트","partOfSpeech":"v.","example":"The doctor was able to pinpoint the exact cause of her symptoms.","exampleTranslation":"의사는 그녀의 증상의 정확한 원인을 찾아낼 수 있었습니다.","level":48,"category":"빈도 학습"},{"id":15685,"term":"plank","meaning":"널빤지; 판자","partOfSpeech":"n.","example":"He replaced the broken plank on the old wooden deck.","exampleTranslation":"그는 낡은 나무 데크에서 부서진 널빤지를 교체했습니다.","level":48,"category":"빈도 학습"},{"id":15686,"term":"plaque","meaning":"명판; 치석","partOfSpeech":"n.","example":"A bronze plaque on the wall marks where the famous poet was born.","exampleTranslation":"벽에 있는 청동 명판은 유명한 시인이 태어난 곳을 표시합니다.","level":48,"category":"빈도 학습"},{"id":15687,"term":"plateau","meaning":"고원; 정체기","partOfSpeech":"n.","example":"After months of progress, her fitness gains hit a plateau.","exampleTranslation":"몇 달간의 발전 후 그녀의 체력 향상이 정체기에 접어들었습니다.","level":48,"category":"빈도 학습"},{"id":15688,"term":"plight","meaning":"곤경; 어려운 처지","partOfSpeech":"n.","example":"The documentary highlighted the plight of refugees living without shelter.","exampleTranslation":"그 다큐멘터리는 거처 없이 살아가는 난민들의 곤경을 부각시켰습니다.","level":48,"category":"빈도 학습"},{"id":15689,"term":"plum","meaning":"자두; 자줏빛","partOfSpeech":"n.","example":"She picked a ripe plum from the tree and ate it on the spot.","exampleTranslation":"그녀는 나무에서 잘 익은 자두를 따서 바로 먹었습니다.","level":48,"category":"빈도 학습"},{"id":15690,"term":"plume","meaning":"깃털; 연기 기둥","partOfSpeech":"n.","example":"A large plume of smoke rose from the factory chimney.","exampleTranslation":"공장 굴뚝에서 큰 연기 기둥이 피어올랐습니다.","level":48,"category":"빈도 학습"},{"id":15691,"term":"plump","meaning":"통통한; 살찐","partOfSpeech":"adj.","example":"The baker chose the most plump berries to put on top of the cake.","exampleTranslation":"제빵사는 케이크 위에 올릴 가장 통통한 베리를 골랐습니다.","level":48,"category":"빈도 학습"},{"id":15692,"term":"pneumonia","meaning":"폐렴","partOfSpeech":"n.","example":"He was hospitalized for a week after being diagnosed with pneumonia.","exampleTranslation":"그는 폐렴 진단을 받은 후 일주일간 입원했습니다.","level":48,"category":"빈도 학습"},{"id":15693,"term":"poach","meaning":"밀렵하다; 가로채다; 수란을 만들다","partOfSpeech":"v.","example":"Rangers work hard to stop hunters from trying to poach elephants.","exampleTranslation":"산림 감시원들은 사냥꾼들이 코끼리를 밀렵하려는 것을 막기 위해 열심히 일합니다.","level":48,"category":"빈도 학습"},{"id":15694,"term":"polo","meaning":"폴로(스포츠); 폴로 셔츠","partOfSpeech":"n.","example":"He wore a navy polo to the casual office party on Friday.","exampleTranslation":"그는 금요일 캐주얼 사무실 파티에 남색 폴로 셔츠를 입었습니다.","level":48,"category":"빈도 학습"},{"id":15695,"term":"polymer","meaning":"중합체; 폴리머","partOfSpeech":"n.","example":"This flexible packaging is made from a lightweight synthetic polymer.","exampleTranslation":"이 유연한 포장재는 가벼운 합성 폴리머로 만들어졌습니다.","level":48,"category":"빈도 학습"},{"id":15696,"term":"portable","meaning":"휴대용의; 이동 가능한","partOfSpeech":"adj.","example":"She bought a portable speaker to use at outdoor gatherings.","exampleTranslation":"그녀는 야외 모임에서 사용하기 위해 휴대용 스피커를 샀습니다.","level":48,"category":"빈도 학습"},{"id":15697,"term":"portal","meaning":"정문; 관문; (인터넷) 포털","partOfSpeech":"n.","example":"Students can submit assignments through the school's online portal.","exampleTranslation":"학생들은 학교 온라인 포털을 통해 과제를 제출할 수 있습니다.","level":48,"category":"빈도 학습"},{"id":15698,"term":"poultry","meaning":"가금류; 닭·오리 등","partOfSpeech":"n.","example":"The farm raises poultry and sells eggs at the local market.","exampleTranslation":"그 농장은 가금류를 키우고 지역 시장에서 달걀을 판매합니다.","level":48,"category":"빈도 학습"},{"id":15699,"term":"pre","meaning":"사전의; ~이전의 (접두사)","partOfSpeech":"prefix","example":"Make sure to complete the pre work before attending the training session.","exampleTranslation":"교육 세션에 참석하기 전에 사전 작업을 반드시 완료하세요.","level":48,"category":"빈도 학습"},{"id":15700,"term":"precarious","meaning":"불안정한; 위험한","partOfSpeech":"adj.","example":"The ladder was in a precarious position against the slippery wall.","exampleTranslation":"사다리가 미끄러운 벽에 불안정하게 기대어 있었습니다.","level":48,"category":"빈도 학습"},{"id":15701,"term":"preclude","meaning":"막다; 방해하다; 불가능하게 하다","partOfSpeech":"v.","example":"A serious injury could preclude him from competing in the championship.","exampleTranslation":"심각한 부상은 그가 선수권 대회에 참가하는 것을 막을 수 있습니다.","level":48,"category":"빈도 학습"},{"id":15702,"term":"premiere","meaning":"초연; 첫 상영","partOfSpeech":"n.","example":"The cast attended the premiere of the film in a downtown theater.","exampleTranslation":"출연진은 시내 극장에서 열린 영화 초연에 참석했습니다.","level":48,"category":"빈도 학습"},{"id":15703,"term":"presuppose","meaning":"전제하다; 미리 가정하다","partOfSpeech":"v.","example":"His argument seems to presuppose that everyone has equal access to education.","exampleTranslation":"그의 주장은 모든 사람이 교육에 동등하게 접근할 수 있다고 전제하는 것 같습니다.","level":48,"category":"빈도 학습"},{"id":15704,"term":"preview","meaning":"미리 보기; 시사회","partOfSpeech":"n.","example":"I watched a preview of the new series and it looks really interesting.","exampleTranslation":"새 시리즈의 미리 보기를 봤는데 정말 흥미로워 보입니다.","level":48,"category":"빈도 학습"},{"id":15705,"term":"procure","meaning":"조달하다; 구하다","partOfSpeech":"v.","example":"The event team had to procure enough chairs for over two hundred guests.","exampleTranslation":"행사 팀은 200명이 넘는 손님들을 위한 충분한 의자를 조달해야 했습니다.","level":48,"category":"빈도 학습"},{"id":15706,"term":"prod","meaning":"찌르다; 자극하다; 독촉하다","partOfSpeech":"v.","example":"She had to prod her brother several times to get him to help with dinner.","exampleTranslation":"그녀는 남동생이 저녁 준비를 돕게 하려고 여러 번 독촉해야 했습니다.","level":48,"category":"빈도 학습"},{"id":15707,"term":"proliferate","meaning":"급증하다; 확산되다","partOfSpeech":"v.","example":"Online shopping apps continue to proliferate as more people use smartphones.","exampleTranslation":"스마트폰 사용자가 늘면서 온라인 쇼핑 앱이 계속 급증하고 있습니다.","level":48,"category":"빈도 학습"},{"id":15708,"term":"prominence","meaning":"두드러짐; 명성; 저명함","partOfSpeech":"n.","example":"The young chef rose to prominence after winning a national cooking competition.","exampleTranslation":"그 젊은 요리사는 전국 요리 대회에서 우승한 후 명성을 얻었습니다.","level":48,"category":"빈도 학습"},{"id":15709,"term":"propaganda","meaning":"선전; 프로파간다","partOfSpeech":"n.","example":"The government used propaganda posters to encourage citizens to support the war effort.","exampleTranslation":"정부는 시민들이 전쟁 노력을 지지하도록 독려하기 위해 선전 포스터를 사용했습니다.","level":48,"category":"빈도 학습"},{"id":15710,"term":"propagate","meaning":"퍼뜨리다; 번식하다; 전파하다","partOfSpeech":"v.","example":"False information can propagate quickly through social media platforms.","exampleTranslation":"잘못된 정보는 소셜 미디어 플랫폼을 통해 빠르게 퍼질 수 있습니다.","level":48,"category":"빈도 학습"},{"id":15711,"term":"proponent","meaning":"지지자; 옹호자","partOfSpeech":"n.","example":"She is a strong proponent of using renewable energy in urban areas.","exampleTranslation":"그녀는 도시 지역에서 재생 에너지 사용을 강하게 지지하는 사람입니다.","level":48,"category":"빈도 학습"},{"id":15712,"term":"protagonist","meaning":"주인공; 주창자","partOfSpeech":"n.","example":"The protagonist of the novel faces many challenges before finding peace.","exampleTranslation":"그 소설의 주인공은 평화를 찾기 전에 많은 도전에 직면합니다.","level":48,"category":"빈도 학습"},{"id":15713,"term":"provisional","meaning":"임시의; 잠정적인","partOfSpeech":"adj.","example":"The board approved a provisional budget until the final figures were ready.","exampleTranslation":"이사회는 최종 수치가 준비될 때까지 임시 예산을 승인했습니다.","level":48,"category":"빈도 학습"},{"id":15714,"term":"prune","meaning":"가지치기하다; 자두; 줄이다","partOfSpeech":"v.","example":"He went outside on a sunny afternoon to prune the rose bushes in the yard.","exampleTranslation":"그는 화창한 오후에 마당의 장미 덤불을 가지치기하러 밖으로 나갔습니다.","level":48,"category":"빈도 학습"},{"id":15715,"term":"psychic","meaning":"초자연적인; 심령의; 점술가","partOfSpeech":"adj.","example":"She visited a psychic who claimed to know things about her past.","exampleTranslation":"그녀는 자신의 과거에 대해 안다고 주장하는 심령술사를 방문했습니다.","level":48,"category":"빈도 학습"},{"id":15716,"term":"punctuate","meaning":"구두점을 찍다; 중간중간 끊다","partOfSpeech":"v.","example":"Please punctuate your sentences correctly when writing a formal email.","exampleTranslation":"공식적인 이메일을 쓸 때는 문장에 구두점을 올바르게 찍으세요.","level":48,"category":"빈도 학습"},{"id":15717,"term":"punk","meaning":"펑크(음악·문화); 불량배","partOfSpeech":"n.","example":"He grew up listening to punk and still loves the rebellious energy of the music.","exampleTranslation":"그는 펑크 음악을 들으며 자랐고 지금도 그 반항적인 에너지를 좋아합니다.","level":48,"category":"빈도 학습"},{"id":15718,"term":"puppet","meaning":"꼭두각시; 인형","partOfSpeech":"n.","example":"The children laughed as the puppet danced across the little stage.","exampleTranslation":"꼭두각시가 작은 무대 위에서 춤추자 아이들이 웃었습니다.","level":48,"category":"빈도 학습"},{"id":15719,"term":"purge","meaning":"제거하다; 숙청하다","partOfSpeech":"v.","example":"The new manager decided to purge all outdated files from the system.","exampleTranslation":"새 관리자는 시스템에서 오래된 파일을 모두 제거하기로 결정했습니다.","level":48,"category":"빈도 학습"},{"id":15720,"term":"purify","meaning":"정화하다; 깨끗하게 하다","partOfSpeech":"v.","example":"This filter can purify tap water and make it safe to drink.","exampleTranslation":"이 필터는 수돗물을 정화해 마실 수 있게 만들어 줍니다.","level":48,"category":"빈도 학습"},{"id":15721,"term":"purport","meaning":"주장하다; 의미하다","partOfSpeech":"v.","example":"Several documents purport to prove the company's ownership of the land.","exampleTranslation":"여러 문서가 그 회사의 토지 소유권을 증명한다고 주장합니다.","level":48,"category":"빈도 학습"},{"id":15722,"term":"pajamas","meaning":"파자마; 잠옷","partOfSpeech":"n.","example":"She put on her pajamas and got into bed early that night.","exampleTranslation":"그녀는 그날 밤 파자마를 입고 일찍 잠자리에 들었습니다.","level":47,"category":"빈도 학습"},{"id":15723,"term":"quartet","meaning":"사중주; 4인조","partOfSpeech":"n.","example":"The string quartet performed beautifully at the wedding reception.","exampleTranslation":"현악 사중주단이 결혼 피로연에서 아름답게 연주했습니다.","level":48,"category":"빈도 학습"},{"id":15724,"term":"quilt","meaning":"누비이불; 퀼트","partOfSpeech":"n.","example":"Her grandmother hand-stitched a beautiful quilt for her birthday.","exampleTranslation":"할머니가 생일 선물로 아름다운 누비이불을 손으로 직접 만들어 주셨습니다.","level":48,"category":"빈도 학습"},{"id":15725,"term":"quiver","meaning":"떨리다; 전율하다","partOfSpeech":"v.","example":"His voice began to quiver as he read the emotional letter aloud.","exampleTranslation":"그가 감동적인 편지를 소리 내어 읽자 목소리가 떨리기 시작했습니다.","level":48,"category":"빈도 학습"},{"id":15726,"term":"quiz","meaning":"퀴즈; 시험","partOfSpeech":"n.","example":"The teacher gave a short quiz to check if students understood the lesson.","exampleTranslation":"선생님은 학생들이 수업 내용을 이해했는지 확인하기 위해 짧은 퀴즈를 냈습니다.","level":48,"category":"빈도 학습"},{"id":15727,"term":"racket","meaning":"라켓; 소음; 사기","partOfSpeech":"n.","example":"She bought a new tennis racket before the summer tournament.","exampleTranslation":"그녀는 여름 대회 전에 새 테니스 라켓을 샀습니다.","level":48,"category":"빈도 학습"},{"id":15728,"term":"radiance","meaning":"광채; 빛남; 환한 기운","partOfSpeech":"n.","example":"Everyone noticed the radiance of her smile when she entered the room.","exampleTranslation":"그녀가 방에 들어섰을 때 모두가 그녀의 빛나는 미소를 알아챘습니다.","level":48,"category":"빈도 학습"},{"id":15729,"term":"radius","meaning":"반지름; 반경","partOfSpeech":"n.","example":"All shops within a radius of one mile were affected by the road closure.","exampleTranslation":"도로 폐쇄로 인해 반경 1마일 이내의 모든 가게가 영향을 받았습니다.","level":48,"category":"빈도 학습"},{"id":15730,"term":"raft","meaning":"뗏목; 고무보트","partOfSpeech":"n.","example":"They built a simple raft out of logs to cross the river safely.","exampleTranslation":"그들은 강을 안전하게 건너기 위해 통나무로 간단한 뗏목을 만들었습니다.","level":48,"category":"빈도 학습"},{"id":15731,"term":"ragged","meaning":"낡아 해진; 들쭉날쭉한","partOfSpeech":"adj.","example":"The child arrived in ragged clothes that clearly needed to be replaced.","exampleTranslation":"그 아이는 분명히 교체가 필요한 낡아 해진 옷을 입고 나타났습니다.","level":48,"category":"빈도 학습"},{"id":15732,"term":"ramble","meaning":"산책하다; 두서없이 말하다","partOfSpeech":"v.","example":"He tends to ramble when he is nervous, so I just listened patiently.","exampleTranslation":"그는 긴장하면 두서없이 말하는 경향이 있어서 나는 그냥 참을성 있게 들었습니다.","level":48,"category":"빈도 학습"},{"id":15733,"term":"rash","meaning":"발진; 성급한","partOfSpeech":"n.","example":"She developed a rash after using the new soap for the first time.","exampleTranslation":"그녀는 새 비누를 처음 사용한 후 발진이 생겼습니다.","level":48,"category":"빈도 학습"},{"id":15734,"term":"rave","meaning":"열광하다; 극찬하다","partOfSpeech":"v.","example":"Everyone at the office rave about the new coffee machine in the break room.","exampleTranslation":"사무실 모든 사람이 휴게실에 새로 들어온 커피 머신을 극찬합니다.","level":48,"category":"빈도 학습"},{"id":15735,"term":"razor","meaning":"면도기; 날카로운 칼","partOfSpeech":"n.","example":"He forgot to pack his razor and had to buy one at the hotel gift shop.","exampleTranslation":"그는 면도기 챙기는 걸 잊어버려서 호텔 기념품 가게에서 하나를 사야 했습니다.","level":48,"category":"빈도 학습"},{"id":15736,"term":"reap","meaning":"수확하다; 얻다","partOfSpeech":"v.","example":"Hard work now will help you reap great rewards in the future.","exampleTranslation":"지금 열심히 하면 미래에 큰 보상을 거둘 수 있습니다.","level":48,"category":"빈도 학습"},{"id":15737,"term":"rebound","meaning":"반등하다; 튀어 오르다","partOfSpeech":"v.","example":"The stock market began to rebound after several weeks of sharp losses.","exampleTranslation":"주식 시장은 몇 주간의 급격한 하락 후 반등하기 시작했습니다.","level":48,"category":"빈도 학습"},{"id":15738,"term":"recede","meaning":"물러나다; 후퇴하다","partOfSpeech":"v.","example":"The floodwaters began to recede after three days of dry weather.","exampleTranslation":"사흘간 건조한 날씨가 계속되자 홍수 물이 물러나기 시작했습니다.","level":48,"category":"빈도 학습"},{"id":15739,"term":"receptive","meaning":"수용적인; 받아들이는","partOfSpeech":"adj.","example":"She was receptive to all suggestions and took careful notes during the meeting.","exampleTranslation":"그녀는 모든 제안을 수용적으로 받아들이며 회의 중에 꼼꼼히 메모했습니다.","level":48,"category":"빈도 학습"},{"id":15740,"term":"receptor","meaning":"수용체; 감각기","partOfSpeech":"n.","example":"The drug works by blocking a specific receptor in the brain.","exampleTranslation":"그 약은 뇌의 특정 수용체를 차단함으로써 작용합니다.","level":48,"category":"빈도 학습"},{"id":15741,"term":"recess","meaning":"휴식 시간; 쉬는 시간; 오목한 공간","partOfSpeech":"n.","example":"The kids ran outside to play as soon as recess started.","exampleTranslation":"아이들은 쉬는 시간이 시작되자마자 밖으로 뛰어나가 놀았습니다.","level":48,"category":"빈도 학습"},{"id":15742,"term":"reciprocal","meaning":"상호적인; 서로 주고받는","partOfSpeech":"adj.","example":"A good friendship is reciprocal — both people need to make an effort.","exampleTranslation":"좋은 우정은 상호적입니다 — 두 사람 모두 노력해야 합니다.","level":48,"category":"빈도 학습"},{"id":15743,"term":"redeem","meaning":"보상하다; 되찾다; 구원하다","partOfSpeech":"v.","example":"You can redeem your loyalty points for a discount on your next purchase.","exampleTranslation":"다음 구매 시 할인을 받기 위해 적립 포인트를 사용할 수 있습니다.","level":48,"category":"빈도 학습"},{"id":15744,"term":"redemption","meaning":"구원; 속죄; 되찾음","partOfSpeech":"n.","example":"The coach gave the player a chance at redemption in the final match.","exampleTranslation":"코치는 그 선수에게 마지막 경기에서 명예를 회복할 기회를 주었습니다.","level":48,"category":"빈도 학습"},{"id":15745,"term":"reed","meaning":"갈대; 리드(악기 부품)","partOfSpeech":"n.","example":"The musician replaced the worn reed in his clarinet before the concert.","exampleTranslation":"음악가는 콘서트 전에 클라리넷의 낡은 리드를 교체했습니다.","level":48,"category":"빈도 학습"},{"id":15746,"term":"reflex","meaning":"반사 작용; 반사적 행동","partOfSpeech":"n.","example":"The goalkeeper's quick reflex saved the team from losing the game.","exampleTranslation":"골키퍼의 빠른 반사 신경이 팀을 패배에서 구해냈습니다.","level":48,"category":"빈도 학습"},{"id":15747,"term":"refrain","meaning":"삼가다; 후렴구","partOfSpeech":"v.","example":"Please refrain from using your phone during the performance.","exampleTranslation":"공연 중에는 휴대폰 사용을 삼가 주세요.","level":48,"category":"빈도 학습"},{"id":15748,"term":"refurbish","meaning":"새로 단장하다; 수리하다","partOfSpeech":"v.","example":"The owner plans to refurbish the old hotel before reopening it next spring.","exampleTranslation":"주인은 내년 봄 재개장 전에 오래된 호텔을 새로 단장할 계획입니다.","level":48,"category":"빈도 학습"},{"id":15749,"term":"regenerate","meaning":"재생하다; 재건하다","partOfSpeech":"v.","example":"Some lizards can regenerate a lost tail over time.","exampleTranslation":"어떤 도마뱀은 시간이 지나면서 잃어버린 꼬리를 재생할 수 있습니다.","level":48,"category":"빈도 학습"},{"id":15750,"term":"registry","meaning":"등록부; 등록소","partOfSpeech":"n.","example":"You need to check the public registry to verify the property ownership.","exampleTranslation":"부동산 소유권을 확인하려면 공개 등록부를 조회해야 합니다.","level":48,"category":"빈도 학습"},{"id":15751,"term":"reimburse","meaning":"상환하다; 비용을 돌려주다","partOfSpeech":"v.","example":"The company agreed to reimburse employees for all travel expenses.","exampleTranslation":"회사는 직원들의 모든 출장 비용을 상환하기로 합의했습니다.","level":48,"category":"빈도 학습"},{"id":15752,"term":"reinstate","meaning":"복직시키다; 복원하다","partOfSpeech":"v.","example":"The board voted to reinstate the fired employee after reviewing the evidence.","exampleTranslation":"이사회는 증거를 검토한 후 해고된 직원을 복직시키기로 표결했습니다.","level":48,"category":"빈도 학습"},{"id":15753,"term":"reiterate","meaning":"반복하여 말하다; 재차 강조하다","partOfSpeech":"v.","example":"I want to reiterate that all deadlines must be met without exception.","exampleTranslation":"모든 마감일을 예외 없이 지켜야 한다는 점을 다시 한번 강조하고 싶습니다.","level":48,"category":"빈도 학습"},{"id":15754,"term":"relegate","meaning":"강등시키다; 좌천시키다","partOfSpeech":"v.","example":"The team's poor performance could relegate them to a lower division next season.","exampleTranslation":"팀의 부진한 성적은 다음 시즌 그들을 하위 리그로 강등시킬 수 있습니다.","level":48,"category":"빈도 학습"},{"id":15755,"term":"relic","meaning":"유물; 유적","partOfSpeech":"n.","example":"The museum displayed a relic recovered from an ancient shipwreck.","exampleTranslation":"박물관은 고대 난파선에서 발견된 유물을 전시했습니다.","level":48,"category":"빈도 학습"},{"id":15756,"term":"relinquish","meaning":"포기하다; 양도하다","partOfSpeech":"v.","example":"She decided to relinquish her position as team leader to focus on research.","exampleTranslation":"그녀는 연구에 집중하기 위해 팀장 자리를 내려놓기로 결정했습니다.","level":48,"category":"빈도 학습"},{"id":15757,"term":"remnant","meaning":"잔재; 나머지","partOfSpeech":"n.","example":"There was only a small remnant of the original forest left after the development.","exampleTranslation":"개발 후에는 원래 숲의 작은 잔재만 남아 있었습니다.","level":48,"category":"빈도 학습"},{"id":15758,"term":"renounce","meaning":"포기하다; 거부하다; 철회하다","partOfSpeech":"v.","example":"He chose to renounce his citizenship and start a new life abroad.","exampleTranslation":"그는 시민권을 포기하고 해외에서 새로운 삶을 시작하기로 선택했습니다.","level":48,"category":"빈도 학습"},{"id":15759,"term":"repeal","meaning":"폐지하다; 철회하다","partOfSpeech":"v.","example":"Citizens signed a petition asking the government to repeal the controversial law.","exampleTranslation":"시민들은 정부에 논란이 된 법을 폐지할 것을 요구하는 청원서에 서명했습니다.","level":48,"category":"빈도 학습"},{"id":15760,"term":"repel","meaning":"쫓아내다; 격퇴하다; 혐오감을 주다","partOfSpeech":"v.","example":"Apply this spray to repel mosquitoes when you go camping outdoors.","exampleTranslation":"야외 캠핑을 갈 때 모기를 쫓아내려면 이 스프레이를 뿌리세요.","level":48,"category":"빈도 학습"},{"id":15761,"term":"repertoire","meaning":"레퍼토리; 연주 목록; 기량","partOfSpeech":"n.","example":"The pianist's repertoire includes pieces from both classical and modern composers.","exampleTranslation":"그 피아니스트의 레퍼토리는 고전 및 현대 작곡가의 작품을 모두 포함합니다.","level":48,"category":"빈도 학습"},{"id":15762,"term":"resilience","meaning":"회복력; 탄력성","partOfSpeech":"n.","example":"Her resilience helped her bounce back quickly after losing the job.","exampleTranslation":"그녀의 회복력은 직장을 잃은 후 빠르게 일어서는 데 도움이 되었습니다.","level":48,"category":"빈도 학습"},{"id":15763,"term":"resonance","meaning":"공명; 울림; 반향","partOfSpeech":"n.","example":"The resonance of the cathedral bells could be heard from miles away.","exampleTranslation":"대성당 종소리의 울림은 몇 마일 밖에서도 들을 수 있었습니다.","level":48,"category":"빈도 학습"},{"id":15764,"term":"respirator","meaning":"호흡기; 방독면","partOfSpeech":"n.","example":"Workers must wear a respirator when handling hazardous chemicals in the lab.","exampleTranslation":"실험실에서 위험한 화학물질을 다룰 때 작업자는 호흡기를 착용해야 합니다.","level":48,"category":"빈도 학습"},{"id":15765,"term":"retard","meaning":"지연시키다; 늦추다","partOfSpeech":"v.","example":"Cold temperatures can retard the growth of bacteria in food.","exampleTranslation":"낮은 온도는 식품 속 박테리아의 성장을 지연시킬 수 있습니다.","level":48,"category":"빈도 학습"},{"id":15766,"term":"retort","meaning":"날카롭게 반박하다; 반박","partOfSpeech":"v.","example":"She was quick to retort when her idea was dismissed without reason.","exampleTranslation":"그녀의 아이디어가 이유 없이 묵살되자 그녀는 재빨리 반박했습니다.","level":49,"category":"빈도 학습"},{"id":15767,"term":"revel","meaning":"흥청거리다; 즐기다","partOfSpeech":"v.","example":"The students revel in the freedom of the long summer break.","exampleTranslation":"학생들은 긴 여름방학의 자유를 만끽합니다.","level":49,"category":"빈도 학습"},{"id":15768,"term":"reverend","meaning":"목사; 성직자","partOfSpeech":"n.","example":"The reverend gave a moving speech at the memorial service.","exampleTranslation":"그 목사는 추모식에서 감동적인 연설을 했습니다.","level":49,"category":"빈도 학습"},{"id":15769,"term":"revert","meaning":"되돌아가다; 원래 상태로 돌아오다","partOfSpeech":"v.","example":"After the update failed, they decided to revert to the previous version.","exampleTranslation":"업데이트가 실패하자 그들은 이전 버전으로 되돌아가기로 결정했습니다.","level":49,"category":"빈도 학습"},{"id":15770,"term":"rhyme","meaning":"운율; 운이 맞다","partOfSpeech":"n.","example":"The children clapped along to every rhyme in the song.","exampleTranslation":"아이들은 노래 속 모든 운율에 맞춰 박수를 쳤습니다.","level":49,"category":"빈도 학습"},{"id":15771,"term":"riddle","meaning":"수수께끼; 난제","partOfSpeech":"n.","example":"Nobody in the group could solve the riddle the guide posed.","exampleTranslation":"그룹의 누구도 가이드가 낸 수수께끼를 풀지 못했습니다.","level":49,"category":"빈도 학습"},{"id":15772,"term":"robin","meaning":"울새(새의 일종)","partOfSpeech":"n.","example":"A robin landed on the fence and sang for a few minutes.","exampleTranslation":"울새 한 마리가 울타리에 앉아 몇 분간 노래를 불렀습니다.","level":49,"category":"빈도 학습"},{"id":15773,"term":"rogue","meaning":"악당; 무법자; 불량의","partOfSpeech":"n.","example":"The rogue acted alone and ignored every rule the team had agreed on.","exampleTranslation":"그 악당은 홀로 행동하며 팀이 합의한 모든 규칙을 무시했습니다.","level":49,"category":"빈도 학습"},{"id":15774,"term":"rouge","meaning":"루즈; 볼 연지","partOfSpeech":"n.","example":"She applied a little rouge to her cheeks before the photo shoot.","exampleTranslation":"그녀는 사진 촬영 전에 볼에 루즈를 살짝 발랐습니다.","level":49,"category":"빈도 학습"},{"id":15775,"term":"rouse","meaning":"깨우다; 불러일으키다","partOfSpeech":"v.","example":"The coach tried to rouse the team with an inspiring halftime speech.","exampleTranslation":"코치는 감동적인 하프타임 연설로 팀을 고무시키려 했습니다.","level":49,"category":"빈도 학습"},{"id":15776,"term":"rubble","meaning":"잔해; 파편","partOfSpeech":"n.","example":"Workers cleared the rubble left by the collapsed building.","exampleTranslation":"작업자들이 무너진 건물이 남긴 잔해를 치웠습니다.","level":49,"category":"빈도 학습"},{"id":15777,"term":"rugby","meaning":"럭비","partOfSpeech":"n.","example":"He played rugby throughout high school and earned a scholarship.","exampleTranslation":"그는 고등학교 내내 럭비를 하며 장학금을 받았습니다.","level":49,"category":"빈도 학습"},{"id":15778,"term":"rugged","meaning":"거친; 험준한; 단단한","partOfSpeech":"adj.","example":"The trail through the rugged mountains took the hikers six hours.","exampleTranslation":"험준한 산을 가로지르는 그 등산로는 하이커들에게 여섯 시간이 걸렸습니다.","level":49,"category":"빈도 학습"},{"id":15779,"term":"rustle","meaning":"바스락거리다; 바스락 소리","partOfSpeech":"v.","example":"Leaves began to rustle as the wind picked up in the evening.","exampleTranslation":"저녁에 바람이 강해지자 나뭇잎이 바스락거리기 시작했습니다.","level":49,"category":"빈도 학습"},{"id":15780,"term":"sacrament","meaning":"성사; 성례전","partOfSpeech":"n.","example":"The priest explained the meaning of each sacrament to the new members.","exampleTranslation":"신부는 새 신자들에게 각 성사의 의미를 설명했습니다.","level":49,"category":"빈도 학습"},{"id":15781,"term":"sag","meaning":"처지다; 축 늘어지다","partOfSpeech":"v.","example":"The old shelf began to sag under the weight of so many books.","exampleTranslation":"낡은 선반이 수많은 책의 무게로 처지기 시작했습니다.","level":49,"category":"빈도 학습"},{"id":15782,"term":"saga","meaning":"대서사시; 장편 이야기","partOfSpeech":"n.","example":"The family's saga of immigration and survival spanned three generations.","exampleTranslation":"이민과 생존에 관한 그 가족의 대서사시는 3대에 걸쳐 있었습니다.","level":49,"category":"빈도 학습"},{"id":15783,"term":"sage","meaning":"현자; 세이지(허브); 현명한","partOfSpeech":"n.","example":"The village elder was regarded as a sage whose advice was always sound.","exampleTranslation":"마을 어른은 항상 조언이 타당한 현자로 여겨졌습니다.","level":49,"category":"빈도 학습"},{"id":15784,"term":"salient","meaning":"두드러진; 핵심적인","partOfSpeech":"adj.","example":"The report highlighted the most salient points for the board to consider.","exampleTranslation":"보고서는 이사회가 고려해야 할 가장 두드러진 사항들을 강조했습니다.","level":49,"category":"빈도 학습"},{"id":15785,"term":"saloon","meaning":"술집; 바","partOfSpeech":"n.","example":"The cowboys walked into the saloon and ordered drinks after a long ride.","exampleTranslation":"카우보이들은 긴 이동 후 술집에 들어가 음료를 주문했습니다.","level":49,"category":"빈도 학습"},{"id":15786,"term":"salvage","meaning":"구하다; 건지다; 구조","partOfSpeech":"v.","example":"The crew worked overnight to salvage the cargo from the sunken boat.","exampleTranslation":"선원들은 침몰한 배에서 화물을 건져내기 위해 밤새 작업했습니다.","level":49,"category":"빈도 학습"},{"id":15787,"term":"satin","meaning":"새틴; 공단(비단의 일종)","partOfSpeech":"n.","example":"The bride chose a satin dress that shimmered under the ballroom lights.","exampleTranslation":"신부는 연회장 조명 아래 빛나는 새틴 드레스를 선택했습니다.","level":49,"category":"빈도 학습"},{"id":15788,"term":"satire","meaning":"풍자; 풍자 작품","partOfSpeech":"n.","example":"The show is a sharp satire of modern office culture.","exampleTranslation":"그 프로그램은 현대 직장 문화에 대한 날카로운 풍자입니다.","level":49,"category":"빈도 학습"},{"id":15789,"term":"savour","meaning":"음미하다; 맛보다","partOfSpeech":"v.","example":"Take a moment to savour the taste before swallowing.","exampleTranslation":"삼키기 전에 잠시 맛을 음미해 보세요.","level":49,"category":"빈도 학습"},{"id":15790,"term":"scalp","meaning":"두피; 머리 가죽","partOfSpeech":"n.","example":"The dermatologist examined her scalp for signs of dryness.","exampleTranslation":"피부과 의사가 건조증 징후를 찾기 위해 그녀의 두피를 검사했습니다.","level":49,"category":"빈도 학습"},{"id":15791,"term":"scant","meaning":"부족한; 거의 없는","partOfSpeech":"adj.","example":"There was scant evidence to support the claim they had made.","exampleTranslation":"그들이 한 주장을 뒷받침할 증거가 거의 없었습니다.","level":49,"category":"빈도 학습"},{"id":15792,"term":"scarlet","meaning":"진홍색; 새빨간","partOfSpeech":"adj.","example":"She wore a scarlet scarf that stood out in the grey crowd.","exampleTranslation":"그녀는 회색빛 군중 속에서 눈에 띄는 진홍색 스카프를 하고 있었습니다.","level":49,"category":"빈도 학습"},{"id":15793,"term":"schizophrenic","meaning":"조현병의; 양면적인","partOfSpeech":"adj.","example":"The film has a schizophrenic tone, shifting between comedy and tragedy.","exampleTranslation":"그 영화는 코미디와 비극 사이를 오가는 양면적인 분위기를 가지고 있습니다.","level":49,"category":"빈도 학습"},{"id":15794,"term":"scissors","meaning":"가위","partOfSpeech":"n.","example":"Could you hand me the scissors so I can cut this ribbon?","exampleTranslation":"이 리본을 자를 수 있게 가위를 건네줄 수 있어요?","level":49,"category":"빈도 학습"},{"id":15795,"term":"scorn","meaning":"경멸; 비웃음; 경멸하다","partOfSpeech":"n.","example":"She looked at his excuse with open scorn and walked away.","exampleTranslation":"그녀는 그의 변명을 노골적으로 경멸하는 눈으로 바라보다가 자리를 떴습니다.","level":49,"category":"빈도 학습"},{"id":15796,"term":"scowl","meaning":"인상 찡그리기; 인상을 찡그리다","partOfSpeech":"v.","example":"The customer began to scowl when he heard about the extra charge.","exampleTranslation":"고객은 추가 요금 이야기를 듣자 인상을 찡그리기 시작했습니다.","level":49,"category":"빈도 학습"},{"id":15797,"term":"screech","meaning":"날카롭게 울다; 끼익 소리","partOfSpeech":"v.","example":"The car's brakes began to screech as it slid on the wet road.","exampleTranslation":"자동차 브레이크가 젖은 도로에서 미끄러지며 끼익 소리를 내기 시작했습니다.","level":49,"category":"빈도 학습"},{"id":15798,"term":"scribble","meaning":"휘갈겨 쓰다; 낙서","partOfSpeech":"v.","example":"She would scribble notes in the margins while reading her textbook.","exampleTranslation":"그녀는 교재를 읽으면서 여백에 메모를 휘갈겨 쓰곤 했습니다.","level":49,"category":"빈도 학습"},{"id":15799,"term":"scroll","meaning":"두루마리; 스크롤하다","partOfSpeech":"v.","example":"He would scroll through social media for hours before bed.","exampleTranslation":"그는 잠자리에 들기 전에 몇 시간 동안 소셜 미디어를 스크롤하곤 했습니다.","level":49,"category":"빈도 학습"},{"id":15800,"term":"secrecy","meaning":"비밀; 비밀 유지","partOfSpeech":"n.","example":"The project was conducted in complete secrecy until the launch day.","exampleTranslation":"그 프로젝트는 출시일까지 완전한 비밀리에 진행되었습니다.","level":49,"category":"빈도 학습"},{"id":15801,"term":"secrete","meaning":"분비하다; 숨기다","partOfSpeech":"v.","example":"Certain glands secrete hormones that regulate your mood and energy.","exampleTranslation":"특정 분비샘은 기분과 에너지를 조절하는 호르몬을 분비합니다.","level":49,"category":"빈도 학습"},{"id":15802,"term":"seep","meaning":"스며들다; 새다","partOfSpeech":"v.","example":"Water began to seep through the crack in the basement wall.","exampleTranslation":"지하실 벽의 균열을 통해 물이 스며들기 시작했습니다.","level":49,"category":"빈도 학습"},{"id":15803,"term":"seizure","meaning":"발작; 압류; 장악","partOfSpeech":"n.","example":"The paramedic stayed with the patient until the seizure had passed.","exampleTranslation":"구급대원은 발작이 끝날 때까지 환자 곁에 있었습니다.","level":49,"category":"빈도 학습"},{"id":15804,"term":"sensory","meaning":"감각의; 감각에 관한","partOfSpeech":"adj.","example":"The museum created a sensory room for children who need a quiet space.","exampleTranslation":"그 박물관은 조용한 공간이 필요한 아이들을 위한 감각 방을 만들었습니다.","level":49,"category":"빈도 학습"},{"id":15805,"term":"sensual","meaning":"관능적인; 감각적 쾌락의","partOfSpeech":"adj.","example":"The chef described the dish as a sensual experience for the palate.","exampleTranslation":"그 셰프는 그 요리를 미각을 위한 관능적인 경험이라고 묘사했습니다.","level":49,"category":"빈도 학습"},{"id":15806,"term":"serene","meaning":"고요한; 평온한","partOfSpeech":"adj.","example":"The lake at dawn looked completely serene with no wind or movement.","exampleTranslation":"새벽의 호수는 바람도 움직임도 없이 완전히 고요해 보였습니다.","level":49,"category":"빈도 학습"},{"id":15807,"term":"sewer","meaning":"하수도; 하수관","partOfSpeech":"n.","example":"The city repaired a damaged sewer that had been causing flooding.","exampleTranslation":"시는 홍수를 유발하던 파손된 하수도를 수리했습니다.","level":49,"category":"빈도 학습"},{"id":15808,"term":"shear","meaning":"깎다; 전단하다; 전단력","partOfSpeech":"v.","example":"The farmer hired extra workers to shear the sheep before summer.","exampleTranslation":"농부는 여름 전에 양털을 깎기 위해 추가 인부를 고용했습니다.","level":49,"category":"빈도 학습"},{"id":15809,"term":"sherry","meaning":"셰리(스페인산 강화 와인)","partOfSpeech":"n.","example":"He poured a small glass of sherry for his guest before dinner.","exampleTranslation":"그는 저녁 식사 전에 손님에게 셰리 한 잔을 따라 주었습니다.","level":49,"category":"빈도 학습"},{"id":15810,"term":"shimmer","meaning":"희미하게 빛나다; 아른거리다","partOfSpeech":"v.","example":"The surface of the pool began to shimmer in the afternoon sunlight.","exampleTranslation":"오후 햇빛 속에 수영장 수면이 아른거리기 시작했습니다.","level":49,"category":"빈도 학습"},{"id":15811,"term":"shortcoming","meaning":"결점; 단점","partOfSpeech":"n.","example":"Every plan has a shortcoming, so we need to prepare a backup strategy.","exampleTranslation":"모든 계획에는 결점이 있으므로 대비 전략을 준비해야 합니다.","level":49,"category":"빈도 학습"},{"id":15812,"term":"shovel","meaning":"삽; 삽으로 퍼내다","partOfSpeech":"n.","example":"He grabbed a shovel and started clearing the snow from the driveway.","exampleTranslation":"그는 삽을 들고 진입로의 눈을 치우기 시작했습니다.","level":49,"category":"빈도 학습"},{"id":15813,"term":"shrewd","meaning":"빈틈없는; 영리한","partOfSpeech":"adj.","example":"She made a shrewd investment that paid off years later.","exampleTranslation":"그녀는 빈틈없는 투자를 해 수년 후에 큰 수익을 얻었습니다.","level":49,"category":"빈도 학습"},{"id":15814,"term":"shriek","meaning":"비명을 지르다; 날카로운 비명","partOfSpeech":"v.","example":"The child began to shriek with laughter on the roller coaster.","exampleTranslation":"아이는 롤러코스터에서 웃음으로 비명을 지르기 시작했습니다.","level":49,"category":"빈도 학습"},{"id":15815,"term":"shroud","meaning":"수의; 가리다; 덮다","partOfSpeech":"n.","example":"A thick shroud of fog covered the valley in the early morning.","exampleTranslation":"이른 아침 짙은 안개의 수의가 계곡을 뒤덮었습니다.","level":49,"category":"빈도 학습"},{"id":15816,"term":"shutter","meaning":"셔터; 덧문; 닫다","partOfSpeech":"n.","example":"The photographer adjusted the shutter speed before taking the shot.","exampleTranslation":"사진작가는 사진을 찍기 전에 셔터 속도를 조정했습니다.","level":49,"category":"빈도 학습"},{"id":15817,"term":"sic","meaning":"원문대로; (오류를 표시하는 라틴어 약어)","partOfSpeech":"adv.","example":"The editor inserted sic after the misspelled word to show it was in the original.","exampleTranslation":"편집자는 원문에 있던 것임을 보여주기 위해 잘못 표기된 단어 뒤에 해당 라틴어 표기를 넣었습니다.","level":49,"category":"빈도 학습"},{"id":15818,"term":"sideline","meaning":"사이드라인; 부업; 벤치로 물러나게 하다","partOfSpeech":"n.","example":"The injured player had to watch the game from the sideline.","exampleTranslation":"부상당한 선수는 사이드라인에서 경기를 지켜봐야 했습니다.","level":49,"category":"빈도 학습"},{"id":15819,"term":"sift","meaning":"체로 치다; 면밀히 검토하다","partOfSpeech":"v.","example":"You need to sift the flour before adding it to the batter.","exampleTranslation":"반죽에 넣기 전에 밀가루를 체로 쳐야 합니다.","level":49,"category":"빈도 학습"},{"id":15820,"term":"silhouette","meaning":"실루엣; 윤곽","partOfSpeech":"n.","example":"We could see the silhouette of the mountains against the setting sun.","exampleTranslation":"지는 해를 배경으로 산의 실루엣이 보였습니다.","level":49,"category":"빈도 학습"},{"id":15821,"term":"sinister","meaning":"불길한; 사악한","partOfSpeech":"adj.","example":"There was something sinister about the way he smiled at us.","exampleTranslation":"그가 우리에게 미소 짓는 방식에는 뭔가 불길한 것이 있었습니다.","level":49,"category":"빈도 학습"},{"id":15822,"term":"siren","meaning":"사이렌; 경보음","partOfSpeech":"n.","example":"Everyone pulled over when they heard the siren of the approaching ambulance.","exampleTranslation":"다가오는 구급차의 사이렌 소리를 듣고 모두가 차를 길 옆으로 세웠습니다.","level":49,"category":"빈도 학습"},{"id":15823,"term":"skim","meaning":"훑어보다; 걷어내다; 스치다","partOfSpeech":"v.","example":"I only had time to skim the report before the meeting started.","exampleTranslation":"회의가 시작되기 전에 보고서를 훑어볼 시간밖에 없었습니다.","level":49,"category":"빈도 학습"},{"id":15824,"term":"skinny","meaning":"몹시 마른; 아주 얇은","partOfSpeech":"adj.","example":"The puppy was so skinny when we rescued it from the street.","exampleTranslation":"우리가 길에서 구조했을 때 그 강아지는 너무 말랐습니다.","level":49,"category":"빈도 학습"},{"id":15825,"term":"slay","meaning":"죽이다; (비격식) 완전히 사로잡다","partOfSpeech":"v.","example":"In the old tale, the hero set out to slay the dragon terrorizing the village.","exampleTranslation":"옛 이야기에서 영웅은 마을을 공포에 떨게 하는 용을 죽이러 나섰습니다.","level":49,"category":"빈도 학습"},{"id":15826,"term":"sleek","meaning":"매끄러운; 세련된","partOfSpeech":"adj.","example":"The new phone has a sleek design that fits comfortably in your hand.","exampleTranslation":"그 새 휴대폰은 손에 편안하게 쥐어지는 매끄러운 디자인을 가지고 있습니다.","level":49,"category":"빈도 학습"},{"id":15827,"term":"sling","meaning":"팔걸이 붕대; 새총; 던지다","partOfSpeech":"n.","example":"The doctor put his arm in a sling after the shoulder injury.","exampleTranslation":"의사는 어깨 부상 후 그의 팔을 팔걸이 붕대에 고정했습니다.","level":49,"category":"빈도 학습"},{"id":15828,"term":"slipper","meaning":"슬리퍼; 실내화","partOfSpeech":"n.","example":"She put on her slipper before walking across the cold floor.","exampleTranslation":"그녀는 차가운 바닥을 걷기 전에 슬리퍼를 신었습니다.","level":49,"category":"빈도 학습"},{"id":15829,"term":"slippery","meaning":"미끄러운; 파악하기 어려운","partOfSpeech":"adj.","example":"Be careful on the stairs — the floor is slippery after mopping.","exampleTranslation":"계단에서 조심하세요 — 걸레질 후에 바닥이 미끄럽습니다.","level":49,"category":"빈도 학습"},{"id":15830,"term":"slit","meaning":"가느다란 틈; 가늘게 베다","partOfSpeech":"n.","example":"Light came through a narrow slit in the curtains.","exampleTranslation":"커튼의 좁은 틈으로 빛이 들어왔습니다.","level":49,"category":"빈도 학습"},{"id":15831,"term":"slop","meaning":"질척한 음식; 엎지르다","partOfSpeech":"v.","example":"He was in such a hurry that he managed to slop coffee all over his shirt.","exampleTranslation":"그는 너무 서두르다가 셔츠 전체에 커피를 엎질러 버렸습니다.","level":49,"category":"빈도 학습"},{"id":15832,"term":"slug","meaning":"민달팽이; 한 모금; 게으름뱅이","partOfSpeech":"n.","example":"After the rain, a slug was crawling slowly across the garden path.","exampleTranslation":"비가 온 뒤 민달팽이 한 마리가 정원 길을 천천히 기어가고 있었습니다.","level":49,"category":"빈도 학습"},{"id":15833,"term":"slum","meaning":"빈민가; 슬럼가","partOfSpeech":"n.","example":"The documentary showed life in a crowded urban slum.","exampleTranslation":"그 다큐멘터리는 혼잡한 도시 빈민가에서의 삶을 보여주었습니다.","level":49,"category":"빈도 학습"},{"id":15834,"term":"sly","meaning":"교활한; 능청스러운","partOfSpeech":"adj.","example":"The sly fox in the story always found a way to outsmart the other animals.","exampleTranslation":"이야기 속 교활한 여우는 항상 다른 동물들을 앞지를 방법을 찾았습니다.","level":49,"category":"빈도 학습"},{"id":15835,"term":"snag","meaning":"뜻밖의 장애물; 걸리다","partOfSpeech":"n.","example":"We hit a snag in the project when the main supplier canceled the order.","exampleTranslation":"주요 공급업체가 주문을 취소하면서 프로젝트에 뜻밖의 차질이 생겼습니다.","level":49,"category":"빈도 학습"},{"id":15836,"term":"snarl","meaning":"으르렁거리다; 뒤엉킨 혼잡","partOfSpeech":"v.","example":"The dog began to snarl when a stranger approached the gate.","exampleTranslation":"낯선 사람이 문에 다가오자 개가 으르렁거리기 시작했습니다.","level":49,"category":"빈도 학습"},{"id":15837,"term":"snipe","meaning":"저격하다; 비열하게 비난하다","partOfSpeech":"v.","example":"It's not professional to snipe at your colleagues during a team meeting.","exampleTranslation":"팀 회의 중에 동료들을 비열하게 비난하는 것은 전문적이지 않습니다.","level":49,"category":"빈도 학습"},{"id":15838,"term":"snort","meaning":"코웃음치다; 콧방귀 뀌다","partOfSpeech":"v.","example":"She let out a snort of laughter when she heard the ridiculous joke.","exampleTranslation":"그녀는 터무니없는 농담을 듣고 코웃음을 쳤습니다.","level":49,"category":"빈도 학습"},{"id":15839,"term":"soda","meaning":"소다; 탄산음료","partOfSpeech":"n.","example":"He ordered a burger and a large soda to go with it.","exampleTranslation":"그는 버거와 함께 먹을 큰 소다를 주문했습니다.","level":49,"category":"빈도 학습"},{"id":15840,"term":"solicit","meaning":"간청하다; 요청하다; 권유하다","partOfSpeech":"v.","example":"The charity will solicit donations from local businesses this weekend.","exampleTranslation":"그 자선단체는 이번 주말에 지역 기업들에게 기부를 요청할 것입니다.","level":49,"category":"빈도 학습"},{"id":15841,"term":"solvent","meaning":"용제; 지급 능력이 있는","partOfSpeech":"n.","example":"Use this solvent to remove the paint stain from the countertop.","exampleTranslation":"이 용제를 사용해서 조리대의 페인트 얼룩을 제거하세요.","level":49,"category":"빈도 학습"},{"id":15842,"term":"sophistication","meaning":"세련됨; 정교함; 복잡함","partOfSpeech":"n.","example":"The sophistication of her writing style impressed the entire editorial board.","exampleTranslation":"그녀의 글쓰기 스타일의 세련됨이 편집위원회 전체를 감동시켰습니다.","level":49,"category":"빈도 학습"},{"id":15843,"term":"sparse","meaning":"드문드문한; 희박한","partOfSpeech":"adj.","example":"The furniture in the apartment was sparse but carefully chosen.","exampleTranslation":"아파트의 가구는 드문드문했지만 신중하게 선택되었습니다.","level":49,"category":"빈도 학습"},{"id":15844,"term":"spectre","meaning":"유령; 망령; 불길한 위협","partOfSpeech":"n.","example":"The spectre of unemployment loomed over the workers after the announcement.","exampleTranslation":"발표 이후 실업의 망령이 노동자들 위에 드리워졌습니다.","level":49,"category":"빈도 학습"},{"id":15845,"term":"splinter","meaning":"파편; 가시; 쪼개지다","partOfSpeech":"n.","example":"She got a splinter in her finger from handling the old wooden fence.","exampleTranslation":"그녀는 낡은 나무 울타리를 다루다가 손가락에 가시가 박혔습니다.","level":49,"category":"빈도 학습"},{"id":15846,"term":"sponge","meaning":"스펀지; 해면; 닦아내다","partOfSpeech":"n.","example":"Use a damp sponge to wipe down the kitchen counter after cooking.","exampleTranslation":"요리 후 주방 조리대를 닦으려면 젖은 스펀지를 사용하세요.","level":49,"category":"빈도 학습"},{"id":15847,"term":"spreadsheet","meaning":"스프레드시트; 표 계산 프로그램","partOfSpeech":"n.","example":"She created a spreadsheet to track the team's monthly expenses.","exampleTranslation":"그녀는 팀의 월별 지출을 추적하기 위해 스프레드시트를 만들었습니다.","level":49,"category":"빈도 학습"},{"id":15848,"term":"squadron","meaning":"편대; 부대; 비행 중대","partOfSpeech":"n.","example":"A squadron of fighter jets flew overhead during the national ceremony.","exampleTranslation":"국가 행사 중에 전투기 편대가 머리 위로 날아갔습니다.","level":49,"category":"빈도 학습"},{"id":15849,"term":"squeak","meaning":"삐걱거리다; 찍 소리를 내다","partOfSpeech":"v.","example":"The old floorboards would squeak every time someone walked across them.","exampleTranslation":"누군가 걸을 때마다 오래된 마룻바닥이 삐걱거렸습니다.","level":49,"category":"빈도 학습"},{"id":15850,"term":"squint","meaning":"눈을 가늘게 뜨다; 사시","partOfSpeech":"v.","example":"He had to squint to read the small text on the sign across the street.","exampleTranslation":"그는 길 건너 표지판의 작은 글씨를 읽으려고 눈을 가늘게 떠야 했습니다.","level":49,"category":"빈도 학습"},{"id":15851,"term":"squirrel","meaning":"다람쥐; 저장하다","partOfSpeech":"n.","example":"A squirrel was busy burying acorns in the park before winter.","exampleTranslation":"다람쥐 한 마리가 겨울 전에 공원에서 도토리를 열심히 묻고 있었습니다.","level":49,"category":"빈도 학습"},{"id":15852,"term":"staple","meaning":"주요 식품; 스테이플; 핵심적인","partOfSpeech":"n.","example":"Rice is a staple in most Asian households and eaten with every meal.","exampleTranslation":"쌀은 대부분의 아시아 가정에서 주요 식품으로 매 끼니마다 먹습니다.","level":49,"category":"빈도 학습"},{"id":15853,"term":"stature","meaning":"신장; 명성; 위상","partOfSpeech":"n.","example":"She grew in stature as a leader after handling the crisis so well.","exampleTranslation":"그 위기를 훌륭하게 처리한 후 그녀는 지도자로서의 위상이 높아졌습니다.","level":49,"category":"빈도 학습"},{"id":15854,"term":"steroid","meaning":"스테로이드; 스테로이드 약물","partOfSpeech":"n.","example":"The athlete was disqualified after testing positive for a banned steroid.","exampleTranslation":"그 선수는 금지된 스테로이드 양성 반응이 나와 실격 처리되었습니다.","level":49,"category":"빈도 학습"},{"id":15855,"term":"stew","meaning":"스튜; 끓이다; 걱정하다","partOfSpeech":"n.","example":"My grandmother made a hearty stew with potatoes, carrots, and beef.","exampleTranslation":"할머니는 감자, 당근, 쇠고기로 든든한 스튜를 만들어 주셨습니다.","level":49,"category":"빈도 학습"},{"id":15856,"term":"stifle","meaning":"억누르다; 숨막히게 하다","partOfSpeech":"v.","example":"She tried to stifle a yawn during the long and boring presentation.","exampleTranslation":"그녀는 길고 지루한 발표 중에 하품을 억누르려고 했습니다.","level":49,"category":"빈도 학습"},{"id":15857,"term":"stipulate","meaning":"규정하다; 명시하다","partOfSpeech":"v.","example":"The contract will stipulate that all payments must be made within thirty days.","exampleTranslation":"계약서는 모든 납부가 30일 이내에 이루어져야 한다고 명시할 것입니다.","level":49,"category":"빈도 학습"},{"id":15858,"term":"stoop","meaning":"몸을 굽히다; 허리를 구부리다; 현관 계단","partOfSpeech":"v.","example":"You have to stoop to enter the low doorway of the old cottage.","exampleTranslation":"오래된 오두막집의 낮은 문을 통과하려면 허리를 굽혀야 합니다.","level":49,"category":"빈도 학습"},{"id":15859,"term":"stout","meaning":"통통한; 튼튼한; 흑맥주","partOfSpeech":"adj.","example":"The stout wooden door was too heavy for the children to push open.","exampleTranslation":"그 튼튼한 나무 문은 아이들이 밀어서 열기에는 너무 무거웠습니다.","level":49,"category":"빈도 학습"},{"id":15860,"term":"strait","meaning":"해협; 곤경","partOfSpeech":"n.","example":"The ship navigated carefully through the narrow strait between the two islands.","exampleTranslation":"배는 두 섬 사이의 좁은 해협을 조심스럽게 항해했습니다.","level":49,"category":"빈도 학습"},{"id":15862,"term":"strangle","meaning":"목 조르다; 억압하다","partOfSpeech":"v.","example":"Heavy regulations can strangle small businesses trying to grow.","exampleTranslation":"과도한 규제는 성장하려는 소기업을 억압할 수 있습니다.","level":49,"category":"빈도 학습"},{"id":15863,"term":"streamline","meaning":"능률적으로 하다; 간소화하다","partOfSpeech":"v.","example":"The company decided to streamline its hiring process to save time.","exampleTranslation":"그 회사는 시간을 절약하기 위해 채용 절차를 간소화하기로 결정했습니다.","level":49,"category":"빈도 학습"},{"id":15864,"term":"stringent","meaning":"엄격한; 까다로운","partOfSpeech":"adj.","example":"The new law introduced stringent safety requirements for all food manufacturers.","exampleTranslation":"새 법은 모든 식품 제조업체에 엄격한 안전 요건을 도입했습니다.","level":49,"category":"빈도 학습"},{"id":15865,"term":"sturdy","meaning":"튼튼한; 견고한","partOfSpeech":"adj.","example":"We need a sturdy table that can hold all the equipment for the event.","exampleTranslation":"행사에 사용할 모든 장비를 올려놓을 수 있는 튼튼한 테이블이 필요합니다.","level":49,"category":"빈도 학습"},{"id":15866,"term":"subdivide","meaning":"세분화하다; 더 작게 나누다","partOfSpeech":"v.","example":"They decided to subdivide the large plot into smaller lots for sale.","exampleTranslation":"그들은 넓은 부지를 판매를 위해 더 작은 구획으로 세분화하기로 결정했습니다.","level":49,"category":"빈도 학습"},{"id":15867,"term":"subdue","meaning":"진압하다; 억누르다","partOfSpeech":"v.","example":"The police managed to subdue the suspect without anyone getting hurt.","exampleTranslation":"경찰은 아무도 다치지 않고 용의자를 제압하는 데 성공했습니다.","level":49,"category":"빈도 학습"},{"id":15868,"term":"submerge","meaning":"물속에 잠기다; 침수시키다","partOfSpeech":"v.","example":"The submarine can submerge to a depth of several hundred meters.","exampleTranslation":"그 잠수함은 수백 미터 깊이까지 잠수할 수 있습니다.","level":49,"category":"빈도 학습"},{"id":15869,"term":"subside","meaning":"가라앉다; 줄어들다","partOfSpeech":"v.","example":"The doctor said the swelling should subside within a few days.","exampleTranslation":"의사는 붓기가 며칠 내로 가라앉을 것이라고 말했습니다.","level":49,"category":"빈도 학습"},{"id":15870,"term":"subsist","meaning":"생존하다; 겨우 살아가다","partOfSpeech":"v.","example":"The villagers had to subsist on very little food during the drought.","exampleTranslation":"가뭄 동안 마을 주민들은 아주 적은 식량으로 버텨야 했습니다.","level":49,"category":"빈도 학습"},{"id":15871,"term":"subvert","meaning":"전복하다; 약화시키다","partOfSpeech":"v.","example":"The group attempted to subvert the government through propaganda.","exampleTranslation":"그 단체는 선동을 통해 정부를 전복하려 했습니다.","level":49,"category":"빈도 학습"},{"id":15872,"term":"succumb","meaning":"굴복하다; (병 등으로) 쓰러지다","partOfSpeech":"v.","example":"He tried to resist temptation but finally had to succumb.","exampleTranslation":"그는 유혹을 뿌리치려 했지만 결국 굴복하고 말았습니다.","level":49,"category":"빈도 학습"},{"id":15873,"term":"suffice","meaning":"충분하다; 족하다","partOfSpeech":"v.","example":"A brief explanation should suffice for now—we can add details later.","exampleTranslation":"간단한 설명으로 지금은 충분할 것입니다—나중에 세부 사항을 추가할 수 있어요.","level":49,"category":"빈도 학습"},{"id":15874,"term":"surpass","meaning":"능가하다; 뛰어넘다","partOfSpeech":"v.","example":"Her final exam score managed to surpass everyone else in the class.","exampleTranslation":"그녀의 기말고사 점수는 반에서 모든 사람을 능가했습니다.","level":50,"category":"빈도 학습"},{"id":15875,"term":"surreal","meaning":"비현실적인; 초현실적인","partOfSpeech":"adj.","example":"Walking through the fog-covered forest felt completely surreal.","exampleTranslation":"안개로 뒤덮인 숲을 걷는 것은 완전히 비현실적인 느낌이었습니다.","level":50,"category":"빈도 학습"},{"id":15876,"term":"swarm","meaning":"떼; 무리; 떼 지어 움직이다","partOfSpeech":"n.","example":"A swarm of bees suddenly appeared near the picnic table.","exampleTranslation":"피크닉 테이블 근처에 갑자기 벌 떼가 나타났습니다.","level":50,"category":"빈도 학습"},{"id":15877,"term":"swoop","meaning":"급강하하다; 덮치다","partOfSpeech":"v.","example":"The eagle began to swoop down toward the fish in the river.","exampleTranslation":"독수리가 강에 있는 물고기를 향해 급강하하기 시작했습니다.","level":50,"category":"빈도 학습"},{"id":15878,"term":"syllable","meaning":"음절","partOfSpeech":"n.","example":"The teacher asked students to count the syllable in each word.","exampleTranslation":"선생님은 학생들에게 각 단어의 음절 수를 세어 보라고 했습니다.","level":50,"category":"빈도 학습"},{"id":15879,"term":"syndicate","meaning":"조합; 연합체; 신디케이트","partOfSpeech":"n.","example":"A media syndicate bought up several local newspapers last year.","exampleTranslation":"한 미디어 신디케이트가 작년에 지역 신문사 여러 곳을 인수했습니다.","level":50,"category":"빈도 학습"},{"id":15880,"term":"synonym","meaning":"동의어; 유의어","partOfSpeech":"n.","example":"Can you give me a synonym for the word 'happy' in this sentence?","exampleTranslation":"이 문장에서 'happy'의 동의어를 하나 알려줄 수 있나요?","level":50,"category":"빈도 학습"},{"id":15881,"term":"syrup","meaning":"시럽; 단맛 나는 액체","partOfSpeech":"n.","example":"She poured maple syrup over her pancakes at breakfast.","exampleTranslation":"그녀는 아침에 팬케이크 위에 메이플 시럽을 뿌렸습니다.","level":50,"category":"빈도 학습"},{"id":15882,"term":"tab","meaning":"탭; 꼬리표; 계산서","partOfSpeech":"n.","example":"Click the new tab to open another page in your browser.","exampleTranslation":"새 탭을 클릭하면 브라우저에서 다른 페이지가 열립니다.","level":50,"category":"빈도 학습"},{"id":15883,"term":"taboo","meaning":"금기; 금기시된","partOfSpeech":"n.","example":"Discussing money openly is still considered a taboo in some cultures.","exampleTranslation":"일부 문화에서는 돈에 대해 공개적으로 이야기하는 것이 여전히 금기로 여겨집니다.","level":50,"category":"빈도 학습"},{"id":15884,"term":"tally","meaning":"집계; 합계; 집계하다","partOfSpeech":"n.","example":"The volunteer kept a tally of how many meals were served each day.","exampleTranslation":"자원봉사자는 매일 제공된 식사 수의 집계를 기록했습니다.","level":50,"category":"빈도 학습"},{"id":15885,"term":"tanker","meaning":"탱커선; 유조차","partOfSpeech":"n.","example":"A large tanker carrying oil ran into trouble near the coast.","exampleTranslation":"석유를 실은 대형 탱커선이 해안 근처에서 사고를 당했습니다.","level":50,"category":"빈도 학습"},{"id":15886,"term":"tart","meaning":"새콤한; 가시 돋친; 타르트","partOfSpeech":"adj.","example":"The lemon dessert had a pleasantly tart flavor that everyone enjoyed.","exampleTranslation":"레몬 디저트는 모두가 즐기는 상큼하게 새콤한 맛이 났습니다.","level":50,"category":"빈도 학습"},{"id":15887,"term":"tattoo","meaning":"문신; 문신을 새기다","partOfSpeech":"n.","example":"He got a small tattoo on his wrist to remember his late grandmother.","exampleTranslation":"그는 돌아가신 할머니를 기억하기 위해 손목에 작은 문신을 새겼습니다.","level":50,"category":"빈도 학습"},{"id":15888,"term":"taunt","meaning":"비웃다; 조롱하다; 비웃음","partOfSpeech":"v.","example":"The kids started to taunt the new student about his accent.","exampleTranslation":"아이들이 새 학생의 억양을 놀리기 시작했습니다.","level":50,"category":"빈도 학습"},{"id":15889,"term":"tavern","meaning":"선술집; 여관","partOfSpeech":"n.","example":"The travelers stopped at a cozy tavern to rest and have dinner.","exampleTranslation":"여행자들은 아늑한 선술집에 들러 쉬면서 저녁을 먹었습니다.","level":50,"category":"빈도 학습"},{"id":15890,"term":"terminology","meaning":"전문 용어; 술어","partOfSpeech":"n.","example":"The textbook uses technical terminology that can be hard for beginners.","exampleTranslation":"그 교재는 초보자가 이해하기 어려울 수 있는 전문 용어를 사용합니다.","level":50,"category":"빈도 학습"},{"id":15891,"term":"theologian","meaning":"신학자","partOfSpeech":"n.","example":"The theologian wrote several books exploring the nature of faith.","exampleTranslation":"그 신학자는 믿음의 본질을 탐구하는 책을 여러 권 저술했습니다.","level":50,"category":"빈도 학습"},{"id":15892,"term":"thorn","meaning":"가시; 골칫거리","partOfSpeech":"n.","example":"She pricked her finger on a thorn while picking roses in the garden.","exampleTranslation":"그녀는 정원에서 장미를 꺾다가 가시에 손가락을 찔렸습니다.","level":50,"category":"빈도 학습"},{"id":15893,"term":"thrash","meaning":"마구 때리다; 뒤척이다; 완파하다","partOfSpeech":"v.","example":"The fish began to thrash wildly once it was pulled out of the water.","exampleTranslation":"물고기는 물 밖으로 끌려나오자마자 맹렬히 퍼덕이기 시작했습니다.","level":50,"category":"빈도 학습"},{"id":15894,"term":"throb","meaning":"욱신거리다; 두근거리다","partOfSpeech":"v.","example":"His head began to throb after staring at the screen for too long.","exampleTranslation":"화면을 너무 오래 바라본 후 그의 머리가 욱신거리기 시작했습니다.","level":50,"category":"빈도 학습"},{"id":15895,"term":"thwart","meaning":"방해하다; 좌절시키다","partOfSpeech":"v.","example":"Bad weather can thwart even the most carefully planned outdoor events.","exampleTranslation":"악천후는 가장 세심하게 계획된 야외 행사도 망칠 수 있습니다.","level":50,"category":"빈도 학습"},{"id":15896,"term":"tickle","meaning":"간지럽히다; 재미있게 하다","partOfSpeech":"v.","example":"The little girl laughed every time her father would tickle her feet.","exampleTranslation":"아버지가 발을 간지럽힐 때마다 어린 소녀는 웃음을 터뜨렸습니다.","level":50,"category":"빈도 학습"},{"id":15897,"term":"tier","meaning":"층; 단계; 등급","partOfSpeech":"n.","example":"The subscription offers three levels: a basic tier, standard, and premium.","exampleTranslation":"구독 서비스는 기본 등급, 스탠다드, 프리미엄의 세 가지 단계를 제공합니다.","level":50,"category":"빈도 학습"},{"id":15898,"term":"topple","meaning":"넘어뜨리다; 무너지다","partOfSpeech":"v.","example":"Strong winds can topple old trees that have weak roots.","exampleTranslation":"강풍은 뿌리가 약한 오래된 나무를 넘어뜨릴 수 있습니다.","level":50,"category":"빈도 학습"},{"id":15899,"term":"torque","meaning":"토크; 회전력","partOfSpeech":"n.","example":"The mechanic checked the torque on each bolt to make sure it was tight.","exampleTranslation":"정비사는 각 볼트가 단단히 조여졌는지 확인하기 위해 토크를 점검했습니다.","level":50,"category":"빈도 학습"},{"id":15900,"term":"tout","meaning":"열렬히 홍보하다; 떠벌리다","partOfSpeech":"v.","example":"The company loves to tout its new product as a revolutionary solution.","exampleTranslation":"그 회사는 자사 신제품을 혁신적인 해결책으로 적극 홍보하길 좋아합니다.","level":50,"category":"빈도 학습"},{"id":15901,"term":"toxin","meaning":"독소; 독성 물질","partOfSpeech":"n.","example":"Drinking contaminated water can introduce a harmful toxin into your body.","exampleTranslation":"오염된 물을 마시면 해로운 독소가 몸속으로 들어올 수 있습니다.","level":50,"category":"빈도 학습"},{"id":15902,"term":"trafficked","meaning":"밀매된; 불법 거래된","partOfSpeech":"adj.","example":"Authorities rescued several trafficked individuals from the warehouse.","exampleTranslation":"당국은 창고에서 인신매매 피해자 여러 명을 구출했습니다.","level":50,"category":"빈도 학습"},{"id":15903,"term":"transcribe","meaning":"받아 적다; 옮겨 쓰다","partOfSpeech":"v.","example":"The assistant was asked to transcribe the interview recording into text.","exampleTranslation":"보조원은 인터뷰 녹음을 텍스트로 받아 적도록 요청받았습니다.","level":50,"category":"빈도 학습"},{"id":15904,"term":"transient","meaning":"일시적인; 덧없는","partOfSpeech":"adj.","example":"The feeling of sadness was transient and passed within a few hours.","exampleTranslation":"슬픈 감정은 일시적이었고 몇 시간 내로 사라졌습니다.","level":50,"category":"빈도 학습"},{"id":15905,"term":"trash","meaning":"쓰레기; 폐기물; 버리다","partOfSpeech":"n.","example":"Please take out the trash before you leave for work in the morning.","exampleTranslation":"아침에 출근하기 전에 쓰레기를 버려 주세요.","level":50,"category":"빈도 학습"},{"id":15906,"term":"traverse","meaning":"횡단하다; 가로지르다","partOfSpeech":"v.","example":"The hikers needed two days to traverse the mountain range on foot.","exampleTranslation":"등산객들은 도보로 산맥을 횡단하는 데 이틀이 필요했습니다.","level":50,"category":"빈도 학습"},{"id":15907,"term":"treachery","meaning":"배신; 반역","partOfSpeech":"n.","example":"He felt deep hurt at his best friend's treachery during the business deal.","exampleTranslation":"그는 사업 거래에서 가장 친한 친구의 배신에 깊은 상처를 받았습니다.","level":50,"category":"빈도 학습"},{"id":15908,"term":"trek","meaning":"장거리 여행; 힘겨운 여정; 트레킹하다","partOfSpeech":"n.","example":"The group set off on a challenging trek through the Himalayan foothills.","exampleTranslation":"그 일행은 히말라야 산기슭을 가로지르는 험난한 트레킹을 시작했습니다.","level":50,"category":"빈도 학습"},{"id":15909,"term":"tribune","meaning":"호민관; 연단; 대변인","partOfSpeech":"n.","example":"The ancient tribune was responsible for protecting the rights of ordinary citizens.","exampleTranslation":"고대 호민관은 일반 시민의 권리를 보호할 책임이 있었습니다.","level":50,"category":"빈도 학습"},{"id":15910,"term":"trinity","meaning":"삼위일체; 세 개의 결합","partOfSpeech":"n.","example":"The concept of the trinity is central to many Christian teachings.","exampleTranslation":"삼위일체 개념은 많은 기독교 가르침의 핵심입니다.","level":50,"category":"빈도 학습"},{"id":15911,"term":"trolley","meaning":"트롤리; 손수레; 전차","partOfSpeech":"n.","example":"She loaded her groceries onto a trolley and headed toward the checkout.","exampleTranslation":"그녀는 식료품을 손수레에 실고 계산대로 향했습니다.","level":50,"category":"빈도 학습"},{"id":15912,"term":"trump","meaning":"이기다; 능가하다; 으뜸패","partOfSpeech":"v.","example":"In card games, a trump card can often trump any other card played.","exampleTranslation":"카드 게임에서 으뜸패는 흔히 다른 어떤 카드도 이길 수 있습니다.","level":50,"category":"빈도 학습"},{"id":15913,"term":"tsar","meaning":"차르; 황제","partOfSpeech":"n.","example":"The tsar ruled over a vast empire that stretched across two continents.","exampleTranslation":"차르는 두 대륙에 걸쳐 뻗어 있는 광대한 제국을 통치했습니다.","level":50,"category":"빈도 학습"},{"id":15914,"term":"tuberculosis","meaning":"결핵","partOfSpeech":"n.","example":"Tuberculosis was once one of the most feared diseases in the world.","exampleTranslation":"결핵은 한때 세계에서 가장 두려운 질병 중 하나였습니다.","level":50,"category":"빈도 학습"},{"id":15915,"term":"tuition","meaning":"수업료; 교습","partOfSpeech":"n.","example":"The tuition at that university has increased significantly over the past decade.","exampleTranslation":"그 대학의 수업료는 지난 10년 동안 상당히 올랐습니다.","level":50,"category":"빈도 학습"},{"id":15916,"term":"tuna","meaning":"참치","partOfSpeech":"n.","example":"She made a tuna sandwich for lunch and added some pickles.","exampleTranslation":"그녀는 점심으로 참치 샌드위치를 만들고 피클을 넣었습니다.","level":50,"category":"빈도 학습"},{"id":15917,"term":"turbine","meaning":"터빈; 회전 엔진","partOfSpeech":"n.","example":"The wind turbine on the hill generates electricity for the village.","exampleTranslation":"언덕 위의 풍력 터빈이 마을에 전기를 공급합니다.","level":50,"category":"빈도 학습"},{"id":15918,"term":"turmoil","meaning":"혼란; 소동","partOfSpeech":"n.","example":"The country fell into turmoil after the sudden change in government.","exampleTranslation":"갑작스러운 정권 교체 이후 그 나라는 혼란에 빠졌습니다.","level":50,"category":"빈도 학습"},{"id":15919,"term":"twilight","meaning":"황혼; 어스름","partOfSpeech":"n.","example":"They sat on the porch and watched the sky during twilight.","exampleTranslation":"그들은 황혼 무렵 현관에 앉아 하늘을 바라봤습니다.","level":50,"category":"빈도 학습"},{"id":15920,"term":"twine","meaning":"꼰 실; 노끈","partOfSpeech":"n.","example":"He tied the package with twine so it would stay closed during shipping.","exampleTranslation":"그는 배송 중에 소포가 열리지 않도록 노끈으로 묶었습니다.","level":50,"category":"빈도 학습"},{"id":15921,"term":"twofold","meaning":"두 배의; 이중의","partOfSpeech":"adj.","example":"The benefit of this plan is twofold: it saves time and reduces costs.","exampleTranslation":"이 계획의 이점은 두 가지로, 시간을 절약하고 비용을 줄여 줍니다.","level":50,"category":"빈도 학습"},{"id":15922,"term":"typewrite","meaning":"타자기로 치다; 타이프하다","partOfSpeech":"v.","example":"In the old days, secretaries had to typewrite every letter by hand.","exampleTranslation":"옛날에는 비서들이 모든 편지를 직접 타이프로 쳐야 했습니다.","level":50,"category":"빈도 학습"},{"id":15923,"term":"ultraviolet","meaning":"자외선(의)","partOfSpeech":"adj.","example":"You should wear sunscreen to protect your skin from ultraviolet rays.","exampleTranslation":"자외선으로부터 피부를 보호하려면 자외선 차단제를 바르세요.","level":50,"category":"빈도 학습"},{"id":15924,"term":"umpire","meaning":"심판; 중재자","partOfSpeech":"n.","example":"The umpire called the ball out, and the crowd began to boo.","exampleTranslation":"심판이 공이 아웃이라고 선언하자 관중이 야유를 보냈습니다.","level":50,"category":"빈도 학습"},{"id":15925,"term":"underpin","meaning":"뒷받침하다; 지지하다","partOfSpeech":"v.","example":"Strong research data can underpin any argument you make in your report.","exampleTranslation":"강력한 연구 데이터는 보고서에서 제시하는 모든 주장을 뒷받침할 수 있습니다.","level":50,"category":"빈도 학습"},{"id":15926,"term":"understate","meaning":"과소평가하다; 절제하여 말하다","partOfSpeech":"v.","example":"It would be wrong to understate how difficult the recovery process was.","exampleTranslation":"회복 과정이 얼마나 힘들었는지를 과소평가하는 것은 잘못된 일입니다.","level":50,"category":"빈도 학습"},{"id":15927,"term":"underway","meaning":"진행 중인; 시작된","partOfSpeech":"adj.","example":"Construction of the new bridge is already underway and ahead of schedule.","exampleTranslation":"새 교량 공사가 이미 진행 중이며 예정보다 앞서 있습니다.","level":50,"category":"빈도 학습"},{"id":15928,"term":"underwrite","meaning":"보증하다; 보험을 인수하다","partOfSpeech":"v.","example":"The bank agreed to underwrite the new startup's initial funding round.","exampleTranslation":"은행은 신규 스타트업의 초기 자금 조달을 보증하기로 합의했습니다.","level":50,"category":"빈도 학습"},{"id":15929,"term":"unilateral","meaning":"일방적인; 단독의","partOfSpeech":"adj.","example":"The company made a unilateral decision without consulting the employees.","exampleTranslation":"회사는 직원들과 상의하지 않고 일방적인 결정을 내렸습니다.","level":50,"category":"빈도 학습"},{"id":15930,"term":"unison","meaning":"한목소리; 일치","partOfSpeech":"n.","example":"The choir sang in unison and the hall filled with a beautiful sound.","exampleTranslation":"합창단이 한목소리로 노래하자 홀에 아름다운 소리가 가득 찼습니다.","level":50,"category":"빈도 학습"},{"id":15931,"term":"unravel","meaning":"풀다; 해명하다","partOfSpeech":"v.","example":"Detectives worked for months to unravel the mystery behind the disappearance.","exampleTranslation":"형사들은 실종 사건의 미스터리를 해명하기 위해 몇 달 동안 수사했습니다.","level":50,"category":"빈도 학습"},{"id":15932,"term":"unrest","meaning":"불안; 소요","partOfSpeech":"n.","example":"There was widespread unrest among workers after the wage cuts were announced.","exampleTranslation":"임금 삭감이 발표된 후 노동자들 사이에 광범위한 불안이 퍼졌습니다.","level":50,"category":"빈도 학습"},{"id":15933,"term":"unsettle","meaning":"불안하게 하다; 동요시키다","partOfSpeech":"v.","example":"Unexpected news about layoffs began to unsettle the entire office.","exampleTranslation":"해고에 관한 갑작스러운 소식이 사무실 전체를 동요시키기 시작했습니다.","level":50,"category":"빈도 학습"},{"id":15934,"term":"upheaval","meaning":"격변; 대혼란","partOfSpeech":"n.","example":"The merger caused a major upheaval in the company's daily operations.","exampleTranslation":"합병은 회사의 일상 업무에 큰 격변을 일으켰습니다.","level":50,"category":"빈도 학습"},{"id":15935,"term":"uprising","meaning":"봉기; 반란","partOfSpeech":"n.","example":"The uprising was quickly suppressed by government forces.","exampleTranslation":"봉기는 정부군에 의해 신속히 진압되었습니다.","level":50,"category":"빈도 학습"},{"id":15936,"term":"uranium","meaning":"우라늄","partOfSpeech":"n.","example":"Uranium is a radioactive element used as fuel in nuclear power plants.","exampleTranslation":"우라늄은 원자력 발전소에서 연료로 사용되는 방사성 원소입니다.","level":50,"category":"빈도 학습"},{"id":15937,"term":"vaccinate","meaning":"예방접종하다","partOfSpeech":"v.","example":"Doctors recommend that you vaccinate your children before they start school.","exampleTranslation":"의사들은 아이들이 학교에 입학하기 전에 예방접종을 받을 것을 권고합니다.","level":50,"category":"빈도 학습"},{"id":15938,"term":"vain","meaning":"허영심 있는; 헛된","partOfSpeech":"adj.","example":"He was so vain that he checked his appearance in every mirror he passed.","exampleTranslation":"그는 허영심이 너무 강해서 지나치는 거울마다 자신의 모습을 확인했습니다.","level":50,"category":"빈도 학습"},{"id":15939,"term":"vandal","meaning":"기물 파손자; 반달족","partOfSpeech":"n.","example":"A vandal spray-painted graffiti all over the park benches last night.","exampleTranslation":"어젯밤 기물 파손자가 공원 벤치 전체에 낙서를 스프레이로 그렸습니다.","level":50,"category":"빈도 학습"},{"id":15940,"term":"vanity","meaning":"허영심; 자만","partOfSpeech":"n.","example":"Her vanity made it hard for her to accept any criticism from others.","exampleTranslation":"그녀의 허영심은 다른 사람들의 비판을 받아들이기 어렵게 만들었습니다.","level":50,"category":"빈도 학습"},{"id":15941,"term":"vapour","meaning":"수증기; 증기","partOfSpeech":"n.","example":"You could see vapour rising from the hot coffee on the cold morning.","exampleTranslation":"추운 아침에 뜨거운 커피에서 수증기가 피어오르는 것을 볼 수 있었습니다.","level":50,"category":"빈도 학습"},{"id":15942,"term":"vault","meaning":"금고; 도약하다","partOfSpeech":"n.","example":"The bank keeps large amounts of cash stored inside a secure vault.","exampleTranslation":"은행은 안전한 금고 안에 거액의 현금을 보관합니다.","level":50,"category":"빈도 학습"},{"id":15943,"term":"vector","meaning":"벡터; 방향량","partOfSpeech":"n.","example":"In physics class, we learned that a vector has both magnitude and direction.","exampleTranslation":"물리 수업에서 벡터는 크기와 방향을 모두 갖는다는 것을 배웠습니다.","level":50,"category":"빈도 학습"},{"id":15944,"term":"vibrant","meaning":"생기 있는; 활기찬","partOfSpeech":"adj.","example":"The city market was vibrant with colors, sounds, and amazing food aromas.","exampleTranslation":"그 도시 시장은 색깔, 소리, 놀라운 음식 향기로 활기가 넘쳤습니다.","level":50,"category":"빈도 학습"},{"id":15945,"term":"vicinity","meaning":"인근; 근처","partOfSpeech":"n.","example":"There are several good restaurants in the vicinity of our hotel.","exampleTranslation":"우리 호텔 인근에 좋은 식당이 여러 군데 있습니다.","level":50,"category":"빈도 학습"},{"id":15946,"term":"villain","meaning":"악당; 악인","partOfSpeech":"n.","example":"The villain in the movie tricked everyone until the very last scene.","exampleTranslation":"영화 속 악당은 마지막 장면까지 모든 사람을 속였습니다.","level":50,"category":"빈도 학습"},{"id":15947,"term":"vitality","meaning":"활력; 생명력","partOfSpeech":"n.","example":"Regular exercise and good sleep are key to maintaining vitality as you age.","exampleTranslation":"규칙적인 운동과 충분한 수면은 나이가 들면서 활력을 유지하는 핵심입니다.","level":50,"category":"빈도 학습"},{"id":15948,"term":"vomit","meaning":"구토하다; 토하다","partOfSpeech":"v.","example":"The passenger felt so seasick that he was about to vomit on the boat.","exampleTranslation":"그 승객은 너무 뱃멀미가 나서 배 위에서 토할 것 같았습니다.","level":50,"category":"빈도 학습"},{"id":15949,"term":"wade","meaning":"물속을 걷다; 헤치고 나아가다","partOfSpeech":"v.","example":"The children wanted to wade through the shallow stream on a hot day.","exampleTranslation":"아이들은 더운 날 얕은 개울을 걸어서 건너고 싶어 했습니다.","level":50,"category":"빈도 학습"},{"id":15950,"term":"waive","meaning":"포기하다; 면제하다","partOfSpeech":"v.","example":"The landlord agreed to waive the first month's rent for the new tenant.","exampleTranslation":"집주인은 새 세입자의 첫 달 임대료를 면제해 주기로 동의했습니다.","level":50,"category":"빈도 학습"},{"id":15951,"term":"walnut","meaning":"호두","partOfSpeech":"n.","example":"She sprinkled crushed walnut on top of the salad for extra crunch.","exampleTranslation":"그녀는 식감을 더하기 위해 샐러드 위에 으깬 호두를 뿌렸습니다.","level":50,"category":"빈도 학습"},{"id":15952,"term":"wane","meaning":"약해지다; 줄어들다","partOfSpeech":"v.","example":"Public interest in the story began to wane after a few weeks.","exampleTranslation":"그 이야기에 대한 대중의 관심은 몇 주 후 시들해지기 시작했습니다.","level":50,"category":"빈도 학습"},{"id":15953,"term":"warden","meaning":"관리인; 교도소장","partOfSpeech":"n.","example":"The warden introduced new rehabilitation programs for inmates at the prison.","exampleTranslation":"교도소장은 수감자들을 위한 새로운 재활 프로그램을 도입했습니다.","level":50,"category":"빈도 학습"},{"id":15954,"term":"warp","meaning":"뒤틀다; 왜곡하다","partOfSpeech":"v.","example":"Extreme heat can warp wooden furniture if it is left in direct sunlight.","exampleTranslation":"극심한 열은 직사광선에 방치된 목재 가구를 뒤틀리게 할 수 있습니다.","level":50,"category":"빈도 학습"},{"id":15955,"term":"warranty","meaning":"품질 보증; 보증서","partOfSpeech":"n.","example":"The laptop comes with a two-year warranty that covers parts and labor.","exampleTranslation":"그 노트북에는 부품과 인건비를 보장하는 2년 보증서가 포함되어 있습니다.","level":50,"category":"빈도 학습"},{"id":15956,"term":"wasp","meaning":"말벌","partOfSpeech":"n.","example":"A wasp flew into the kitchen and everyone scrambled to open the window.","exampleTranslation":"말벌 한 마리가 주방으로 날아들자 모두가 창문을 열려고 허둥댔습니다.","level":50,"category":"빈도 학습"},{"id":15957,"term":"waver","meaning":"흔들리다; 망설이다","partOfSpeech":"v.","example":"She did not waver in her decision even when everyone else disagreed.","exampleTranslation":"그녀는 다른 모든 사람이 반대해도 자신의 결정에서 흔들리지 않았습니다.","level":50,"category":"빈도 학습"},{"id":15958,"term":"whine","meaning":"칭얼거리다; 징징대다","partOfSpeech":"v.","example":"The child started to whine when his parents said it was time to leave.","exampleTranslation":"부모님이 떠날 시간이라고 하자 아이가 칭얼거리기 시작했습니다.","level":50,"category":"빈도 학습"},{"id":15959,"term":"whirl","meaning":"빙빙 돌다; 소용돌이","partOfSpeech":"v.","example":"Leaves began to whirl in the wind as the storm approached the town.","exampleTranslation":"폭풍이 마을에 다가오자 나뭇잎들이 바람에 빙빙 돌기 시작했습니다.","level":50,"category":"빈도 학습"},{"id":15960,"term":"wield","meaning":"휘두르다; (권력을) 행사하다","partOfSpeech":"v.","example":"A good leader should wield authority with fairness and respect for others.","exampleTranslation":"좋은 지도자는 다른 사람에 대한 공정성과 존중으로 권한을 행사해야 합니다.","level":50,"category":"빈도 학습"},{"id":15961,"term":"wig","meaning":"가발","partOfSpeech":"n.","example":"She wore a wig during the play to look like a character from the 1800s.","exampleTranslation":"그녀는 연극에서 1800년대 인물처럼 보이기 위해 가발을 착용했습니다.","level":50,"category":"빈도 학습"},{"id":15962,"term":"willow","meaning":"버드나무","partOfSpeech":"n.","example":"A tall willow stood by the river, its branches trailing in the water.","exampleTranslation":"키 큰 버드나무 한 그루가 강가에 서서 가지를 물 위에 늘어뜨리고 있었습니다.","level":50,"category":"빈도 학습"},{"id":15963,"term":"wince","meaning":"움찔하다; 얼굴을 찡그리다","partOfSpeech":"v.","example":"He couldn't help but wince when the nurse gave him the injection.","exampleTranslation":"간호사가 주사를 놓을 때 그는 움찔하지 않을 수 없었습니다.","level":50,"category":"빈도 학습"},{"id":15964,"term":"wither","meaning":"시들다; 쇠퇴하다","partOfSpeech":"v.","example":"The flowers will wither quickly if you forget to water them every day.","exampleTranslation":"매일 물을 주는 것을 잊으면 꽃이 금방 시들 것입니다.","level":50,"category":"빈도 학습"},{"id":15965,"term":"withstand","meaning":"견디다; 저항하다","partOfSpeech":"v.","example":"These walls were built to withstand strong earthquakes and harsh weather.","exampleTranslation":"이 벽들은 강한 지진과 혹독한 날씨를 견디도록 지어졌습니다.","level":50,"category":"빈도 학습"},{"id":15966,"term":"wobble","meaning":"흔들리다; 비틀거리다","partOfSpeech":"v.","example":"The old table tends to wobble when you put something heavy on it.","exampleTranslation":"그 낡은 테이블은 무거운 것을 올려놓으면 흔들리는 경향이 있어요.","level":50,"category":"빈도 학습"},{"id":15967,"term":"woe","meaning":"슬픔; 불행; 고통","partOfSpeech":"n.","example":"She listened patiently as he told her about all his woe.","exampleTranslation":"그녀는 그가 자신의 모든 슬픔을 털어놓는 동안 인내심 있게 들어주었습니다.","level":50,"category":"빈도 학습"},{"id":15968,"term":"woo","meaning":"구애하다; 호감을 얻으려 하다","partOfSpeech":"v.","example":"The company tried to woo new customers with a special discount offer.","exampleTranslation":"그 회사는 특별 할인 혜택으로 새 고객을 끌어들이려 했습니다.","level":50,"category":"빈도 학습"},{"id":15969,"term":"wrench","meaning":"렌치; 비틀다; 급격히 당기다","partOfSpeech":"n.","example":"He used a wrench to tighten the loose bolt under the sink.","exampleTranslation":"그는 싱크대 아래의 헐거운 볼트를 조이기 위해 렌치를 사용했습니다.","level":50,"category":"빈도 학습"},{"id":15970,"term":"wretch","meaning":"불쌍한 사람; 비열한 사람","partOfSpeech":"n.","example":"The poor wretch had nowhere to go on such a cold night.","exampleTranslation":"그 불쌍한 사람은 이렇게 추운 밤에 갈 곳이 없었습니다.","level":50,"category":"빈도 학습"},{"id":15971,"term":"wry","meaning":"비꼬는; 비틀린; 냉소적인","partOfSpeech":"adj.","example":"She gave a wry smile when she heard the ironic news.","exampleTranslation":"그녀는 아이러니한 소식을 듣고 냉소적인 미소를 지었습니다.","level":50,"category":"빈도 학습"},{"id":15972,"term":"yank","meaning":"세게 잡아당기다; 확 잡아채다","partOfSpeech":"v.","example":"He had to yank the stuck drawer hard before it finally opened.","exampleTranslation":"그는 꽉 막힌 서랍이 결국 열릴 때까지 세게 잡아당겨야 했습니다.","level":50,"category":"빈도 학습"},{"id":15973,"term":"yarn","meaning":"실; 털실; 긴 이야기","partOfSpeech":"n.","example":"My grandmother knitted a warm scarf using soft blue yarn.","exampleTranslation":"할머니는 부드러운 파란 실을 사용해 따뜻한 목도리를 뜨개질하셨습니다.","level":50,"category":"빈도 학습"},{"id":15974,"term":"yawn","meaning":"하품하다; 하품","partOfSpeech":"v.","example":"She started to yawn repeatedly during the long boring lecture.","exampleTranslation":"그녀는 지루한 강의가 길어지자 반복적으로 하품하기 시작했습니다.","level":50,"category":"빈도 학습"},{"id":15975,"term":"yearn","meaning":"갈망하다; 그리워하다","partOfSpeech":"v.","example":"After years abroad, he began to yearn for his hometown food.","exampleTranslation":"수년간의 해외 생활 후 그는 고향 음식이 그리워지기 시작했습니다.","level":50,"category":"빈도 학습"},{"id":15976,"term":"yeast","meaning":"효모; 이스트","partOfSpeech":"n.","example":"You need to add yeast to the dough to make the bread rise properly.","exampleTranslation":"빵이 제대로 부풀어 오르려면 반죽에 이스트를 넣어야 합니다.","level":50,"category":"빈도 학습"},{"id":15977,"term":"yen","meaning":"엔화(일본 화폐); 열망","partOfSpeech":"n.","example":"She exchanged her dollars for yen before traveling to Japan.","exampleTranslation":"그녀는 일본 여행 전에 달러를 엔화로 환전했습니다.","level":50,"category":"빈도 학습"},{"id":15978,"term":"zeal","meaning":"열정; 열의; 열심","partOfSpeech":"n.","example":"The new volunteer worked with great zeal to help the local community.","exampleTranslation":"새 자원봉사자는 지역 사회를 돕기 위해 대단한 열정으로 일했습니다.","level":50,"category":"빈도 학습"},{"id":15979,"term":"zoom","meaning":"빠르게 이동하다; 확대하다","partOfSpeech":"v.","example":"The car had to zoom past the intersection to catch the green light.","exampleTranslation":"그 차는 파란 신호를 잡기 위해 교차로를 빠르게 통과해야 했습니다.","level":50,"category":"빈도 학습"}]`);export{e as default};